  INSERT INTO public.users (id, email, created_at)
INSERT INTO public.autores (slug, nome, numero_registro, instagram, arquetipo, cor_hex, bio_curta, persona) VALUES
('caleb-montenegro','Caleb Montenegro','71.100','@caleb.montenegro','Veterano','#FF4D14',
INSERT INTO public.provocacoes (dia_ano, mes, dia, autor_slug, autor_dia, autor_numero, citacao, autor_citacao, pergunta, texto, aspas_autor, instagram) VALUES
('01-01', 1, 1, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Dai-me, pois, agora este monte.', 'Josué 14:12', 'Que monte você está pedindo a Deus esse ano — ou ainda quer o mesmo vale de conforto?', 'Caleb tinha 85 anos quando pediu o monte. Não o vale, não a planície, não o que já estava limpo. O monte. O lugar com gigantes. Você tem 30, 40, 50 anos e está pedindo a Deus o quê? Que as coisas melhorem? Que o ano seja leve? Caleb pediu terreno de guerra. Ele sabia que ali tinha inimigo. E foi. A maioria dos crentes morre espiritualmente pedindo vale. Deus está entregando monte pra quem tem coragem de tomar. 2026 é o quê pra você: outro ano de sobrevivência ou o ano do monte?', 'O monte é pra quem tem coragem de subir, não pra quem fica pedindo descida.', '@caleb.montenegro'),
('01-02', 1, 2, 'josue-caetano', 'Josué Caetano', '71.204', 'Esforça-te e tem bom ânimo.', 'Josué 1:6', 'Quantas decisões você está segurando só por medo de errar — e que preço você já pagou pela indecisão?', 'Josué ouviu isso quatro vezes em um único capítulo. Não é à toa. Líder vive entre a vontade de avançar e o medo de errar. Deus não disse "pensa bem", disse "vai". Você está aí há quanto tempo esperando clareza perfeita pra começar? Clareza não vem sentado. Vem no caminho. Atravessa o Jordão primeiro, as águas se abrem depois. Quem espera condição ideal, morre na margem.', 'Clareza não vem sentado. Vem no caminho.', '@josue.caetano'),
('01-03', 1, 3, 'davi-valverde', 'Davi Valverde', '71.337', 'Assim cingiu Davi a sua espada sobre as suas vestes.', '1 Samuel 17:39', 'O que em você é harpa e o que é espada — e qual dos dois você anda negligenciando?', 'Davi tocava harpa no palácio e cortava cabeça no vale. Não eram dois homens. Era o mesmo. Você quer ser só sensível ou só duro? Isso não é caráter, é fraqueza disfarçada. O guerreiro que só sabe matar é bruto. O adorador que só sabe chorar é covarde. Legendário carrega harpa e espada na mesma mochila. Ora forte, trabalha forte, ama forte, enfrenta forte. Ponto.', 'Harpa e espada na mesma mão — ou você nem é guerreiro nem é adorador.', '@davi.valverde'),
('01-04', 1, 4, 'elias-dovale', 'Elias do Vale', '71.418', 'Ainda deixei em Israel sete mil.', '1 Reis 19:18', 'Em que ponto você se acha único guerreiro na batalha — e que orgulho disfarçado tem nisso?', 'Elias achou que era o último. Deus disse: tem sete mil que você não viu. A autopiedade do guerreiro é armadilha sutil. "Só eu luto, só eu vejo, só eu me importo." Mentira. Tem mais gente no front, você só não enxerga porque está trancado dentro da sua caverna de exaustão. Sai. Come. Dorme. Volta. A guerra continua com ou sem você — e você não é o centro dela.', 'Autopiedade de guerreiro é orgulho disfarçado de cansaço.', '@elias.dovale'),
('01-05', 1, 5, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'O povo que contigo está é demais.', 'Juízes 7:2', 'Que "ajuda" você está mantendo perto só porque tem medo de lutar com exército menor?', 'Gideão tinha 32 mil homens. Deus reduziu pra 300. Não porque fossem mais fortes — porque eram os certos. Você anda lotado de gente, de ideia, de plano, de compromisso, e nada avança. Pode ser que Deus queira cortar. Cortar agenda, cortar sócio, cortar amizade, cortar produto. A vitória com 32 mil vira mérito humano. A vitória com 300 vira testemunho. Quem você precisa soltar pra Deus fazer o impossível?', 'Exército grande rouba o crédito da vitória de Deus.', '@gideao.sampaio'),
('01-06', 1, 6, 'neemias-barros', 'Neemias Barros', '71.612', 'E pus guarda contra eles de dia e de noite.', 'Neemias 4:9', 'Onde na sua vida você está orando e não está guardando — ou guardando e não está orando?', 'Neemias orava. Neemias também colocava guarda. Não era uma coisa OU outra. Era as duas. Tem crente que só ora e não executa. Tem executor que só executa e não ora. Os dois são burros, em lados opostos. A obra se levanta com oração E espada. Com fé E muro. Com submissão E firmeza. Se você só reza pelo seu casamento mas não guarda teu coração, o muro cai. Se você só disciplina teu corpo mas não ora, cai também. As duas coisas. Sempre as duas.', 'Oração sem guarda é ingenuidade. Guarda sem oração é arrogância.', '@neemias.barros'),
('01-07', 1, 7, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Fala, Senhor, que o teu servo ouve.', '1 Samuel 3:9', 'Quando foi a última vez que você ouviu Deus — não leu sobre Ele, não falou com Ele, ouviu?', 'Samuel era um menino e aprendeu a ouvir. Você é adulto, tem Bíblia, tem acesso a mil podcasts, e não ouve. Escuta não é ruído de fora, é silêncio de dentro. Você não ouve Deus porque tem a boca cheia de pedidos, a cabeça cheia de scroll, a agenda cheia de tarefa. Cala. Escuta. Dez minutos. Sem Bíblia, sem música, sem celular. Só cala e diz: fala, Senhor. Você vai ouvir coisas que evitou por anos.', 'Quem não cala não ouve. E quem não ouve, não muda.', '@samuelqueiroga'),
('01-08', 1, 8, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'E os filhos de Benjamim eram homens valentes.', 'Juízes 20:16', 'Você anda medindo força pelo tamanho ou pela inteireza — e quando foi que começou a se achar pequeno?', 'Tribo de Benjamim era pequena. Mas os caras acertavam um fio de cabelo com funda, de costas, de longe. Tamanho não decide nada. Inteireza decide tudo. Você tem um negócio pequeno, uma família pequena, um ministério pequeno, uma influência pequena — e tá ótimo. O problema não é o tamanho. É a falta de treino. De pontaria. De prática. Quer crescer? Foca no que tem e treina o dobro. Benjamim pequeno dava medo no exército grande. Faz igual.', 'Tamanho não vence guerra. Pontaria vence.', '@benjamim.paiva'),
('01-09', 1, 9, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Porventura, viverão estes ossos?', 'Ezequiel 37:3', 'Que área da sua vida você já enterrou — e que Deus ainda está esperando você profetizar sobre ela?', 'Deus mostrou ossos secos a Ezequiel e fez uma pergunta irritante: viverão? Ezequiel não respondeu sim nem não. Disse: "Senhor, tu o sabes." Inteligente. Tem coisa na sua vida que parece osso seco: o casamento, a saúde, a fé, o sonho, o filho, a missão. Você já enterrou. Deus pergunta: vai viver? Não responde com otimismo barato nem com derrota covarde. Responde com obediência: Senhor, tu sabes — e profetiza em cima. O que você enterrou pode ainda andar.', 'O que parece morto pode só estar esperando voz.', '@ezequielferraz'),
('01-10', 1, 10, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Entrou em aliança com Davi.', '1 Samuel 18:3', 'Quem é o teu Davi — e o que você já abriu mão', ' de verdade', ' pra manter essa aliança?', 'Jônatas era filho do rei. Por sangue, herdeiro. Escolheu Davi — o rapaz que ia tomar o trono dele — e fez pacto. Tirou o próprio manto e deu. Tirou a espada, deu. Tirou o arco, deu. Amizade de verdade tira coisa. Não é quem curte seu post. É quem renuncia trono por você. E você, tem alguém assim? Você É alguém assim? Pacto custa. Relação rasa é gostosa. Aliança é sangue. Com quem você sangra?'),
('01-11', 1, 11, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Até aqui nos ajudou o Senhor.', '1 Samuel 7:12', 'O que você ainda não comemorou porque acha que é pouco comparado ao próximo?', 'Samuel ergueu uma pedra e chamou de Ebenezer: "Até aqui nos ajudou o Senhor". Não disse "até o fim", disse "até aqui". Você passa a vida correndo atrás do próximo milagre sem parar pra ver o que já aconteceu. Olha pra trás. O casamento que durou. O filho que nasceu. O emprego que entrou. A saúde que voltou. O vício que você largou. Levanta tua pedra. Memória é combustível de fé.', 'Quem não registra o que Deus fez esquece do que Ele pode fazer.', '@caleb.montenegro'),
('01-12', 1, 12, 'josue-caetano', 'Josué Caetano', '71.204', 'Sede homens e pelejai.', '1 Samuel 4:9', 'Em que lugar você tá esperando alguém brigar no seu lugar?', 'Os filisteus gritaram pro exército deles: "Sede homens, pelejai." Os inimigos já sabiam. Você, cristão, é pior — vive esperando que outro pele tua briga. Pelo teu casamento. Pelo teu filho. Pela tua empresa. Pela tua paz. Ninguém vem. É você. Levanta da cadeira e briga. Homem de Deus briga ajoelhado E de pé.', 'Se você espera outro brigar por você, já perdeu. Levanta.', '@josue.caetano'),
('01-13', 1, 13, 'davi-valverde', 'Davi Valverde', '71.337', 'O Senhor é o meu pastor.', 'Salmo 23:1', 'Quando você diz "o Senhor é o meu pastor", você está declarando ou pedindo?', 'Davi escreveu isso DEPOIS de passar vale da sombra. Não é afirmação de quem nunca foi atacado. É testemunho de quem já foi e saiu. Você canta esse Salmo toda sacola cheia ou só quando aperta? Se é só na aperta, é pedido travestido de declaração. Declara mesmo agora: em dia de fartura, de sobra, de casamento firme. Aí é fé.', 'Declaração de fé na abundância vale mais que pedido no aperto.', '@davi.valverde'),
('01-14', 1, 14, 'elias-dovale', 'Elias do Vale', '71.418', 'Até quando coxeareis entre dois pensamentos?', '1 Reis 18:21', 'Em que área você tá em cima do muro — e que preço você tá pagando pela indecisão?', 'Elias perguntou ao povo: até quando você vai ficar entre Baal e Deus, meio lá meio cá? Você faz igual. Meio crente no domingo, meio mundo na segunda. Meio pai, meio ausente. Meio empresário, meio funcionário de si mesmo. Decide. Não morno. Jesus vomita morno. Quente ou frio, mas inteiro. Hoje é o dia de parar de coxear.', 'Cima do muro é pior que errar. Errar ao menos é posição.', '@elias.dovale'),
('01-15', 1, 15, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'O Senhor é contigo, valente por tua força.', 'Juízes 6:12', 'Que chamado Deus te deu que você tá fingindo que não entendeu?', 'O anjo apareceu pra Gideão e o chamou de "valente por tua força". Gideão tava escondido, malhando trigo num lagar (lugar errado pra trigo). Deus enxerga o guerreiro no covarde antes do covarde se enxergar. Você tá escondido fazendo tua tarefa medíocre enquanto Deus te chama pra guerra. Para de fugir do chamado. Sai do lagar.', 'Deus te chama pelo que você é. Ainda que você não enxergue.', '@gideao.sampaio'),
('01-16', 1, 16, 'neemias-barros', 'Neemias Barros', '71.612', 'Lança-te mãos à obra e sê forte.', '1 Crônicas 28:20', 'Que obra Deus te confiou que você ainda não começou por medo do tamanho?', 'Davi disse pro Salomão: a obra é grande, mas põe a mão nela. Você fica paralisado porque o projeto é grande. A Bíblia não diz que é pequeno. Diz pra POR A MÃO. Começa pelo tijolo um. Pelo capítulo um. Pela oração um. Pelo dia um. Obra grande se constrói com mão pequena, dia após dia. Para de olhar o prédio. Coloca o tijolo.', 'Quem olha o prédio paralisa. Quem coloca o tijolo constrói.', '@neemias.barros'),
('01-17', 1, 17, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Não olhes para a sua aparência.', '1 Samuel 16:7', 'Quem você tá subestimando em você mesmo por causa da aparência?', 'Samuel ia ungir o rei e quase errou de alvo. Os irmãos mais altos, mais fortes, mais imponentes passaram na frente. Deus disse: não olha aparência. O próximo rei era o menor, o caçula, o esquecido pastor. Você faz o mesmo com você. Se compara com quem aparenta melhor, mais calmo, mais estruturado. Deus não liga pra tua aparência. Liga pro teu coração. Para de rebaixar o que Ele quer ungir.', 'Deus unge coração, não selfie.', '@samuelqueiroga'),
('01-18', 1, 18, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Ainda que ele me mate, nele esperarei.', 'Jó 13:15', 'Que ponto de tua fé você ainda condicionou a Deus dar o que você quer?', 'Jó perdeu tudo — tudo mesmo, filhos, casa, saúde — e disse isso. "Ainda que Ele me mate." Isso é fé de quem largou o palpite. A maioria da tua fé é contrato: se Deus me der X, eu creio. Isso não é fé, é cálculo. Fé é: mesmo que não venha, eu fico. Mesmo que eu morra, eu confio. Testa tua fé tirando a condição. O que sobra?', 'Fé com condição é negociação. Fé é quando não tem negociação.', '@benjamim.paiva'),
('01-19', 1, 19, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Não te tomes de medo por eles.', 'Ezequiel 2:6', 'De quem você tá com medo que Deus já mandou você confrontar?', 'Deus mandou Ezequiel falar pra Israel e avisou: vão ser rebeldes, vão te espinhar. Mas não tenha medo deles. Tem gente na tua vida que Deus já te mandou confrontar e você tá com medo. Sócio tóxico. Filho rebelde. Liderança injusta. Amigo que te arrasta. Medo da reação deles te trava mais que a reação em si. Encara. Eles já espinharam. Tu ainda não falou.', 'Medo da reação do outro é pior que a reação do outro.', '@ezequielferraz'),
('01-20', 1, 20, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'A alma de Jônatas se ligou com a alma de Davi.', '1 Samuel 18:1', 'Quem é tua alma ligada — e quanto tempo você tá dando pra essa aliança?', 'Aliança não é conhecido. Não é seguidor. Não é colega. É alma ligada com alma. Jônatas e Davi se viram e viraram irmãos. Tua vida tem quem? Se morrer hoje, quem carrega teu caixão? Quem liga pra tua esposa? Quem pega teus filhos? Se a resposta é "não sei", você não construiu aliança. Tá na hora. Liga pra um. Marca café. Começa.', 'Solidão masculina é epidemia silenciosa. Alianças quebram.', '@jonataspellegrino'),
('01-21', 1, 21, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Até aqui nos ajudou o Senhor.', '1 Samuel 7:12', 'O que passou e você não percebeu que era Deus?', 'Você reza pedindo sinal enquanto Deus já mandou três. O emprego que veio na hora. A cura que ninguém explicou. O perdão que achava impossível. O filho que voltou. Registra. Memoriza. Conta pros teus. Deus não é o Deus do futuro só — é o Deus do já aconteceu. Se você esquece o que Ele fez, teu desespero cresce sem precisar.', 'Deus não te deve sinal novo. Você deve gratidão pelos antigos.', '@caleb.montenegro'),
('01-22', 1, 22, 'josue-caetano', 'Josué Caetano', '71.204', 'Escolhei hoje a quem sirvais.', 'Josué 24:15', 'Você serve a Deus ou serve à tua conveniência com verniz de Deus?', 'Josué colocou Israel no paredão. Hoje. Não amanhã. Hoje. A quem você serve? Se é Deus, mostra. Se é dinheiro, imagem, sexo, controle — fala pelo menos. Pior que idolatria é idolatria com disfarce de religião. Cristão que serve a Deus "nos horários que dá" não serve — terceiriza. Hoje é o dia. Escolhe inteiro.', 'Cristão de fim de semana é ateu de segunda.', '@josue.caetano'),
('01-23', 1, 23, 'davi-valverde', 'Davi Valverde', '71.337', 'Sonda-me, ó Deus, e conhece o meu coração.', 'Salmo 139:23', 'O que você não quer que Deus veja em você — e por que?', 'Davi pediu pra Deus sondar o coração dele. Esse versículo é pedido de exame completo. Você tem medo desse exame. Tem pasta escondida, aba fechada, relação não confessada, ressentimento acumulado, inveja maquiada. Deus já vê. A oração não é pra Ele ver — é pra VOCÊ ver. Pede sondagem. Pede exame. Depois lida com o que aparecer.', 'Coração não sondado é casa com porão infiltrado.', '@davi.valverde'),
('01-24', 1, 24, 'elias-dovale', 'Elias do Vale', '71.418', 'Levanta-te e come; o caminho te será longo.', '1 Reis 19:7', 'Você tá comendo direito pra batalha longa — ou se achando guerreiro numa dieta de exausto?', 'Elias tava debaixo do zimbro querendo morrer. O anjo acordou, deu comida, deu água, disse: come. Dormiu. Anjo voltou, deu mais. Disse: come, caminho é longo. Corpo é templo, mas também é veículo. Guerreiro cansado é candidato a cair. Dorme. Come. Hidrata. Trein. Guerra espiritual ganha com corpo cuidado. Negligência física é covardia disfarçada de espiritualidade.', 'Quem não cuida do corpo quer desculpa pra perder a guerra.', '@elias.dovale'),
('01-25', 1, 25, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Se o Senhor é conosco, por que tudo isto nos sobreveio?', 'Juízes 6:13', 'Onde você tá culpando Deus pela consequência das tuas próprias escolhas?', 'Gideão perguntou isso como se Deus tivesse falhado. Israel tinha abandonado Deus 7 anos antes. Deus não falhou — Israel escolheu. Você faz o mesmo. Toma decisão errada, depois pergunta: por que isso comigo? Ignorou conselho. Passou do limite. Comeu demais. Gastou demais. Ignorou a esposa. Depois culpa Deus. Algumas consequências são sementes tuas. Deus não é responsável pela colheita do que Ele não plantou.', 'Chama de provação o que é colheita de escolha.', '@gideao.sampaio'),
('01-26', 1, 26, 'neemias-barros', 'Neemias Barros', '71.612', 'Orei ao Deus dos céus.', 'Neemias 2:4', 'Que oração de emergência você ainda não fez por orgulho?', 'Neemias tava diante do rei, ia pedir coisa grande, e orou no meio da frase. Sem fechar olho, sem pose. Oração curta, dentro do caminho. Você acha que oração tem lugar certo, horário certo, postura certa. Não tem. Tem hora que é antes de uma reunião. Antes de um exame. No meio de uma briga. No carro. No banheiro. Ora agora. Mente já tá dispersa mesmo — redireciona.', 'Oração no meio do aperto é mais verdadeira que oração na sombra.', '@neemias.barros'),
('01-27', 1, 27, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Eis que o obedecer é melhor do que o sacrificar.', '1 Samuel 15:22', 'Que "sacrifício religioso" você faz pra compensar a desobediência em outra área?', 'Saul quis ofertar sacrifício em vez de obedecer. Samuel acabou com ele: obedecer é melhor. Você reza mais pra compensar a mentira que não largou. Dá mais oferta pra compensar o adultério que não confessou. Jejua pra compensar o filho que não educa. Deus não aceita troca. Obedece primeiro. Depois a oferta faz sentido.', 'Religião é cortina. Obediência é porta.', '@samuelqueiroga'),
('01-28', 1, 28, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Bem-aventurados os que têm fome.', 'Mateus 5:6', 'Qual sua fome de Deus — ou tu tá satisfeito com sobra de ontem?', 'Jesus disse: bem-aventurados os que TEM FOME. Não os satisfeitos. Não os bem-intencionados. Os que ainda querem mais. Fome de santidade. Fome de justiça. Fome de Deus. Se você tá satisfeito hoje com a oração que fez ontem, você secou. Crente satisfeito é crente adormecido. Fome é sinal de vida. Tua fome tá viva?', 'Crente satisfeito é crente adormecido.', '@benjamim.paiva'),
('01-29', 1, 29, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Farei sair de ti um espírito nova.', 'Ezequiel 36:26', 'O que em você tá pedindo pra ser trocado, não melhorado?', 'Deus disse em Ezequiel: vou DAR coração novo, não consertar o velho. Tem coisa em você que não é pra conserto. É pra troca. Vício, mágoa, cinismo, religiosidade fria — não ajusta, morre. Jesus não é ajustador. É trocador. Entrega, não reforma. Pede coração novo, não versão 2.0. Quer?', 'Tem vício que não é pra corrigir. É pra sepultar.', '@ezequielferraz'),
('01-30', 1, 30, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Tirou o manto que vestia e deu a Davi.', '1 Samuel 18:4', 'O que você precisaria tirar do próprio corpo pra provar que ama alguém?', 'Jônatas tirou o manto — símbolo do trono — e deu pro Davi. Deu arco. Deu espada. Cada peça era renúncia. Você fala "te amo" fácil. Renuncia difícil. Tira horário por um amigo. Tira dinheiro por um irmão. Tira orgulho por um filho. Tira razão por uma esposa. Amor prova por subtração, não por adjetivo. Que peça do teu manto tá na hora de tirar?', 'Amar é tirar. Quem não tira, só declara.', '@jonataspellegrino'),
('01-31', 1, 31, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Vai com a tua força.', 'Juízes 6:14', 'Que "vai" você tá esperando mais sinal pra obedecer?', 'Deus mandou Gideão: vai com a tua força. Não veio anjo do lado, não veio exército, não veio dinheiro antes. Foi "vai". Você quer "vai" já com tudo resolvido. Não vai. É "vai" e no caminho Deus resolve. Abraão saiu sem saber onde. Moisés subiu sem plano B. Pedro pisou sem boia. Vai com o que tens. O milagre encontra quem andou, não quem esperou.', 'Milagre é pra quem andou. Fica parado, o milagre passa reto.', '@caleb.montenegro'),
('02-01', 2, 1, 'josue-caetano', 'Josué Caetano', '71.204', 'Não te afastes dela nem para a direita nem para a esquerda.', 'Josué 1:7', 'Em que área da tua vida você tá fazendo "ajustinho" pra caber tua conveniência?', 'Deus disse pra Josué: a Palavra é o mapa. Nem direita nem esquerda. Crente moderno ama direita e esquerda. Ajusta a Escritura na fofoca, no trabalho, no dinheiro, na cama. Um pouquinho ali, outro aqui. Isso tem nome: apostasia gradual. Quando você acorda, já tá no fundo. Volta pro centro do caminho. Sem ajuste. Sem jeitinho. Reto é feio no curto prazo — mas só ele chega.', 'Ajuste teológico é rampa pra apostasia.', '@josue.caetano'),
('02-02', 2, 2, 'davi-valverde', 'Davi Valverde', '71.337', 'Aquietai-vos e sabei que eu sou Deus.', 'Salmo 46:10', 'Quando foi a última vez que você aquietou — sem celular, sem podcast, sem música?', '"Aquietai-vos" em hebraico é "harpu" — soltem as mãos, desistam da luta. Deus diz: PARA. Você roda há meses. Cabeça cheia, agenda cheia, rede cheia. Silêncio assusta. Pq no silêncio Deus fala o que você evita. Senta. Dez minutos. Zero estímulo. Se incomodar, não foge. Essa inquietação é o que precisa ser enfrentado. Aquieta.', 'Quem não aquieta, não escuta. Quem não escuta, erra caminho.', '@davi.valverde'),
('02-03', 2, 3, 'elias-dovale', 'Elias do Vale', '71.418', 'O Senhor não estava no vento.', '1 Reis 19:11', 'Em que altos você tá procurando Deus — enquanto Ele tá num sussurro que você ignora?', 'Elias buscou Deus no vento, no tremor, no fogo. Não achou. Deus tava no "som brando e suave". Você faz igual. Busca Deus em conferência, em show gospel, em jejum extremo, em experiência mística. Muitas vezes Ele tá no silêncio do banho, no choro do filho, na conversa com a esposa, no versículo simples. Para de procurar ESPETÁCULO e começa a escutar SUSSURRO.', 'Deus fala mais em sussurro que em tempestade.', '@elias.dovale'),
('02-04', 2, 4, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Não te gloriem sobre mim, dizendo: minha mão me livrou.', 'Juízes 7:2', 'Quantas vitórias recentes você tá atribuindo a "teu esforço" que na verdade foi Deus te protegendo de você mesmo?', 'Deus cortou o exército de Gideão pra ficar claro: a vitória é Dele. Você ganha e logo posta: "consegui". Acha que foi disciplina, foco, mindset. Foi. Mas também foi. Deus te guardando. Deus movendo peça. Deus segurando inimigo. Humildade não é negar teu trabalho — é reconhecer que mesmo o teu trabalho aconteceu dentro de graça. Glória é dEle. Lembra.', 'Tudo que você conquistou, Deus permitiu. Não esquece.', '@gideao.sampaio'),
('02-05', 2, 5, 'neemias-barros', 'Neemias Barros', '71.612', 'O Deus dos céus nos fará prosperar.', 'Neemias 2:20', 'Você declara "Deus vai prosperar isso" ou trabalha como se fosse só pelo teu braço?', 'Neemias trabalhou E declarou. Tocou as pedras E disse: o Deus dos céus faz prosperar. Tua oração não substitui teu braço. Teu braço não substitui tua oração. Crente fraco escolhe um dos dois. Cristão legendário carrega as duas cargas. Ora como se tudo dependesse de Deus. Trabalha como se tudo dependesse de ti. Ninguém disse que é leve.', 'Ora como se dependesse de Deus. Trabalha como se dependesse de ti. As duas.', '@neemias.barros'),
('02-06', 2, 6, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Servi ao Senhor com alegria.', 'Salmo 100:2', 'Seu serviço a Deus tá pesado — é direção errada ou atitude errada?', 'Davi disse: serve com alegria. Serviço certo com alegria errada é sacrifício — que Deus aceita mas não ama. Crente sério demais serve por medo. Crente sensato serve por amor. Se teu ministério, tua família, teu trabalho virou obrigação amarga, para. Ou muda direção, ou muda atitude. Nenhum dos dois vale escravo emburrado carregando saco.', 'Servir sem alegria é escravidão disfarçada de santidade.', '@samuelqueiroga'),
('02-07', 2, 7, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'O reino dos céus é tomado à força.', 'Mateus 11:12', 'Em que área da tua vida espiritual você tá esperando tudo "fluir" — quando Jesus disse que é conquista?', 'Jesus falou claro: reino dos céus é TOMADO. Não é recebido na poltrona. Violência santa — contra ti mesmo, contra pecado, contra inércia. Você quer oração fluida, leitura fluida, jejum fluido, serviço fluido. Não fluido: tomado. À força. Todo dia. Se tua fé virou "quando der", tu já entregou. Retoma. Tomando, não esperando.', 'Reino é conquista. Poltrona é esquife.', '@benjamim.paiva'),
('02-08', 2, 8, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Fui levado no espírito.', 'Ezequiel 37:1', 'Quando foi a última vez que você deixou o Espírito te levar — e não tua agenda?', 'Ezequiel tava sentado e de repente o Espírito levou. Tu senta e liga celular. Espírito Santo não briga com agenda lotada — Ele espera brecha. Hoje é dia de abrir brecha. 30 minutos sem destino. Bíblia, caderno, silêncio. Pede pro Espírito levar. Aonde? Tu não escolhe. Só vai. Quem anda com Espírito descobre lugares que agenda ignora.', 'Agenda cheia bloqueia o Espírito. Brecha convida.', '@ezequielferraz'),
('02-09', 2, 9, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'O que fizermos, havemos de ser leais.', '2 Samuel 15:15', 'Quem na tua vida tá esperando lealdade que você não tá dando?', 'Os homens disseram a Davi: faça o que for, a gente é leal. Lealdade é fácil em vitória. Em derrota, selva. Quem te segue quando você erra? E você — quem você segue quando ele erra? Lealdade com ressalva é amizade. Lealdade sem ressalva é pacto. Legendário faz poucos pactos, mas honra até o fim. Revisa teus pactos. Tá honrando?', 'Lealdade em vitória é fácil. Em queda é que prova.', '@jonataspellegrino'),
('02-10', 2, 10, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Dai-me, pois, agora este monte.', 'Josué 14:12', 'Qual monte você parou de pedir depois de uma derrota?', 'Caleb, 85 anos, dez depois daquela missão, seguia pedindo O MESMO monte. Não desistiu por causa de idade. Não desistiu por causa de demora. Você pediu uma vez, não veio, desistiu. Oração não é leilão — é posicionamento. Repete. Persiste. Herda pelo cansaço, não pela eloquência. Deus não é impressionado por frase bonita. Deus responde insistência de quem não arreda.', 'Quem desiste na primeira negativa, não tava pronto pra vitória.', '@caleb.montenegro'),
('02-11', 2, 11, 'josue-caetano', 'Josué Caetano', '71.204', 'Somente sê forte e tem grande ânimo.', 'Josué 1:7', 'Onde você tá procurando mais informação pra não precisar de coragem?', 'Josué não pediu planilha. Pediu coragem. Tu, sempre quer mais aula, mais podcast, mais livro, mais mentor. Isso vicia. Info vira desculpa. Info infinita é procrastinação travestida de preparação. Para. Você já sabe o que precisa. Fazer falta. Coragem vem praticando coragem, não estudando coragem.', 'Conhecimento sem coragem é covardia com diploma.', '@josue.caetano'),
('02-12', 2, 12, 'davi-valverde', 'Davi Valverde', '71.337', 'Bendize, ó minha alma, ao Senhor.', 'Salmo 103:1', 'Quando foi a última vez que você bendizou algo sem pedir nada?', 'Davi começa o salmo mandando a alma bendizer. Hoje a alma só sabe pedir. Deus vira caixa eletrônico espiritual. Você não bendiz porque acha que Ele DEVE. Não deve. Ele DEU. Levanta uma oração que só agradece. Nome por nome. Episódio por episódio. Sem pedido no fim. Tua alma vai doer de vergonha de como virou consumidora de graça.', 'Alma que só pede, perdeu o ofício de louvar.', '@davi.valverde'),
('02-13', 2, 13, 'elias-dovale', 'Elias do Vale', '71.418', 'Sobe, come e bebe.', '1 Reis 18:41', 'Que chuva você ainda não ouviu que Deus já disse que vem?', 'Elias ouviu a chuva antes de chover. Falou pra Acabe comer, ia chover. Pela FÉ ouviu, não pelo ouvido. Você vive dizendo: quando ver, acredito. Isso não é fé — é conferência. Fé é ouvir antes de chover. Comer antes. Dormir antes. Agir antes. Tem coisa que Deus já prometeu na tua vida. Tu tá esperando chover pra agir — e a obediência é agir ouvindo o som que só tu escuta.', 'Fé ouve o que ainda não chegou.', '@elias.dovale'),
('02-14', 2, 14, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Tomai da carne e dos asmos.', 'Juízes 6:20', 'Que "sinal de Deus" você já recebeu e desconsiderou porque não veio do jeito que você esperava?', 'Gideão ofereceu comida. O anjo falou: encosta a vara. O fogo subiu. Deus responde não do teu jeito — do jeito Dele. Você pede sinal, vem por conta inesperada, com pessoa imprevisível, em frase simples — e você descarta. Aprende: sinal que chega diferente ainda é sinal. Reconhece. Ajoelha. Agradece. Essa é a diferença entre quem anda com Deus e quem só fala dEle.', 'Sinal de Deus nem sempre vem pela porta que tu apontou.', '@gideao.sampaio'),
('02-15', 2, 15, 'neemias-barros', 'Neemias Barros', '71.612', 'Disse ao rei: se é do agrado do rei.', 'Neemias 2:5', 'Qual pedido ousado você adiou por "ser muito pedir"?', 'Neemias pediu carta imperial pro rei persa. Coisa grande. Ele tremia, mas pediu. Tu fica pequeno porque teu Deus encolheu na tua cabeça. Se Deus é o dono da prata e do ouro, pede grande. Não por ganância — por fé proporcional. Cristão que só pede "pão nosso de cada dia" numa geração que Jesus deu pão pra 5000 tá desatualizado. Ousa.', 'Pedido pequeno é fé pequena. Deus não cabe em oração covarde.', '@neemias.barros'),
('02-16', 2, 16, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Aqui estou, que me chamaste.', '1 Samuel 3:5', 'Que chamado você tá confundindo com ruído?', 'Samuel ouviu a voz e correu pro Eli, achando que era ele. Três vezes. Só na quarta entendeu: era Deus. Tu ouve coisas direto e confunde com teu próprio pensamento, com teu coach, com tua vontade. Treina ouvir. Pergunta: "Senhor, és Tu?" Aos poucos, identifica a voz. Ouvir é habilidade. Se desenvolve. Tu desenvolveu leitura, fala, decisão. Ouvir a Deus também precisa treino.', 'Ouvir a Deus não é mágica. É hábito.', '@samuelqueiroga'),
('02-17', 2, 17, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Forçoso nos é entrar no reino de Deus.', 'Atos 14:22', 'Que tribulação você tá tentando pular que Deus disse que é a porta?', 'Paulo disse: por muitas tribulações entramos no reino. Não alternativa — caminho. Você ora pra escapar da tribulação. A Bíblia diz: por ela. Pelo luto. Pela doença. Pela perda. Pela decepção. Não é castigo — é refinamento. Ouro sai do fogo, não do conforto. Se você fugir da tribulação, fugiu do próprio caminho do crescimento. Entra. Atravessa. Sai outro.', 'Tribulação não é desvio. É estrada.', '@benjamim.paiva'),
('02-18', 2, 18, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Filho do homem, estás vendo isto?', 'Ezequiel 8:12', 'O que Deus tá tentando te mostrar que você fecha os olhos pra não ver?', 'Deus levou Ezequiel e perguntou: tá vendo? Ezequiel via e detalhava. Tu? Deus mostra dia sim, dia não. Pela esposa. Pelo filho. Pelo corpo. Pelo negócio. Tu fecha. Fecha porque ver implica agir. E agir dá trabalho. Mas não ver não protege — atrasa. Abre os olhos. Olha direto. Dói no começo. Depois você age. Age — e alivia.', 'Não ver não é paz. É adiamento.', '@ezequielferraz'),
('02-19', 2, 19, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Se eu te disser: essas flechas estão aqui da banda de dentro.', '1 Samuel 20:21', 'Tem alguém na tua vida que você precisa alertar sobre perigo real — e tá calando por medo de ofender?', 'Jônatas avisou Davi por código de flechas. Não podia falar claro, mas avisou. Tu tem irmão em risco e cala. Amigo no pecado e sorri. Sócio em cagada e aplaude. Alertar dói pros dois. Calar dói pra um só — o da frente. Ama de verdade: alerta. Mesmo que quebre. Jônatas salvou Davi. Teu aviso pode salvar alguém — se você passar da covardia social e falar.', 'Amizade covarde assiste amigo afundar.', '@jonataspellegrino');
INSERT INTO public.provocacoes (dia_ano, mes, dia, autor_slug, autor_dia, autor_numero, citacao, autor_citacao, pergunta, texto, aspas_autor, instagram) VALUES
('02-20', 2, 20, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Mas Caleb aquietou o povo.', 'Números 13:30', 'Em que sala cheia de reclamação você tá calando por educação?', '12 espias foram. 10 voltaram apavorados. Caleb calou o povo — sozinho, contra os dez. Você entra em grupo onde todos lamentam. Todos criticam governo. Todos xingam mercado. Todos reclamam da igreja. Todos choram filho. Você cala "por educação". Caleb não calou. Interrompe. Reframe. Levanta a fé. Não é ingenuidade. É posição. Sala cheia de desespero precisa de um Caleb que fale.', 'Educação em sala derrotista é cumplicidade.', '@caleb.montenegro'),
('02-21', 2, 21, 'josue-caetano', 'Josué Caetano', '71.204', 'Naquele dia engrandeceu o Senhor a Josué.', 'Josué 4:14', 'Que reconhecimento Deus tá te preparando — e você tá fugindo por falsa humildade?', 'Depois do Jordão, Deus engrandeceu Josué diante de TODO Israel. Reconhecimento divino vem. Você vive fingindo que não quer. Diz que honra é pra Deus — e é. Mas usa isso pra fugir de plataforma, de palco, de chamado público. Falsa humildade é pecado. Aceita a obra que Deus preparou. Honra Ele na altura que Ele te colocar. Foge pra baixo também é desobediência.', 'Humildade não é recusar cadeira. É servir sentado nela.', '@josue.caetano'),
('02-22', 2, 22, 'davi-valverde', 'Davi Valverde', '71.337', 'Tua vara e teu cajado me consolam.', 'Salmo 23:4', 'Que correção de Deus você tá chamando de provação?', 'Pastor carrega vara e cajado. Vara bate, cajado guia. Os dois. Davi disse: me consolam. Tu, chora quando Deus corrige. Perde emprego e reclama — pode ser vara. Casamento racha e culpa outro — pode ser cajado. Corrige, não te abandona. Quem é castigado é filho. Quem é ignorado, não. Se Deus tá te disciplinando, alegra-te. É sinal de propriedade.', 'Disciplina dói. Ignorância é pior.', '@davi.valverde'),
('02-23', 2, 23, 'elias-dovale', 'Elias do Vale', '71.418', 'Quantos anos tens?', 'Gênesis 47:8', 'O que você tá postergando pra "ano que vem" há 5 anos?', 'Faraó perguntou a Jacó: quantos anos? Pergunta pesada. Resposta pesada. Tu, 40 anos e adia o chamado. 50 e ainda vai estudar. 60 e "um dia eu escrevo". Metusalém morreu. Tudo mundo morre. Tua postergação não é estratégica, é covardia. Faz HOJE o que há 5 anos você empurra. Amanhã a resposta da pergunta é uma a mais.', 'Ano que vem é o cemitério dos sonhos covardes.', '@elias.dovale'),
('02-24', 2, 24, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Quem de vós tem medo, volte.', 'Juízes 7:3', 'Quantas pessoas da tua vida tá pesando por medo — tuas ou delas?', 'Gideão mandou embora os medrosos. 22 mil foram. Ficaram 10 mil. Deus cortou mais. Ficaram 300. Medroso junto do front enfraquece todo mundo. Tua vida tem medroso. Sócio que sempre puxa freio. Amigo que vomita dúvida. Liderança que tropeça. Avalia: tá te ajudando ou drenando? Não julgue o medo — mas não carrega todo ele. Medroso volta. Tu segue.', 'Medo de outro vaza pelo teu poro se você mantiver perto.', '@gideao.sampaio'),
('02-25', 2, 25, 'neemias-barros', 'Neemias Barros', '71.612', 'Os nossos adversários disseram: nada saberão.', 'Neemias 4:11', 'Quem tá tentando te sabotar achando que você não percebe?', 'Os inimigos de Neemias falavam que iam invadir de surpresa. Neemias descobriu — e guardou. Tu é ingênuo. Pensa: "ninguém quer mal pra mim". Inveja tua. Ex-sócio planejando. Colega torcendo queda. Diabo armando. Não é paranoia — é discernimento. Ora por olhos abertos. Guarda tua obra. Muro sobe com espada também.', 'Quem não guarda, perde. Mesmo orando.', '@neemias.barros'),
('02-26', 2, 26, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Eis que o Senhor te pôs por rei sobre Israel.', '1 Samuel 15:17', 'Em que áreas Deus te colocou autoridade que você tá renunciando por preguiça?', 'Saul esqueceu quem era. Samuel lembrou: o Senhor te pôs. Tu esquece. Pai: Deus te pôs como autoridade da casa — tu abdica em nome de "respeitar a individualidade". Marido: Deus te pôs como guarda da esposa — tu vira colega. Líder: Deus te pôs como cabeça — tu delega tudo. Autoridade não é sobre poder. É sobre responsabilidade. Retoma.', 'Autoridade delegada sem retomada é abandono.', '@samuelqueiroga'),
('02-27', 2, 27, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Trabalhai pela comida que não perece.', 'João 6:27', 'Quantas horas você gastou nessa semana no que não dura — e quantas no que dura?', 'Jesus disse: não trabalha só pelo que perece. Tu trabalha 60h pela empresa, 2h pela família, 0h pelo reino. Conta. Sente a vergonha. Não é moralismo — é matemática. Tempo investido no eterno é o único que sobra. O dinheiro que você acumulou, alguém vai gastar. A alma que você formou, alguém vai lembrar. Reorganiza tua planilha da semana. Pelo que sobra.', 'Você é o que você investiu tempo em construir.', '@benjamim.paiva'),
('02-28', 2, 28, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Estabelecerei um sinal sobre ti.', 'Ezequiel 4:3', 'O que tua vida tá pregando sem tu abrir a boca?', 'Deus mandou Ezequiel virar sinal vivo. Sem falar — já era pregação. Tu também é. Vizinho olha teu casamento. Equipe olha teu temperamento. Filho olha teu tempo. Câmera não liga só no culto — liga o tempo todo. Tua vida é o sermão mais longo que tu prega. Concorda com o que ela fala?', 'Tua vida fala mais que tua boca. Revisa o que ela tá anunciando.', '@ezequielferraz'),
('02-29', 2, 29, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Vai em paz, porquanto ambos juramos pelo nome do Senhor.', '1 Samuel 20:42', 'Que aliança você tá deixando se deteriorar por falta de oração comum?', 'Jônatas e Davi selavam aliança por Deus. Não por simpatia. Por Deus. Tu tem amigo, mas não orou junto. Tem sócio, mas não orou junto. Tem irmão, mas só compartilha meme. Aliança que não tem Deus no meio é papel sem assinatura. Próximo encontro: pede pra orar junto. Parece estranho. Depois vai ser indispensável.', 'Aliança sem oração é amizade à prova de crise. Não aguenta.', '@jonataspellegrino'),
('03-01', 3, 1, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Toma posse dela.', 'Deuteronômio 1:21', 'Qual terra Deus já te deu que você tá esperando "ser merecedor" pra tomar?', 'Deus falou claro: a terra tá dada. Sobe. Possui. A maioria gasta a vida se achando pouco digno. Deus não deu porque você merece. Deu porque é o plano. Tua inadequação é sabida — e ainda assim a terra tá liberada. Toma. Possui. Dignidade vem da posse, não antes. Caleb não esperou dignidade. Subiu.', 'Dignidade é fruto da posse, não requisito pra ela.', '@caleb.montenegro'),
('03-02', 3, 2, 'josue-caetano', 'Josué Caetano', '71.204', 'Esta terra se vos dará por herança.', 'Deuteronômio 3:18', 'O que você tá esperando "ficar pronto" pra tomar — que Deus já te deu?', 'Moisés mandou Rúben e Gade: a terra já é de vocês. Vão. Tu recebe promessa e congela. Espera mais sinal, mais confirmação, mais maturidade. Deus já disse. Você tá esperando VOCÊ achar que tá pronto. Isso não vem. Toma com medo. Toma trêmulo. Toma imperfeito. A terra é tua. Posse passiva não existe — é ocupação ativa ou perda por desuso.', 'Promessa não se guarda. Se ocupa.', '@josue.caetano'),
('03-03', 3, 3, 'davi-valverde', 'Davi Valverde', '71.337', 'Porque o Senhor esquadrinha todos os corações.', '1 Crônicas 28:9', 'O que você não quer que Deus veja — e por que você acha que Ele não vê?', 'Davi alertou Salomão: cuidado, Deus esquadrinha tudo. Você tem zonas protegidas. Gavetas fechadas. Abas privadas. Pensamentos que rotula como passageiros. Deus não pergunta se pode entrar. Já entrou. Sua privacidade com Deus é ilusão. Então escolhe: lidar com o que Ele já vê ou fingir que Ele não sabe. A segunda opção é mais pesada porque alimenta vergonha. A primeira é mais curta porque começa com confissão e termina com liberdade.', 'Não tem gaveta privada com Deus. Só tem gaveta ignorada por você.', '@davi.valverde'),
('03-04', 3, 4, 'elias-dovale', 'Elias do Vale', '71.418', 'Tomou Elias o seu manto.', '2 Reis 2:8', 'Que manto você tá usando que não é seu — e por quanto tempo mais vai se disfarçar de outro?', 'Elias tinha manto próprio. Identidade própria. Profeta com linguagem própria. Você? Imita pastor de YouTube, mentor de livro, gurú de podcast. Mistura cinco mantos e não tem o teu. Legendário tem voz própria. Calibrada no front. Tira esse manto emprestado. Assume o teu. Pode ser mais simples. Mais tosco. Mais cru. Mas é teu — e Deus unge o teu, não o emprestado.', 'Manto emprestado pesa mais que manto teu.', '@elias.dovale'),
('03-05', 3, 5, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'A espada do Senhor e de Gideão.', 'Juízes 7:20', 'Você consegue nomear a guerra que Deus te deu — ou anda brigando em guerra que ninguém chamou?', 'Os 300 gritaram: a espada do Senhor e de Gideão. Guerra nomeada. Lado definido. Tu, cristão moderno, briga em tudo. Briga na internet, briga em grupo de família, briga no trânsito, briga em tudo e não ganha nada. Foca. Deus te deu uma guerra específica. Família, vício, vocação, liderança. Essa. Não dispersa energia em guerras que não são tuas.', 'Guerreiro disperso não vence. Fica cansado.', '@gideao.sampaio'),
('03-06', 3, 6, 'neemias-barros', 'Neemias Barros', '71.612', 'Ouviu-me ali e muito me alegrei.', 'Neemias 2:10', 'Quantos adversários do teu projeto você tá ignorando achando que somem sozinhos?', 'Neemias chegou em Jerusalém e já tinha inimigo esperando — Sambalate e Tobias. Ele não ignorou. Reconheceu. Tomou nota. Seu projeto sério sempre tem Sambalate. Ex-sócio. Concorrente. Crítico. Torcedor da queda. Você finge que não tem. Pior pra você. Reconhece o inimigo específico, documenta a estratégia de ataque dele, e age. Ignorar Sambalate é deixar o muro vulnerável.', 'Inimigo ignorado é inimigo armado.', '@neemias.barros'),
('03-07', 3, 7, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Tira a verdade escondida.', 'Salmo 51:6', 'Que mentira que você conta pra você mesmo todo dia virou hábito?', 'Davi escreveu em Salmo 51: Deus quer verdade nas partes escondidas. Tu vive de autoengano. "Vou parar amanhã." "Tô bem." "É só mais um." "Ninguém repara." "Eu tô no controle." Mentira. Cada uma delas. Sequestra 10 minutos hoje. Escreve no papel o que você tá se mentindo. Sem censura. Deus quer verdade — começa pela tua.', 'Autoengano é pecado com jaqueta de esperteza.', '@samuelqueiroga'),
('03-08', 3, 8, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Maior é o que está em vós.', '1 João 4:4', 'Tu tá agindo como se Deus fosse menor que o teu problema — ou maior?', 'João disse: maior é Aquele que tá EM VÓS. Em. Dentro. Tu anda como se Deus fosse ficar do lado, observando, torcendo. Não. Ele tá dentro. O mesmo poder. A mesma autoridade. E tu, pequeno, trava, medo, desiste. Se Deus tá dentro e você ainda se sente pequeno, o problema é tradução. Aprende a agir pelo que habita em ti, não pelo que te rodeia.', 'Se o Maior tá dentro, menor é o que tá fora.', '@benjamim.paiva'),
('03-09', 3, 9, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Tornarei um só pau.', 'Ezequiel 37:17', 'Que fragmentação na tua vida Deus tá querendo unir — e você tá insistindo em manter separado?', 'Ezequiel pegou dois paus e uniu. Deus falou: vou unir o que tá dividido. Tua vida é fragmentada. Um Brunno no trabalho, outro em casa. Um no culto, outro no bar. Um na rede social, outro quando ninguém vê. Deus unifica. Integridade (etimologicamente: integração) é quando os teus pedaços viram uma coisa só. Custa. Mas Deus não usa pedaço.', 'Deus não usa pessoa fragmentada. Ele unifica antes de usar.', '@ezequielferraz'),
('03-10', 3, 10, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Amava Jônatas a Davi como a sua própria alma.', '1 Samuel 20:17', 'Quem você ama tanto quanto a si mesmo — e isso se prova em quê?', 'Jônatas amava Davi como a própria alma. Isso é Mandamento antes do NT. Amar como a si mesmo é alto. Tu? Ama como ajuda, quando sobra tempo, quando convém. Cristão não ama meia-boca. Escolhe um. Esposa. Filho. Amigo. Irmão. E ama a esse como ama a si — tempo, dinheiro, atenção, disposição. Se não consegue, confessa que é mentira o "amo todos". Começa num. Faz verdade.', 'Quem ama todos igualzinho, ama raso em todos.', '@jonataspellegrino'),
('03-11', 3, 11, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Bem-aventurado o homem que não anda.', 'Salmo 1:1', 'Quais três conselhos você andou seguindo que eram do ímpio com roupa de amigo?', 'Salmo 1 começa dizendo: bem-aventurado quem NÃO anda com ímpio. Tu anda. Segue. Curte. Compartilha. Acha bonito. Acha sagaz. Acha realista. O ímpio moderno não aparece com chifre. Aparece com estética, marketing, frase de efeito. Tu absorve. Faz inventário: três conselhos recentes que moldaram tua última decisão — de onde vieram? Se não sobrevive ao crivo bíblico, larga. Andar errado contamina devagar.', 'Ímpio moderno é elegante. Por isso ninguém percebe.', '@caleb.montenegro'),
('03-12', 3, 12, 'josue-caetano', 'Josué Caetano', '71.204', 'Vós passareis armados.', 'Josué 1:14', 'Em que batalha dos outros você tá se recusando a entrar por comodismo?', 'Josué mandou Rúben e Gade: vocês já têm terra, mas atravessam armados com os irmãos. Tu, cristão individualista, conquistou tua terra (carreira, família, estabilidade) e senta. Deixa irmão se virar. Errado. Passa armado. Ajuda quem ainda luta. Seu próximo, tua igreja, teu discípulo. Guerreiro sozinho é ego. Guerreiro junto é reino.', 'Quem já venceu e não volta ajudar, virou desertor.', '@josue.caetano'),
('03-13', 3, 13, 'davi-valverde', 'Davi Valverde', '71.337', 'Alegrai-vos no Senhor.', 'Filipenses 4:4', 'Quantas vezes ontem você escolheu alegrar em vez de reclamar?', 'Paulo, preso, escreveu: alegrai-vos. Tu, com wi-fi, geladeira cheia, família inteira, reclama. Alegria não é emoção, é escolha. Conta: ontem, quantas vezes você lamentou? Quantas agradeceu? Tua voz interna molda tua realidade. Se a trilha sonora é reclamação, a tua vida segue roteiro de reclamado. Muda a trilha. Agradece a mão, o café, a cama, a filha que incomoda, o joelho que dói. Alegria é disciplina de pobre que conhece riqueza real.', 'Alegria é escolha de quem viu pior.', '@davi.valverde'),
('03-14', 3, 14, 'elias-dovale', 'Elias do Vale', '71.418', 'Quarenta dias e Nínive será destruída.', 'Jonas 3:4', 'Qual aviso você tá segurando por medo de soar exagerado?', 'Jonas gritou: 40 dias. Curto e cru. Não floreou. Você? Tem aviso pra dar (marido, filho, irmão, equipe) e enrola. Passa pano. Faz analogia. Chama em privado pra não constranger. Às vezes é prudência. Muitas vezes é covardia. Discernimento: quando o preço da suavização é a perda do recado, você suavizou demais. Jonas foi direto. Nínive se arrependeu. Tua suavidade deixa ninguém se arrepender.', 'Recado suavizado não converte. Só tranquiliza quem deu.', '@elias.dovale'),
('03-15', 3, 15, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'E quebraram os cântaros que tinham nas mãos.', 'Juízes 7:19', 'Que "cântaro" de segurança você precisa quebrar pra a luz sair?', 'Os 300 de Gideão tinham tochas dentro de cântaros. Quebraram os cântaros. Luz só apareceu depois do quebrado. Tu tem coisa guardando tua luz: trabalho falso, relacionamento morno, aparência de tudo ok, reputação preservada. Enquanto o cântaro tá inteiro, ninguém vê a luz. Precisa quebrar. Verdade dita. Mudança feita. Sacrifício real. Medo de quebrar é vergonha disfarçada.', 'Luz guardada não vence guerra. Só luz exposta.', '@gideao.sampaio'),
('03-16', 3, 16, 'neemias-barros', 'Neemias Barros', '71.612', 'Fiz oração e pus guarda.', 'Neemias 4:9', 'Quando foi a última vez que você fez as duas — ora e age — no mesmo dia?', 'Neemias fez as duas coisas. Não é frase bonita, é prática. A maioria faz uma. Ora de manhã, age o dia com cabeça nublada. Ou age o dia, esquece de orar, dorme frustrado. Hoje: liga as duas. Ora no primeiro evento, resolve com cabeça fria. Ora na reunião difícil, fala com convicção. Isso é integração. O sagrado não fica só no início do dia.', 'Oração de manhã que não integra o dia vira ritual vazio.', '@neemias.barros'),
('03-17', 3, 17, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Rejeitou ser rei sobre nós.', '1 Samuel 8:7', 'Quem você colocou no lugar de Deus — e tá chamando isso de pragmatismo?', 'Israel pediu rei humano. Samuel se sentiu rejeitado. Deus explicou: não é você — é a Mim que rejeitaram. Tu substitui Deus por cargos, por dinheiro, por imagem, por pessoa. Chamas de foco. Chamas de realismo. Chamas de estratégia. É rejeição de Deus com nome técnico. Volta. Recoloca Ele no centro. Pragmatismo sem Deus vira ídolo com planilha.', 'Substituir Deus por planilha é idolatria moderna.', '@samuelqueiroga'),
('03-18', 3, 18, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Combate o bom combate da fé.', '1 Timóteo 6:12', 'Você tá combatendo ou só reclamando da luta?', 'Paulo disse: COMBATE. Verbo ativo, imperativo. Você gosta mais de reclamar da luta que de combater. "Ah, tá difícil." "Deus me provou demais." "Meu caso é complicado." Mentira de covarde. Combate é ação. Oração é ação. Jejum é ação. Obediência é ação. Sair da cama é ação. Parar de postar lamento e começar a agir — ação. Bom combate existe. Mas combate.', 'Choramingar em voz de vítima é desistir com edit de oração.', '@benjamim.paiva'),
('03-19', 3, 19, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Cavei na parede.', 'Ezequiel 8:8', 'Que parede aparentemente sólida na tua vida Deus tá te mandando cavar pra ver o que tá escondido?', 'Deus mandou Ezequiel cavar a parede. Aparecia normal. Cavou. Atrás, idolatria escondida. Tua casa tem parede assim. Parece ok de fora. Igreja vai, diz amém, lê versículo. Cava. Atrás pode ter ressentimento guardado há 3 anos. Vício secreto. Ferida não tratada. Idolatria de conforto. Deus não quer só aparência. Quer cavar. Aceita a escavação — Ele não cava pra humilhar. Cava pra libertar.', 'Parede lisa de fora pode esconder altar de Baal dentro.', '@ezequielferraz'),
('03-20', 3, 20, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Davi e Jônatas fizeram aliança.', '1 Samuel 18:3', 'Você tem pacto formal com alguém — ou só tem amizades casuais?', 'Davi e Jônatas FIZERAM aliança. Ato formal. Verbo. Declaração. Você tem pacto com alguém? Marca com nome, palavra, e prova com tempo. Grupo de oração fixo — tem? Encontro mensal fixo — tem? Três caras que sabem teus vícios e teu sonho — tem? Se não tem, constroi. Aliança não é sentimento — é arquitetura. Começa a projetar a tua.', 'Amizade não-ritualizada derrete na crise.', '@jonataspellegrino'),
('03-21', 3, 21, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Aquela terra sobre que pisaste.', 'Deuteronômio 11:24', 'Você reza pela terra que ainda não pisou — e esquece da que tá embaixo do teu pé?', 'Deus disse: a terra que você pisa é tua. Pisar é verbo. Você fica orando pelo próximo contrato, próximo cliente, próximo nível — e negligencia o que já tá debaixo do pé. Casamento, família, negócio atual, ministério atual. Não precisa de mais terra nova — precisa pisar fundo na que já tem. Pisa com presença. Pisa com atenção. Pisa com excelência. Essa terra, ainda não tomada plenamente, tá te esperando.', 'Terra nova não substitui terra não pisada.', '@caleb.montenegro'),
('03-22', 3, 22, 'josue-caetano', 'Josué Caetano', '71.204', 'Apartai-vos dos deuses estranhos.', 'Josué 24:23', 'Que "deus estranho" você tolera no teu templo interno achando que não atrapalha?', 'Josué disse no fim: apartai. Não remova um pouco. Aparta. Corta. Tira. Teus deuses estranhos não são estátua — são hábito. O celular logo antes de dormir. A cerveja de sexta "só uma". A ambição que justifica qualquer custo. A imagem nas redes. Aparta. Não negocia. Negociação com ídolo é derrota lenta. Decisão imediata.', 'Idolatria é negociada aos poucos até a alma virar zero.', '@josue.caetano'),
('03-23', 3, 23, 'davi-valverde', 'Davi Valverde', '71.337', 'Tirou-me de um lago horrível.', 'Salmo 40:2', 'Por onde Deus já te tirou — e que tu tá dando pouco crédito?', 'Davi descreveu: lago horrível, lama do lodo. Deus tirou. Tu olha pra trás: foi Deus ou foi teu esforço? Se falar "foi eu" muito fácil, você já esqueceu. A proteção de Deus é silenciosa. Tu não vê o acidente que Ele desviou. Não vê a doença que Ele atrasou. Não vê a pessoa tóxica que Ele removeu. Só vê o lago de onde saiu — e até isso negas. Humildade começa em lembrança.', 'Você saiu de mais lagos do que admite. Cada um foi Ele.', '@davi.valverde'),
('03-24', 3, 24, 'elias-dovale', 'Elias do Vale', '71.418', 'E subiu Elias ao cume do Carmelo.', '1 Reis 18:42', 'Qual monte você precisa subir sozinho pra ouvir o que ninguém mais escuta?', 'Elias subiu sozinho. Se ajoelhou. Rezou 7 vezes enquanto o servo ia ver a nuvem. Tu não fica só. Tu não sobe. Tu não insiste. Desce no primeiro "ainda nada". Legendário sobe o monte. Demora. Insiste. Escuta o sussurro. Ora sete. Se o céu tá ferro, reza oito. Os santos não tinham dom — tinham paciência. Tu é impaciente. Cura isso.', 'Sete pedidos sem resposta ainda não justifica descer.', '@elias.dovale'),
('03-25', 3, 25, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'O medo causará desmaio ao coração.', 'Levítico 26:36', 'Quem mais medo você tá vivendo — ou fé?', 'Levítico avisa: medo desmaia coração. Você vive em estado de medo. Medo de perder emprego. Medo de adoecer. Medo do que os outros vão achar. Medo da rejeição. Medo de ficar sozinho. Medo do futuro. Cada medo é um pedaço do coração desmaiando. Fé é o antídoto — e é prática diária. Toda vez que você escolhe fé em vez de medo, teu coração acorda um pouco.', 'Medo é confiança depositada na ameaça, em vez de em Deus.', '@gideao.sampaio'),
('03-26', 3, 26, 'neemias-barros', 'Neemias Barros', '71.612', 'Ajudar-me-ia contra meu adversário.', 'Neemias 2:9', 'Quais pessoas Deus já te deu que você não tá usando por orgulho?', 'Neemias aceitou ajuda. Chefes do exército, cartas reais. Não fez sozinho. Tu, macho, acha feio pedir ajuda. Contador que corrige tua loucura, advogado que evita tua cagada, amigo que traduz tua esposa, pastor que escuta teu segredo. Eles já foram colocados. Tu só precisa usar. Orgulho é caro. Custou mais muro do que todos os Sambalates do mundo.', 'Quem só pede ajuda no desespero paga caro a lição.', '@neemias.barros'),
('03-27', 3, 27, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Esperai um pouco.', '1 Samuel 9:27', 'O que você tá forçando pra acelerar que Deus tá te pedindo pra pausar?', 'Samuel pediu pra Saul esperar. Não muito. Um pouco. Tu odeia esperar. Faz o achismo e chama de fé. Força porta que não é pra hoje e chama de iniciativa. Há coisa que requer espera. Maturidade do filho. Cura da ferida. Aprovação do processo. Clareza da decisão. Forçar antes da hora é arrogância disfarçada de proatividade. Pausa. Um pouco. Ouve o que Deus diz no intervalo.', 'Espera não é preguiça. Forçar antes da hora é orgulho.', '@samuelqueiroga'),
('03-28', 3, 28, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Os violentos é que o arrebatam.', 'Mateus 11:12', 'Que violência santa você tá evitando porque prefere conforto?', 'Jesus chama de violentos quem toma o reino. Não é agressão — é intensidade. Tu evita intensidade. Cristão morno é regra hoje. Oração morna, leitura morna, jejum morno, discipulado morno. Não arrebata. Não conquista. Não toma. Morno. Deus cospe morno. Quebra o padrão: hoje, uma coisa feita com intensidade total. Oração longa. Jejum real. Decisão radical. Intensidade santa não é pra show — é pra tomar.', 'Intensidade santa assusta crente morno. Essa é a ideia.', '@benjamim.paiva'),
('03-29', 3, 29, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Coração de carne te darei.', 'Ezequiel 36:26', 'Quais áreas do teu coração já endureceram — que Deus tá esperando entrega pra substituir?', 'Deus prometeu coração de CARNE no lugar de pedra. Tu tem área endurecida. Sobre dinheiro. Sobre perdão. Sobre a ex. Sobre o pai ausente. Sobre a igreja que machucou. Sobre você mesmo. Endurecer parece proteção — é cadeia. Entrega pra Ele. "Senhor, aqui tá duro. Substitui por carne." Coração de carne sente, sangra, cura. Coração de pedra só quebra em pedaços.', 'Coração de pedra parece protegido. É só duro até estilhaçar.', '@ezequielferraz'),
('03-30', 3, 30, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Forte mais que o amor das mulheres.', '2 Samuel 1:26', 'Que tipo de amor masculino santo você nunca experimentou — e por que nunca buscou?', 'Davi chorou Jônatas: amor mais forte que amor das mulheres. Não sexual. Amor de irmão de pacto. Tu teme intimidade masculina santa. Confunde com fraqueza. Confunde com afeminamento. Erra feio. Legendário tem irmão que abraça. Irmão que chora com. Irmão que enfrenta. Sem essa intimidade sagrada, você vai viver guerras sozinho. E solidão masculina mata — estatística real.', 'Irmão de pacto é mais forte que amante. E tu tá sozinho.', '@jonataspellegrino'),
('03-31', 3, 31, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Retiveram a palavra.', 'Gênesis 37:11', 'Quais palavras proféticas sobre tua vida você jogou fora por acharem loucura?', 'Os irmãos de José ouviram o sonho e tiraram sarro. O pai reteve a palavra. Ponderou. Guardou. Tu ouve palavra profética (pregação que grita, palavra de irmão, versículo específico que vem no espírito) e joga fora. Cumpre depois. Retém. Anota. Guarda. Nem tudo faz sentido hoje. Algumas sementes só brotam em 20 anos. José foi um deles.', 'Palavra retida é semente plantada. Palavra jogada é fato perdido.', '@caleb.montenegro'),
('04-01', 4, 1, 'josue-caetano', 'Josué Caetano', '71.204', 'Edificou Josué um altar.', 'Josué 8:30', 'Qual altar você ainda não construiu pra marcar uma vitória recente?', 'Depois da vitória em Ai, Josué construiu altar. Não foi comemoração — foi declaração. Tu vence e esquece. Fez milagre e não registrou. Ganhou cliente grande e deletou o email. Saiu do vício e não escreveu a data. Altar é memória física. Escolhe um objeto, escreve uma data, põe onde veja. Altar é a diferença entre testemunho e amnésia.', 'Vitória não marcada é vitória perdida.', '@josue.caetano'),
('04-02', 4, 2, 'davi-valverde', 'Davi Valverde', '71.337', 'Derrama como águas o teu coração.', 'Lamentações 2:19', 'Quando foi a última vez que você chorou com Deus — sem filtro, sem paciência com teu ego?', 'Jeremias escreveu: derrama. Davi derramou. Chorou, escreveu, cantou. Você tranca lágrima como se fosse virilidade. Idiotice. Legendário chora. Com Deus, com esposa, com irmão de pacto. Não toda hora, não por manha — por emoção real tratada. Represa de lágrima vira raiva. Vira vício. Vira distância. Derrama hoje. Começa por 10 minutos em oração sincera. Depois fala com humano.', 'Macho que não chora, adoece. E machuca quem ama.', '@davi.valverde'),
('04-03', 4, 3, 'elias-dovale', 'Elias do Vale', '71.418', 'Trata-me como um dos teus jornaleiros.', 'Lucas 15:19', 'Em que área você tá brincando de filho quando Deus tá te chamando de volta de verdade?', 'Prodígio voltou disposto a ser jornaleiro — servo. Tu volta pra Deus com negociação. "Volto, mas mantém meu status." "Volto, mas não confesso tudo." "Volto, mas a relação continua." Não é volta. É ajuste de conveniência. Volta de verdade não tem cláusula. É inteira. Deus recebe até na forma de servo — e restaura. Mas a volta parcial é pior que o ficar longe.', 'Volta negociada não é volta. É marketing espiritual.', '@elias.dovale'),
('04-04', 4, 4, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Gideão lhes respondeu: eu não dominarei sobre vós.', 'Juízes 8:23', 'Que convite de poder você precisaria recusar mesmo podendo dizer sim?', 'Povo quis fazer Gideão rei. Recusou: "o Senhor dominará". Raro. Tu, se oferecem cargo, aceita sem discernir. Nem sempre aceitar é avançar. Às vezes o trono oferecido é armadilha de orgulho. Perguntas antes: é pra mim mesmo? É hora? É do Reino ou do meu ego? Nem tudo que te chamam a liderar é liderança do Alto.', 'Cadeira oferecida sem direção divina é armadilha de orgulho.', '@gideao.sampaio'),
('04-05', 4, 5, 'neemias-barros', 'Neemias Barros', '71.612', 'E o povo tinha ânimo para trabalhar.', 'Neemias 4:6', 'Como tá o ânimo do teu time — e o que ele tá refletindo do teu?', 'Neemias observa: o povo tinha ânimo. Líder sem ânimo gera time sem ânimo. Tu vai amargurado pra casa, a esposa sente. Vai apático pro trabalho, equipe afunda. Teu ânimo não é assunto privado — vaza. Cuida dele. Ora por ele. Durma bem. Faça exercício. Alegre-se. Teu ânimo é bandeira que o time todo segue, queira ou não.', 'Líder triste forma exército desanimado.', '@neemias.barros'),
('04-06', 4, 6, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Cessa de me perturbar.', 'Juízes 9:31', 'Que conselho você tá dando há meses e a pessoa claramente não vai seguir — por que insiste?', 'Abimeleque cansou. Samuel aprendeu a respeitar obstinação alheia. Tu gasta energia aconselhando quem não quer ouvir. Filho, irmão, amigo, sócio. Eles vão ter que aprender apanhando. Pede sabedoria pra saber quando falar e quando silenciar. Amor maduro às vezes é silêncio. Continuar insistindo depois do claro é ansiedade tua — não responsabilidade cristã.', 'Conselho repetido vira ruído. Cala, ora, espera.', '@samuelqueiroga'),
('04-07', 4, 7, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Sendo ouvintes esquecidos.', 'Tiago 1:25', 'Quantas pregações você ouviu nas últimas 3 semanas — e o que mudou em você?', 'Tiago cutuca: ouvir e não fazer é esquecer. Tu consome conteúdo bíblico como podcast de motivação. Ouve, posta, esquece. Zero mudança. Tiago chama isso de esquecido. Legendário aplica. Uma palavra por semana. Uma só. E pratica sete dias. Transformação não é volume de informação — é obediência continuada.', 'Consumidor de sermão sem obediência é ateu educado.', '@benjamim.paiva'),
('04-08', 4, 8, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Filho do homem, come o que achares.', 'Ezequiel 3:1', 'Que palavra amarga Deus tá te mandando engolir — e você tá fazendo bico?', 'Deus mandou Ezequiel comer um livro. No começo, doce. No estômago, amargo. Palavra de Deus nem sempre desce fácil. Correção. Responsabilidade. Sacrifício. Você quer só o doce. O amargo vem junto — é a parte que transforma. Engole. Dói descer, cura depois. Cristão que só consome doutrina doce morre de diabete espiritual.', 'Palavra amarga é a que cura mais fundo.', '@ezequielferraz'),
('04-09', 4, 9, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Oposição de Saul.', '1 Samuel 19:2', 'Quem na tua família tá boicotando teu chamado — e você tá respeitando demais?', 'Jônatas tinha Saul (pai) contra Davi. Escolheu Davi. Família também opõe. Pai cético do teu sonho. Mãe amedrontada da tua decisão. Irmão que minimiza. Esposa que reclama. Respeitar família é correto. Mas respeitar à custa de abandonar o chamado é idolatria familiar. Jônatas amou o pai E escolheu o irmão de pacto. Os dois. Aprende a amar sem abdicar.', 'Idolatria familiar atrasa mais gente que o diabo.', '@jonataspellegrino');
INSERT INTO public.provocacoes (dia_ano, mes, dia, autor_slug, autor_dia, autor_numero, citacao, autor_citacao, pergunta, texto, aspas_autor, instagram) VALUES
('04-10', 4, 10, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Sois ainda tão fortes como éreis naquele dia.', 'Josué 14:11', 'Que habilidade/força você já tinha que parou de usar por preguiça disfarçada de maturidade?', 'Caleb, 85, disse: ainda tô tão forte quanto aos 40. Tu, 40, "já não sou mais o mesmo". Mentira. Parou de treinar. Parou de estudar. Parou de persuadir. Parou de arriscar. A força não sumiu — sumiu o uso. Volta a usar. Exercícios. Leitura. Ministério. Voluntariado. Vai descobrir que tá mais forte do que tu achava. Só precisa ativar.', 'Força não treinada some. Mas volta mais rápido do que você imagina.', '@caleb.montenegro'),
('04-11', 4, 11, 'josue-caetano', 'Josué Caetano', '71.204', 'Escolhe hoje.', 'Josué 24:15', 'Quais decisões você tá deixando pra "daqui a pouco" — que Deus tá dizendo pra hoje?', 'Josué mandou Israel escolher HOJE. Daqui a pouco é covardia com roupa de prudência. Marido que conversa com esposa "quando estiver mais calmo". Pai que vai confrontar filho "quando tiver tempo". Empresário que vai pivotar o negócio "assim que o trimestre fechar". A verdade é: nunca tá o momento perfeito. Hoje é sempre o momento. Quanto mais cedo, menos rastro de dano.', 'Daqui a pouco é amanhã. Amanhã é nunca.', '@josue.caetano'),
('04-12', 4, 12, 'davi-valverde', 'Davi Valverde', '71.337', 'Maior é o que está em nós.', '1 João 4:4', 'Em qual frase pequena você tá apostando tua grandeza — e tá perdendo?', 'Davi era pastor, sem histórico militar. O que ele tinha de grande? Um gigante dentro, maior que o gigante fora. Tu mede tua grandeza pelo teu currículo. Errado. Teu currículo não é tua medida. Deus em ti é. Renuncia a comparação. Assume a habitação. Grandeza não é sobre o que você teve — é sobre quem te habita. Davi tinha cinco pedras e o Maior. Bastou.', 'Currículo é passado. Gigante dentro é futuro.', '@davi.valverde'),
('04-13', 4, 13, 'elias-dovale', 'Elias do Vale', '71.418', 'Eles se cansaram.', 'Habacuque 2:13', 'Qual parte do teu esforço é vã — porque não foi mandada por Deus?', 'Habacuque alerta: povo se cansou em vão. Tu constrói tanto. Tanto. E não pergunta se Deus mandou. Casa que Deus não projetou vai pro chão. Negócio que Deus não chamou vai pro buraco. Ministério sem envio vai virar trabalho braçal. Faz pausa. Pergunta: Senhor, isso é Tua obra ou meu projeto? Tem a coragem de ouvir resposta que você não quer.', 'Trabalho em vão cansa mais que o verdadeiro. É peso sem glória.', '@elias.dovale'),
('04-14', 4, 14, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Lambe com a língua como lambe o cão.', 'Juízes 7:5', 'Que detalhe aparentemente insignificante na tua disciplina tá separando os escolhidos dos descartados?', 'Deus separou os 300 por como bebiam água. Detalhe microscópico. Tua disciplina se define nos pequenos. Hora que levanta. O que come. Se ora antes da refeição. Se olha celular na mesa. Se cumpre palavra com filho. Nada épico. Puro detalhe. Deus te seleciona no micro. Macro vem depois.', 'A guerra se ganha no que você faz quando ninguém tá olhando.', '@gideao.sampaio'),
('04-15', 4, 15, 'neemias-barros', 'Neemias Barros', '71.612', 'Não desamparaste os teus amigos.', 'Neemias 9:17', 'Quem tu desamparou recentemente — e sabia que tava abandonando?', 'Neemias louvou Deus: não abandona. Tu abandona. Amigo na crise, você sumiu. Irmão no luto, você não apareceu. Filho no tombo, você virou ocupado. Ausência é abandono maquiado. Legendário faz presença. Torpedo. Recado. Visita curta. Não precisa de solução — precisa de presença. Bota o nome de três pessoas pra ligar hoje. Não planeja. Liga.', 'Ausência quando importa é abandono. Deus não faz isso contigo — não faz com eles.', '@neemias.barros'),
('04-16', 4, 16, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Meu coração está inquieto.', 'Jeremias 4:19', 'Essa tua inquietação crônica é Deus te chamando pra ação ou ansiedade por falta de rendição?', 'Jeremias declarou inquietação santa. Tu? Inquietude tua é ansiedade camuflada. Diferença: inquietação santa te move pra direção clara. Ansiedade te deixa parado ruminando. Olha pra dentro: o que tu sente impulsiona ação definida ou só roda em círculo? Se é ação, obedece. Se é rodada, entrega. Ansiedade tratada com oração e rendição dorme bem à noite.', 'Inquietação santa move. Ansiedade paralisa. Não confunde.', '@samuelqueiroga'),
('04-17', 4, 17, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Sê forte no Senhor.', 'Efésios 6:10', 'Onde você tá sendo forte na sua própria energia — e falhando?', 'Paulo disse: sê forte NO SENHOR, não em ti. Tu tenta ser forte no próprio tanque. Esvazia. Cai. Culpa situação. Força humana tem limite. Força no Senhor renova. Acorda hoje declarando: hoje eu sou forte no Senhor, não em mim. Muda a fonte e você muda o suprimento. Tenta. Um dia. Registra a diferença.', 'Quem se acha forte sozinho acaba mais fraco que todos.', '@benjamim.paiva'),
('04-18', 4, 18, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Ossos bem secos.', 'Ezequiel 37:2', 'Qual situação na tua vida você classifica como "passada dos remédios" — e Deus ainda espera palavra?', 'Deus destaca: ossos BEM secos. Não só secos — bem secos. Não havia como ser pior. Tua situação tá bem seca? Casamento sem conversa há 6 meses? Filho sem diálogo há ano? Saúde com laudo ruim? Negócio sem perspectiva? Deus especializa em bem seco. Profetiza em cima. Literal. Abre a boca e declara vida. Parece estranho. É a mecânica Dele.', 'Deus trabalha onde humano desiste.', '@ezequielferraz'),
('04-19', 4, 19, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Põe esta aliança entre nós.', '1 Samuel 20:42', 'Que aliança verbal falta ser traduzida em prática concreta contigo?', 'Jônatas selou aliança em palavras. Mas manteve em atos — arriscou vida várias vezes. Tua aliança (com amigo, com esposa, com Deus) tá só em palavra? Tem atos? Atos são: tempo, dinheiro, prioridade, renúncia. Se a aliança só vive em frase de parede, tá quebrada sem você saber. Olha cada uma tua. Cadê a prática? Onde faltar, começa hoje.', 'Aliança só existe no que tu sacrifica por ela.', '@jonataspellegrino'),
('04-20', 4, 20, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'E Calebe cala.', 'Números 13:30', 'Que sala de reclamação você precisa calar hoje?', 'Calebe não discute. Cala o povo. Tu entra em grupo derrotista e vira um deles. Fofoca do trabalho, crítica de igreja, lamento de família. Cala. Interrompe. Ou sai. Ambiente molda espírito. Você não precisa de mais informação ruim. Precisa de menos exposição a ruído de desespero. Legendário escolhe espaço — não aceita ambiente qualquer.', 'Ambiente forma caráter. Escolhe onde respira.', '@caleb.montenegro'),
('04-21', 4, 21, 'josue-caetano', 'Josué Caetano', '71.204', 'Quão boas são as tuas tendas.', 'Números 24:5', 'Que parte da tua casa Deus quer que você honre hoje que você tá negligenciando?', 'Balaão olhou Israel e exclamou: quão boas são tuas tendas. Tua casa tá boa? Não tua casa externa — tendência interna. Jantar com filho. Oração com esposa. Presença inteira. Benção antes de sair. Legendário cuida da tenda primeiro. Não adianta vencer muralha fora e ter deserto dentro. Hoje: uma ação concreta de cuidado com tua tenda. Feita antes de dormir.', 'Vitória em fora com tenda seca dentro é fracasso consagrado.', '@josue.caetano'),
('04-22', 4, 22, 'davi-valverde', 'Davi Valverde', '71.337', 'Ama a justiça.', 'Salmo 45:7', 'Tu ama a justiça ou só ama parecer justo?', 'Davi escreveu: o rei ama justiça. Amar justiça é escolher o direito mesmo quando custa. Você? Ama parecer justo. Defende justiça em teoria, aceita injustiça na prática quando te beneficia. Diz que é contra corrupção e paga propina pra evitar multa. Diz que é contra gossip e alimenta grupo. Escolhe. Justiça real custa. Vale.', 'Parecer justo é mais barato que ser. Por isso virou epidemia.', '@davi.valverde'),
('04-23', 4, 23, 'elias-dovale', 'Elias do Vale', '71.418', 'O Senhor passou.', '1 Reis 19:11', 'Deus passou recentemente por ti — e você tava olhando tua tela?', 'Elias ficou na caverna. Deus passou. Vento, tremor, fogo, sussurro. Elias estava atento. Tu não estaria. Scroll na mão. Notificação na cabeça. Deus passa e você perde. Desativa notificação. Sai 30 minutos do celular. Senta em silêncio. Os grandes momentos de Deus são quietos. Só quem tá acordado pra eles percebe.', 'Quem tá olhando a tela perde a passagem de Deus.', '@elias.dovale'),
('04-24', 4, 24, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'O Senhor é contigo.', 'Juízes 6:12', 'Quanto da tua identidade vem do que Deus fala sobre ti — e quanto do que o mundo reflete?', 'Anjo chamou Gideão de valente. Ele se via covarde. Identidade divina contradiz autoestima humana. Tu ouve tua própria voz mais que a voz do Pai. Ou pior — ouve a voz da rede, do crítico, do passado. Desliga. Reza. Pergunta: Pai, quem sou para Ti? Fica sentado até ouvir. A identidade que Deus declara é mais verdadeira que todas as outras. Vive dela.', 'Identidade vem de quem Deus diz que você é, não do que você sente.', '@gideao.sampaio'),
('04-25', 4, 25, 'neemias-barros', 'Neemias Barros', '71.612', 'Orai por nós.', '1 Tessalonicenses 5:25', 'Quantas pessoas tu carrega em oração diária — e quantas te carregam?', 'Paulo pediu: orai por nós. Reconheceu que precisava. Tu não pede oração. Acha fraqueza. Tu também não ora pelos outros com nome. Ora genérico "pelos meus". Hoje: lista três pessoas que precisam de ti. Ora nome por nome. E pede pra três pessoas orarem por ti. Quebra a cultura de self-made. Cristão não é solo.', 'Quem não ora por ninguém, vira ninguém.', '@neemias.barros'),
('04-26', 4, 26, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'O Senhor é contigo.', 'Juízes 6:12', 'Tu confia que Deus é contigo agora — na briga específica que tá encarando?', 'Anjo chamou Gideão de valente com o Senhor presente. A presença mudou tudo. Tu briga sozinho — cansa, mas Ele tá contigo. Identifica a briga específica de agora: declara em voz alta que Deus é contigo nela. Essa mudança de consciência muda ação.', 'Presença declarada é luta transformada.', '@caleb.montenegro'),
('04-27', 4, 27, 'neemias-barros', 'Neemias Barros', '71.612', 'Fiz-lhes saber.', 'Neemias 2:18', 'Quem ainda não sabe da tua visão — e precisa saber pra te apoiar?', 'Neemias contou sua visão aos líderes. Não guardou. Compartilhou estrategicamente. Tu guarda visão no peito achando que protege. Erra. Quem precisa cooperar tem que saber. Escolhe 3-5 pessoas-chave que devem conhecer visão clara tua. Agenda conversa.', 'Visão secreta morre. Visão compartilhada vive em rede.', '@neemias.barros'),
('04-28', 4, 28, 'davi-valverde', 'Davi Valverde', '71.337', 'A minha alma espera em Deus.', 'Salmo 62:1', 'Tua alma espera em Deus ou em resposta do humano?', 'Davi esperava só em Deus. Tu espera mensagem do cliente, volta da ex, resposta do chefe, aprovação da banca. Alma amarrada em humano rasga. Amarrada em Deus, descansa. Transfere espera. Humano faz o que faz — Deus quem te sustenta.', 'Esperar em humano é martelada ao coração.', '@davi.valverde'),
('04-29', 4, 29, 'elias-dovale', 'Elias do Vale', '71.418', 'Saiu da caverna.', '1 Reis 19:13', 'Qual caverna de desânimo tu tá escondido — e Deus tá chamando pra sair?', 'Elias se escondeu. Deus perguntou: o que fazes aqui? Convite pra sair. Tu também tem caverna — vício, depressão, apatia, isolamento. Deus pergunta o que tu faz aí. Resposta honesta, saída lenta. Cada passo pra fora é um sim. Ora: sinto teu chamado? Onde? Pra fazer o quê?', 'Caverna dá sensação de segurança. Só Deus é segurança real.', '@elias.dovale'),
('04-30', 4, 30, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'A tua vida é escondida.', 'Colossenses 3:3', 'Tua identidade tá em Cristo — ou em algum rótulo que some com a profissão?', 'Paulo: vida escondida com Cristo. Se tirar teu cargo, teu papel, tua marca — sobra o quê? Se sobra ''nada'', identidade tava errada. Identidade em Cristo resiste à mudança profissional, à idade, à fama. Planta identidade ali. Tudo mais vem como fruto, não como raiz.', 'Identidade em casca rui no vento. Em Cristo, não.', '@benjamim.paiva'),
('05-01', 5, 1, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'A cidade, apesar de tudo, é tua.', 'Josué 17:18', 'Qual terra Deus já te entregou que você tá tratando como ''ainda quase''?', 'Efraim reclamou que a terra era difícil — tinha floresta, tinha cananeu com carro de ferro. Josué respondeu: é tua. Corta a floresta. Expulsa o cananeu. Tu herdou vocação, família, negócio, casa — e fica reclamando dos cananeus. Deus já deu. Mas dar não é receber passivo. É tomar trabalhando. Reclamação é desculpa elegante.', 'Deus dá a terra. A conquista é tua obrigação.', '@caleb.montenegro'),
('05-02', 5, 2, 'josue-caetano', 'Josué Caetano', '71.204', 'Sobe e possui.', 'Deuteronômio 9:1', 'O que você tá olhando de baixo há anos — esperando autorização extra pra subir?', 'Sobe E possui. Dois verbos imediatos. Tu sobe e não possui. Possui e não sobe. Ou nem sobe nem possui. Anda orbitando o que Deus entregou. Ora por nova terra esquecendo de tomar a que tem. Posse exige passos físicos: marcar reunião, mandar mensagem, abrir processo, atravessar conversa evitada. Hoje, sobe um degrau. E possui aquele degrau.', 'Orar sem subir é fé fake.', '@josue.caetano'),
('05-03', 5, 3, 'davi-valverde', 'Davi Valverde', '71.337', 'Ensina-me a fazer tua vontade.', 'Salmo 143:10', 'Você pede direção ou conforto disfarçado de direção?', 'Davi pediu: ensina-me. Quer aprender. Quer ser mudado no processo. Tu pede direção só pra ratificar o que já decidiu. Se Deus apontar o contrário, você acha que ouviu errado. Isso é auto-engano. Oração madura: ''Pai, Tua vontade, mesmo que doa''. Experimenta. Escuta sem censura. Aceita correção. Essa é a escola de quem cresce de verdade — não a prateleira de mentoria cristã premium.', 'Quem só pede confirmação não tá orando. Tá pedindo endorsement.', '@davi.valverde'),
('05-04', 5, 4, 'elias-dovale', 'Elias do Vale', '71.418', 'O fogo do Senhor caiu.', '1 Reis 18:38', 'Quantas vezes teu altar foi reformado porque tu parou de acender o fogo?', 'Elias reconstruiu altar com 12 pedras, encharcou de água, e o fogo caiu. Tu? Constroi altar toda semana. Segunda: vou orar. Sexta: nada aconteceu. Para de reformar. Mantém. Um altar diário, mesmo pequeno, mesmo molhado. Fogo não cai em altar de quem desiste no terceiro dia. Cai em altar consistente. Constância é preparação pro sobrenatural.', 'Fogo cai em altar que permanece. Não em reforma constante.', '@elias.dovale'),
('05-05', 5, 5, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Faze também comigo um sinal.', 'Juízes 6:17', 'Quando Deus confirmou claramente e você ainda assim pediu mais um sinal?', 'Gideão pediu sinal duas, três, quatro vezes. Lã. Orvalho. Chão seco. Deus respondeu. Tem hora que sinal é pra ter certeza; tem hora que é pra fugir da obediência. Qual é o teu caso? Se Deus já falou claro, mais um sinal é ruído pra adiar. Se ainda não foi claro, pede — mas com humildade, não com acusação.', 'Pedir sinal demais pode ser sabotagem vestida de fé.', '@gideao.sampaio'),
('05-06', 5, 6, 'neemias-barros', 'Neemias Barros', '71.612', 'Trabalhavam a obra.', 'Neemias 4:21', 'Você trabalha a obra — ou só fala dela em mesa de restaurante?', 'Povo de Neemias trabalhava do amanhecer ao aparecer estrelas. Sem TED Talk sobre reconstrução. Mão na massa. Tu gasta mais tempo explicando teu projeto do que executando. Posta mais sobre propósito do que pratica. A diferença entre quem constrói muro e quem só fala de muro é física: calo na mão. Olha tua mão hoje. Tem calo do quê?', 'Calo denuncia o real. Fala denuncia o intencionado.', '@neemias.barros'),
('05-07', 5, 7, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Longe esteja de mim.', '1 Samuel 12:23', 'Que irmão tá precisando da tua oração — e você lembrou por 3 segundos e não orou?', 'Samuel disse: longe de mim pecar contra vocês deixando de orar. Deixar de interceder é PECADO, não é falta de tempo. Você passa 2 horas rolando feed. Não tem 5 minutos pra orar pelo teu irmão? Intercessão é função sacerdotal de quem é em Cristo. Negligencia e tá pecando. Hoje: três nomes. 5 minutos. Por cada. Sem culpa, com disciplina.', 'Não orar pelo próximo não é falta de tempo. É pecado.', '@samuelqueiroga'),
('05-08', 5, 8, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Nada vos poderá empecer.', 'Lucas 10:19', 'Você crê que tem autoridade — ou age como se estivesse sempre pedindo permissão?', 'Jesus disse: dei autoridade. Não prometeu. Deu. Já tá dado. Tu anda pedindo permissão, sondando atmosfera, temendo ofender. Autoridade em Cristo não é arrogância — é posição. Quando Paulo expulsou demônio, não pediu opinião da assembleia. Ordenou. Onde na tua vida falta uso de autoridade dada? Vício, ansiedade, medo, opinião alheia? Usa. Já é teu.', 'Cristão sem consciência de autoridade vive pedindo licença pra existir.', '@benjamim.paiva'),
('05-09', 5, 9, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Estarei contigo.', 'Juízes 6:16', 'Que presença de Deus contigo você tá tratando como metáfora fofa?', 'Deus disse pra Gideão: ''estarei contigo''. Não é figura. É fato. Ezequiel viu a glória se mover literalmente. Tu? Canta ''Deus tá comigo'' e age como quem tá sozinho. Ou canta e tudo bem — mas na hora da dificuldade, entra em desespero. A diferença é: tu crê mesmo ou só canta? Testa teu coração. Se crê, a próxima crise deixa de ser crise — é oportunidade de testemunhar presença real.', 'Presença de Deus é fato. Quem acha que é poesia anda sozinho.', '@ezequielferraz'),
('05-10', 5, 10, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Deu Jônatas a sua armadura.', '1 Samuel 18:4', 'O que você tá acumulando que Deus tá querendo você soltar na mão de outro?', 'Jônatas não só prometeu. Entregou. Armadura, espada, cinto, arco. Literal. Tu diz que ajudaria, que daria, que ofereceria. Mas na prática, segura. Dinheiro, oportunidade, conhecimento, tempo, contato. Deus colocou alguém na tua vida pra receber — e tu segura por medo de escassez. Libera. Passa adiante. Deus é reservatório, não teu saldo bancário.', 'Deus é suprimento. Tua mão fechada é sintoma de pouca fé no suprimento.', '@jonataspellegrino'),
('05-11', 5, 11, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Escolhido para ti.', '1 Crônicas 28:6', 'Que papel específico Deus te escolheu — que você tá ignorando por querer outro?', 'Davi contou que Deus escolheu Salomão pra construir o templo. Não Davi. Tinha sonho, tinha capacidade, tinha desejo. Deus escolheu outro. Tu? Quer a missão do irmão. Invejas ministério do outro. Cobiças carreira alheia. Cada legendário tem chamado específico. Aceita o teu. Cada desvio pra disputar trilha alheia é anos perdidos. Foca no que é teu.', 'Inveja do ministério alheio é desobediência ao chamado próprio.', '@caleb.montenegro'),
('05-12', 5, 12, 'josue-caetano', 'Josué Caetano', '71.204', 'Ficareis firmes no vosso posto.', 'Êxodo 14:13', 'Qual chamado a ficar parado Deus tá dando — que teu ativismo tá ignorando?', 'Moisés falou pro povo: ficai parados. Não é sempre sair fazendo. Às vezes é parar. Você confunde atividade com obediência. Faz mil coisas e esquece de escutar. Legendário sabe brigar E sabe parar. Hoje, 30 minutos de pausa deliberada. Sem celular. Sem agenda. Só aguardando. A vitória às vezes é esperar Deus agir.', 'Ativismo religioso é a nova fuga da presença.', '@josue.caetano'),
('05-13', 5, 13, 'davi-valverde', 'Davi Valverde', '71.337', 'Alegra a tua herança.', 'Deuteronômio 33:9', 'Você tá sendo presença alegre na vida dos teus — ou carga que todos aguentam?', 'Levi foi abençoado com alegria na herança. Tu pega teu trabalho, tua casa, tua igreja, e chega seco. Carrega peso. Reclama. Difunde inércia. Culpa ninguém dorme bem contigo. Pergunta: tua família tá melhor ou pior com tua chegada em casa? Tua equipe respira aliviada quando tu sai? Legendário não deixa herança pesada. Deixa alegria contagiante, combustível. Ajusta o tom. Hoje.', 'Cristão triste contamina mais que alegre ignorante.', '@davi.valverde'),
('05-14', 5, 14, 'elias-dovale', 'Elias do Vale', '71.418', 'O Senhor será luz perpétua.', 'Isaías 60:19', 'Sua autoestima depende mais de elogio humano ou de identidade divina?', 'Isaías prometeu: o Senhor luz perpétua. Não o sol. Não as pessoas. Não likes. Não prêmio. Tua autoestima, hoje, depende do quê? Se a pessoa X não falar bem de ti, desaba? Se o post não bombar, cai? Dependência de aprovação é escravidão camuflada de ambição. Volta a beber da fonte perpétua. Ali a valia é fixa. Aqui no mundo ela oscila todo dia.', 'Dependência de aplauso é escravidão com roupa cara.', '@elias.dovale'),
('05-15', 5, 15, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Deus deu na vossa mão.', 'Juízes 7:15', 'Que vitória tu tá dizendo ''eu consegui'' — quando foi Deus entregando?', 'Gideão ouviu do inimigo: Deus entregou Midiã. Ele entendeu. Adorou antes de lutar. Tu entregaria? Depois da vitória você sempre dá o crédito certo? Ou vira meme ''deu certo porque eu fui insistente''? Atribuição errada de glória é pecado. Hoje: três vitórias recentes. Reconhece Deus em cada uma em voz alta (ou por escrito). Memória treinada impede soberba futura.', 'Vitória sem gratidão ao Dono vira dívida espiritual.', '@gideao.sampaio'),
('05-16', 5, 16, 'neemias-barros', 'Neemias Barros', '71.612', 'O que será de nós?', 'Números 14:3', 'Qual medo do futuro tá te fazendo querer voltar pro Egito?', 'Povo olhou pra frente, viu gigante, preferiu o Egito — lugar da escravidão conhecida. Tu? Casamento pegou fogo — pensa em voltar pra solteirice. Empresa passa aperto — pensa em voltar pra CLT. Chamado dá trabalho — pensa em sumir. Egito conhecido é mais confortável que Canaã por conquistar. Mas não é chamado. Não volta. Atravessa. Deus separou água pra trás.', 'Nostalgia de Egito é traição do chamado.', '@neemias.barros'),
('05-17', 5, 17, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Observaram sinais.', 'Jeremias 10:2', 'Você lê o que Deus já escreveu — ou anda atrás de mística exótica?', 'Jeremias alertou: povo observando sinais dos pagãos. Hoje é igual. Mapa astral cristianizado. Signo espiritual. Jornada dos chakras com versículo. Tu? Procura palavra profética a cada decisão? Vai em mil congresso pra ouvir alguém te falar o que Deus já disse na Bíblia? Letreiro místico é droga. Lê a Palavra. Ali tá. Direção vem por Palavra lida, oração feita, conselho sábio. Não por emissora milagreira.', 'A Bíblia é suficiente. Quem busca mística além dela desconfia da suficiência.', '@samuelqueiroga'),
('05-18', 5, 18, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Quem é Saul?', '1 Samuel 10:11', 'Em que momento você ficou ridículo fazendo o que era do Reino — e recuou?', 'Saul se escondeu entre bagagens no dia da coroação. Depois profetizou com outros profetas. Gente riu: Saul também entre profetas?! Tu sofre ''vergonha santa''. Evita orar em público. Evita pregar no trabalho. Evita admitir jejum. Dá pra esconder por um tempo. Mas Reino não comporta escondimento permanente. Sai da bagagem. Custa ser ridículo. Mas é pior ser covarde pro Reino.', 'Vergonha de Cristo vira vergonha de si no juízo.', '@benjamim.paiva'),
('05-19', 5, 19, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'A profecia soou.', 'Ezequiel 37:7', 'Qual palavra dita por ti em obediência tu acha que não surtiu — mas não profetizou de novo?', 'Ezequiel profetizou. Ouviu o barulho. Ossos se juntaram. Não na primeira palavra; no processo. Tu disse uma vez e achou que não funcionou. Falou com filho uma vez. Corrigiu esposa uma vez. Alertou sócio uma vez. Insiste. Obediência é profecia sustentada. Repete. Sem agressão, com convicção. Primeira palavra é sementeira. Colheita vem de muitas.', 'Falou uma vez e parou? Então não falou de verdade.', '@ezequielferraz'),
('05-20', 5, 20, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Dar-te-ei o seu amor.', 'Salmo 91:14', 'Você vive pra ser amado ou pra amar?', 'Salmo diz: Deus dará amor a quem O ama. Foco é errado hoje. Todo mundo quer ser amado. Legendário ama primeiro. Ama esposa antes de esperar carinho. Ama filho antes de ver gratidão. Ama irmão antes de retribuição. Ama Deus antes de benção. Amor que inicia não depende de reciprocidade. E estranho: é nesse tipo de amor que Deus despeja o Dele. Volta-vida.', 'Amor que espera retorno é comércio. Amor que inicia é legado.', '@jonataspellegrino'),
('05-21', 5, 21, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Farei conforme a palavra.', 'Números 14:20', 'Qual palavra de Deus você já ouviu e seguiu — e qual ainda acha negociável?', 'Deus disse a Moisés: farei conforme a palavra. Fiel à própria Palavra. Tu separa. Uma parte da Palavra tu obedece. Outra acha exagero, cultural, legalista, desatualizado. Bíblia toda é Bíblia. Ou é tudo ou nada. Quando tu começa a escolher versículo como cardápio, terminou a submissão. Volta ao começo. Obedece o desconfortável primeiro. O confortável já era fácil.', 'Obediência seletiva é rebeldia elegante.', '@caleb.montenegro'),
('05-22', 5, 22, 'josue-caetano', 'Josué Caetano', '71.204', 'Atravessaste a seca o Jordão.', 'Josué 4:22', 'Que travessia seca Deus te deu que virou história sem memorial?', 'Depois de atravessar o Jordão, Josué mandou erguer 12 pedras. Marco físico. Pra que o povo lembrasse. Tu atravessa e não marca. Salva emprego e não agradece. Cura e não registra. Sai do vício e não comemora. Sem memorial, a próxima geração não sabe o que Deus fez. Filho teu não vê fé tua, vê rotina tua. Constroi memorial: oração em família, testemunho, foto marcada. Memória é combustível.', 'Sem memorial, a próxima geração esquece. E tu também.', '@josue.caetano'),
('05-23', 5, 23, 'davi-valverde', 'Davi Valverde', '71.337', 'Como ama o cervo às correntes das águas.', 'Salmo 42:1', 'Quando foi a última vez que você teve SEDE de Deus — não rotina, sede?', 'Davi descreveu sede. Não rotina, não devocional das 6, não grupo de célula. Sede. Fera correndo pra água. Cristão moderno não tem sede — tem agenda. Perdeu a urgência. Deus deixou de ser vital, virou rotina opcional. Pede ao Pai sede. Pede desejo. ''Pai, deseja-Te em mim, que eu não sinto''. Ele responde. Sede é sinal de vida. Ausência de sede é sinal de agonia espiritual travestida de constância.', 'Quem não tem sede é porque já morreu ou já se contaminou com cisterna.', '@davi.valverde'),
('05-24', 5, 24, 'elias-dovale', 'Elias do Vale', '71.418', 'Clama em alta voz.', '1 Reis 18:27', 'Teu Deus é grande — ou você parou de clamar como se Ele fosse pequeno?', 'Elias, na disputa com os profetas de Baal, zombou: clama alto, seu deus pode estar viajando. Quase engraçado. Elias provocava. Tu provoca teus ídolos? Ou trata ''Deus'' com mais cuidado que deveria? Deus real não se ofende com clamor alto. Convoca. Pede. Aposta fé. Clama com fervor. Deus não desconfia; se alegra com quem não deixa dúvida na intensidade.', 'Clamor baixinho às vezes é tão incrédulo quanto silêncio.', '@elias.dovale'),
('05-25', 5, 25, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Não temais.', 'Juízes 6:23', 'Qual medo tá escolhendo teu comportamento essa semana?', 'Deus tocou Gideão: não temas. Tu tem medo com rosto. Medo de perder cliente, e suaviza preço (mentira comercial). Medo de esposa reagir, e omite verdade (covardia doméstica). Medo de crítica, e posta só o que agrada (vaidade disfarçada). Nomeia o medo específico. Enfrenta. Medo não desaparece por ignorar — só por confrontar. Legendário não é sem medo. É com medo e agindo assim mesmo.', 'Quem ignora o próprio medo termina escravizado por ele.', '@gideao.sampaio'),
('05-26', 5, 26, 'neemias-barros', 'Neemias Barros', '71.612', 'Toca o rebate.', 'Neemias 4:20', 'Que sinal de alarme você tá ouvindo na tua casa — e silenciando por cansaço?', 'Neemias acertou: alguém toca a trombeta, todos correm junto. Tua casa tem alarme soando. Filho retraído. Esposa irritada. Corpo dolorido. Espírito árido. Você silencia: ''depois eu vejo''. Cada alarme ignorado cobra juros. Hoje: pára. Atende um alarme. Só um. O que for mais urgente. Uma conversa, uma consulta, uma oração. Sem atender, o muro cai enquanto você trabalha em outra ponta.', 'Alarme silenciado é trégua falsa. O problema só cresceu.', '@neemias.barros'),
('05-27', 5, 27, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Não vim por meu próprio comer.', 'Jonas 1:12', 'Pra quem tu tá sacrificando e não avisou — gerando ressentimento em silêncio?', 'Jonas confessou no navio: a culpa é minha, joga-me fora. Tu carrega culpa em silêncio. Ou aceita carga pesada e reclama escondido pra família. Pior ainda: ressentimento marinando enquanto sorri. Legendário fala antes. ''Tô cansado, preciso pausa''. ''Não posso, vou dizer não''. Sacrifício em silêncio não santifica — envenena. Comunica custo real. Ou carrega consciente — sem ressentir.', 'Sacrifício escondido envenena. Declara ou não faz.', '@samuelqueiroga'),
('05-28', 5, 28, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Vós é que perseguis.', 'Provérbios 28:1', 'O perverso foge sem perseguidor. Que sombras você foge sozinho?', 'Salomão descreve: perverso foge mesmo sem ninguém atrás. Culpa gera paranoia. Tu tem ação secreta? Vive olhando por cima do ombro? Anda defensivo sem motivo? Isso pode ser sintoma. Não ignora. Quieto com Deus. Confessa. Limpa. Perdão de Deus traz passo firme. Sem ele, você vai fugir de fantasma próprio a vida inteira — e chamar isso de ansiedade generalizada.', 'Quem tem paz dorme quieto. Quem corre é preso do próprio passado.', '@benjamim.paiva'),
('05-29', 5, 29, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Os vigias não ficarão mudos.', 'Ezequiel 33:7', 'Tu é vigia de alguém — e tá mudo há quanto tempo?', 'Deus fez Ezequiel vigia e mandou falar. Se o vigia cala, sangue do povo sobre ele. Tu é vigia de pelo menos uma pessoa — amigo, irmão, parente. Tá mudo. Covardia. Legendário levanta voz. Fala a verdade com amor. Se a pessoa rejeitar, a responsabilidade saiu das tuas mãos. Mas se calar, o sangue é teu. Bíblia é dura. Hoje: vigia chama a pessoa. Diz.', 'Vigia mudo é cúmplice da queda alheia.', '@ezequielferraz');
INSERT INTO public.provocacoes (dia_ano, mes, dia, autor_slug, autor_dia, autor_numero, citacao, autor_citacao, pergunta, texto, aspas_autor, instagram) VALUES
('05-30', 5, 30, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Irei depois de ti para onde fores.', 'Rute 1:16', 'Quem tá caminhando contigo em nível ''Rute-Noemi'' — ou tu só tem conhecidos?', 'Rute disse: onde fores, vou. Onde pousares, pouso. Teu povo, meu povo. Teu Deus, meu Deus. Nível profundíssimo. Tu tem alguém assim? Na sua vida existe gente que te seguiria pro desconhecido? Ou só tem gente que te segue enquanto dá certo? Amizade Rute-Noemi se constrói em provação. Tu tá criando uma? Ou tá pulando todo desconforto por medo de parecer carente?', 'Amizade que some na crise é conhecido. Amizade que fica é pacto.', '@jonataspellegrino'),
('05-31', 5, 31, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Não sabemos o que será o dia de amanhã.', 'Tiago 4:14', 'O que você tá tratando como certo — que Deus te lembra que pode virar em minutos?', 'Tiago zera: não sabemos do amanhã. Nuvem que some. Tu planeja 10 anos com ilusão de controle. Bom planejar. Ruim controlar. ''Se o Senhor quiser''. Frase esquecida. Tua saúde, tua grana, teu casamento, teu negócio — pode mudar rápido. Não é pra paralisar. É pra humilhar. Entre plano e fatalidade, tem obediência diária. Foco. Plano, mas sem prepotência.', 'Plano sem ''se Deus quiser'' é prepotência disfarçada.', '@caleb.montenegro'),
('06-01', 6, 1, 'josue-caetano', 'Josué Caetano', '71.204', 'Feriste toda a terra com fio de espada.', 'Josué 10:40', 'Onde tu tá parando antes do fim — deixando bolsão que depois volta a te morder?', 'Josué varreu a terra. Completo. Ferramenta: espada, até o fim. Tu? Começa processo de mudança, para na metade. Perdoa com reserva. Corta hábito 70%. Estabelece rotina por 2 semanas. Deus odeia meia obra. Amaleque sobrou em Saul — voltou na história pra derrotar. Tu deixa Amaleque pequeno no teu. Volta. Termina. Obra feita 100% é descanso de verdade.', 'Meia obra é porta pro problema voltar maior.', '@josue.caetano'),
('06-02', 6, 2, 'davi-valverde', 'Davi Valverde', '71.337', 'Os que vão para ela, todos morrem.', '2 Samuel 14:14', 'Qual verdade óbvia você tá fingindo ignorar?', 'A mulher de Tecoa disse a Davi: somos como água derramada, morremos. Verdade óbvia. Tu ignora óbvio: vai morrer, vai envelhecer, vai prestar contas. Age como eterno. Adia confissão, reconciliação, sonho, ministério. Saúde mais forte só fica mais fraca. Oportunidade só fica mais cara. Encara o óbvio: teu tempo é limitado. Isso não paralisa — mobiliza. Age hoje no que é permanente, não no que é ornamento.', 'Óbvio ignorado cobra juro com tempo.', '@davi.valverde'),
('06-03', 6, 3, 'elias-dovale', 'Elias do Vale', '71.418', 'Responde, Senhor.', '1 Reis 18:37', 'Você ora pra parecer espiritual — ou pra receber resposta?', 'Elias orou direto: responde pra o povo saber que és Deus. Objetivo claro. Tu ora com floreio. Gasta frase. Repete ''Senhor'' 15 vezes. Evita chegar ao pedido. Pergunta: pra que tu ora? Seja sincero. Oração bonita vazia é retórica. Oração feia objetiva é fé. Dá uma descostura nas tuas orações. Diz o que quer. Pede. Confia. Se Deus responde, tu cresce. Se não responde, tu aprende. Ornamento não muda nada.', 'Oração enfeitada sem pedido objetivo é narcisismo religioso.', '@elias.dovale'),
('06-04', 6, 4, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Eu sou o menor.', 'Juízes 6:15', 'Qual ''eu sou o menor'' tu tá repetindo como mantra — pra continuar pequeno?', 'Gideão disse: meu clã é o menor, eu sou o menor do clã. Diagnóstico honesto. Mas Deus superescreveu. Tu fica no diagnóstico. ''Eu sou tímido''. ''Eu não tenho dom''. ''Eu não tenho capital''. ''Eu não tenho estudo''. Tudo pode ser verdade. E é irrelevante. Deus transforma os ''menores''. Aceita o fato. Rejeita a prisão. Ser menor hoje não é sentença vitalícia — é ponto de partida.', 'Autoimagem de ''menor'' vira cadeia se repetida.', '@gideao.sampaio'),
('06-05', 6, 5, 'neemias-barros', 'Neemias Barros', '71.612', 'A obra é grande.', 'Neemias 4:19', 'Que projeto tu chamou de ''pequeno'' só pra não assumir responsabilidade?', 'Neemias reconheceu: obra grande, muros extensos, distantes. Realismo. Tu minimiza teu projeto. ''Só um canal no YouTube''. ''Apenas um livro''. ''Uma igreja de garagem''. Minimização é defesa do ego contra fracasso. Adota a dimensão real. Grande coisa exige grande dependência de Deus. Admite o tamanho. Com isso, humilha-se. Com humildade, Deus age. Com minimização, fica tudo pequeno mesmo.', 'Quem minimiza o que começou, inibe o que Deus quer expandir.', '@neemias.barros'),
('06-06', 6, 6, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Tua palavra é lâmpada.', 'Salmo 119:105', 'Quanta Palavra entrou em você nos últimos 7 dias?', 'Salmista: lâmpada aos pés. Luz ao caminho. Sem lâmpada, tropeça. Escuridão. Tu leu Palavra essa semana? Quanto? Uma página? Zero? Tá reclamando de direção, de confusão, de ansiedade — com a lâmpada apagada. Acende. 10 minutos por dia. Não é mérito, é sobrevivência. Quem não lê Palavra caminha no escuro e depois culpa Deus por tropeçar.', 'Lâmpada apagada não tem direito de reclamar da escuridão.', '@samuelqueiroga'),
('06-07', 6, 7, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'A porta estreita.', 'Mateus 7:13', 'Qual porta larga você prefere porque dá pra passar com bagagem do ego intacta?', 'Jesus avisou: larga é a porta da destruição. Muitos entram. Estreita, poucos. Tu prefere larga. Caminho fácil. Igreja fácil. Casamento fácil. Profissão fácil. Largo compensa por algum tempo. Depois entrega. Estreita é estreita porque exige deixar bagagem. Orgulho. Controle. Vaidade. Hábito. Só passa quem desce da bagagem. Qual bagagem tua hoje te impede de passar?', 'Bagagem que cabe na porta larga te impede na estreita.', '@benjamim.paiva'),
('06-08', 6, 8, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Faz de mim um sinal.', 'Ezequiel 12:6', 'Se alguém filmasse tua vida por uma semana, que mensagem ficaria clara?', 'Deus fez Ezequiel sinal vivo. Tu também é. Tua vida pregando. Essa semana: teus horários, tuas escolhas, tuas palavras, tuas postagens, tua reação à contrariedade. Coerente com Cristo? Ou pregando outra coisa? Testamento de vida pesa mais que discurso. Cristão que prega bem e vive mal é ateu com marketing. Tu? Vive melhor do que fala ou ao contrário?', 'Sua vida já é sinal. A pergunta é se é o que você quer.', '@ezequielferraz'),
('06-09', 6, 9, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Não te deixará nem te desamparará.', 'Hebreus 13:5', 'Em quem você confia de verdade — e a quem Deus tá pedindo que tu confies mais?', 'Hebreus promete: Deus não desampara. Tu confia? Ou confia mais no plano B, na rede de contatos, no saldo? Contas de poupança, apólices, backup de backup. Tudo é bom — desde que Deus seja primeiro. Se o plano B cair, tu desaba? Então não é plano B, é fundação secreta. Move Deus pro lugar central. Plano B fica plano B. Falha. Inclusive humanos que amo. Deus não.', 'Quem confia em plano B ressente o dia em que ele falha.', '@jonataspellegrino'),
('06-10', 6, 10, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Inteiro com o Senhor.', 'Números 14:24', 'Qual ''inteiro'' de você Deus tá esperando há anos?', 'Caleb foi chamado de ''inteiro'' com o Senhor. Espírito diferente. Sem ressalva. Deus procura gente assim — raro. Tu é inteiro? Ou dá 80%, 70%, 50%? No casamento, na paternidade, na fé, na vocação. Inteireza é não separar o que for Dele do que for teu. Hoje: uma área de tua vida em que tu divide. Entrega 100%. Caleb por inteireza herdou Hebron. Qual tua herança trancada pela metade?', 'Inteireza é o caráter raro que Deus recompensa.', '@caleb.montenegro'),
('06-11', 6, 11, 'josue-caetano', 'Josué Caetano', '71.204', 'Sirva a quem bem vos parecer.', 'Josué 24:15', 'Você acha que tá servindo a Deus — ou tá servindo tua agenda espiritual?', 'Josué cutucou: serve a quem bem vos parecer. Provocação. Tu diz servir a Deus. Mas no fundo serve à tua agenda. Oração quando sobra tempo. Generosidade quando não aperta. Compromisso se couber. Isso é servir a si. Deus quer servo primeiro. Ajusta. Primeiro a oração. Primeiro o dízimo. Primeiro o jejum. Primeiro o Reino. Depois o resto. Ordem invertida é idolatria disfarçada de prioridade.', 'Primeiro é literal. Se vem depois, é segundo.', '@josue.caetano'),
('06-12', 6, 12, 'davi-valverde', 'Davi Valverde', '71.337', 'De todo teu coração.', 'Deuteronômio 6:5', 'Qual parte do teu coração tu trancou fora do culto?', 'Shemá: amarás de todo teu coração. TODO. Tu trancou parte. Ferida antiga do pai, cola em religião mas não em adoração. Vício escondido, bloqueia intimidade. Ressentimento contra pessoa específica, trava a tua oração. ''Todo'' é requisito. Não moderação. Deixar parte de fora é relacionamento pela metade. Destranca a porta. Entrega a parte amputada. Deus cura — só precisa acesso.', 'Coração trancado em parte é coração não entregue.', '@davi.valverde'),
('06-13', 6, 13, 'elias-dovale', 'Elias do Vale', '71.418', 'Os céus são como ferro.', 'Deuteronômio 28:23', 'Céu de ferro pra ti agora — é castigo ou silêncio pedagógico?', 'Deuteronômio avisa: desobediência traz céu de ferro. Mas nem todo silêncio é castigo. Às vezes Deus ensina através do silêncio. Dois motivos. Examina: tem pecado específico não confessado? Então é correção. Confessa. Se não tem e o céu tá ferro, é escola. Persiste. Ora. Silêncio não é ausência — é forja. Muitos grandes do Reino passaram anos de silêncio antes da palavra que mudou tudo.', 'Silêncio de Deus é pedagogia, não ausência.', '@elias.dovale'),
('06-14', 6, 14, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Alvedrio da multidão.', 'Êxodo 23:2', 'Você tá seguindo a maioria — ou a convicção?', 'Êxodo manda: não siga multidão pra fazer mal. Maioria vale pouco diante de Deus. Tua decisão de hoje foi convicção ou conveniência social? ''Todo mundo tá fazendo''. ''Ninguém liga mais''. ''É normal''. Cuidado — o normal da sua geração é frequentemente abominação. Coragem de divergir. Maioria dos 10 espias era negativa. Caleb e Josué foram minoria. Só os dois entraram.', 'Maioria errada é maioria mesmo assim.', '@gideao.sampaio'),
('06-15', 6, 15, 'neemias-barros', 'Neemias Barros', '71.612', 'Restauram o que se tinha caído.', 'Neemias 2:5', 'O que tá caído na tua vida esperando reconstrução que você não começou?', 'Neemias pediu ao rei: vou restaurar. Não pediu coisa nova — restaurar o que tinha caído. Casamento caído, amizade caída, corpo caído, relação com pai caída. Você evita restaurar porque é mais fácil começar novo. Novo casamento, novo emprego, nova igreja. Deus trabalha muito em restauração. Valoriza mais do que ruptura. Escolhe UMA coisa caída pra começar a restaurar esta semana. Pedra um.', 'Restauração é glória maior que começo novo.', '@neemias.barros'),
('06-16', 6, 16, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Falou Samuel ao povo.', '1 Samuel 12:1', 'Qual conversa difícil tá esperando teu pai/líder falar — e já virou ressentimento?', 'Samuel reuniu o povo: falou. Não guardou. Não terceirizou. Falou. Tu é pai, líder, marido, chefe. Tem conversa engolida há meses. Achando que passa. Não passa — vira ressentimento teu e deles. Chama. Marca. Fala. Mesmo que mal, fala. Imperfeita comunicação direta é superior a silenciosa perfeita. Todo dia não falar é voto pra o problema crescer.', 'Conversa engolida é veneno que vaza pelos poros.', '@samuelqueiroga'),
('06-17', 6, 17, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Padecemos dor.', 'Salmo 90:10', 'Quanta dor você tá mascarando de ''tô bem'' por causa de imagem?', 'Moisés escreveu: anos passam, e trabalho e pesar. Dor é parte. Nega. Tu posta ''tudo bem'' no story. Na mesa com esposa, ''tudo bem''. Na célula, ''vou bem''. Mentira caseira. Vulnerabilidade com Deus e com dois ou três íntimos. Isolamento emocional mata. Confessa dor. Não pra lamentar crônico — pra sair da prisão de imagem. Legendário não precisa performar. Pode pesar. E ser amado assim.', 'Imagem forte com alma podre é ruína arrumada.', '@benjamim.paiva'),
('06-18', 6, 18, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'A glória do Senhor.', 'Ezequiel 43:2', 'Qual ''glória'' você construiu pra si mesmo — que Deus tá querendo substituir pela Dele?', 'Ezequiel viu glória de Deus encher o templo. Gloria real. Tu construiu outra. Seu legado. Sua marca. Seu nome. Tua reputação. Boa busca? Sim. Ocupou lugar errado? Perigoso. Glória tua é sombra perto de Dele. Entrega. Deus devolve glória real — com eternidade. Enquanto tu segura, Deus espera. Nenhum grande do Reino ficou grande por buscar grandeza própria.', 'Glória própria sempre vira prisão.', '@ezequielferraz'),
('06-19', 6, 19, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Amem-se uns aos outros.', 'João 13:34', 'Na tua casa, é o amor que mais pesa — ou a tarefa?', 'Jesus: novo mandamento, amem uns aos outros. Casa cristã moderna é tarefa ambulante. Reunião, escola, trabalho, serviço, igreja. Amor sumiu. Viraram equipe. Logística. Gestão. Sem amor visível. Tua família lembra como você ama — ou como você cobra? Ajusta. Hoje: um gesto não-funcional. Olhar. Abraço longo. Palavra de valorização. Tarefa pode. Amor é não-negociável.', 'Família sem amor evidente é escritório compartilhado.', '@jonataspellegrino'),
('06-20', 6, 20, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Não deixamos disso.', 'Atos 4:20', 'O que Deus fez por ti que tu tá calando — por medo do quê?', 'Pedro e João foram presos e disseram: não conseguimos calar. Tu fica calado. Tem testemunho de cura, de provisão, de casamento restaurado, de filho de volta — e tu guarda. ''É pessoal'', ''não é hora'', ''vão achar religioso''. Medo de parecer crente. Medo de perder cliente. Medo de perder amigo laico. Calar testemunho é covardia. Abre a boca. Conta. Deus não fez coisa grande na tua vida pra ser hashtag #grateful — fez pra ser proclamado.', 'Testemunho silenciado é Deus roubado do crédito.', '@caleb.montenegro'),
('06-21', 6, 21, 'josue-caetano', 'Josué Caetano', '71.204', 'Apartareis o maldito.', 'Josué 7:13', 'Que ''acã'' escondido na tua tenda tá travando tua tropa?', 'Acã roubou coisas condenadas, escondeu na tenda, e o exército de Israel perdeu batalha. Tu é líder. Tem acã em ti: pecado secreto, relação velada, dinheiro mal-justificado. Enquanto isso existir, tua tropa (família, equipe, ministério) não vence. Tu foge, eles caem. Josué confrontou Acã antes de prosseguir. Teu turno: confessa. A primeira caixa da tua vitória é limpar o acã pessoal.', 'Líder com acã condena a tropa inteira.', '@josue.caetano'),
('06-22', 6, 22, 'davi-valverde', 'Davi Valverde', '71.337', 'Nos lugares frescos.', 'Salmo 23:2', 'Quando foi a última vez que tu descansou SEM culpa?', 'Pastor leva pras águas tranquilas. Davi descansa. Tu não descansa. Quando para, sente culpa. ''Deveria estar fazendo''. Isso é treino de ansiedade — não de produtividade. Deus instituiu sábado. Uma vez por semana. Desconecta. Dorme. Anda sem rumo. Brinca com filho. Ora sem pedido. Descanso culpado não é descanso — é prolongamento do cansaço. Legendário lidera descansando bem.', 'Quem não descansa bem, lidera mal.', '@davi.valverde'),
('06-23', 6, 23, 'elias-dovale', 'Elias do Vale', '71.418', 'Sobe, come e bebe.', '1 Reis 18:41', 'Quantas porções você tá deixando acumular — e o corpo tá cobrando?', 'Elias antes da vitória: come, bebe, dorme. Depois do embate com os profetas, repete: come, bebe, dorme. Ministério sem corpo é burnout a caminho. Tu pula refeição. Dorme 5h. Não exercita. Reza mais, come mal. Deus não é sádico — Ele criou corpo. Honra corpo. Pergunta sincera: tu comeu hoje? Dormiu? Caminhou? Não é carnalidade, é mordomia. Negligência física é desconfiança do Deus que criou teu sistema.', 'Espiritual sem mordomia de corpo é auto-sabotagem.', '@elias.dovale'),
('06-24', 6, 24, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Chegai aqui.', 'Juízes 7:17', 'Quantos perto de ti ainda não foram chamados pro teu propósito específico?', 'Gideão falou: chegai, olhai, fazei como eu faço. Convocou. Tu tem propósito. Raro. Mas anda sozinho. Medo de expor, medo de delegar. Propósito multiplica com equipe. Convoca. Nomeia três pessoas — a pessoa 1 do teu projeto, a 2, a 3. Chama pessoalmente. Um por vez. Mostra a visão. Deus não chama indivíduo — chama gente junta. Lobo solitário não é líder; é desperdício.', 'Propósito sem equipe é vaidade lenta.', '@gideao.sampaio'),
('06-25', 6, 25, 'neemias-barros', 'Neemias Barros', '71.612', 'Eu sondaria Jerusalém.', 'Neemias 2:13', 'Qual diagnóstico honesto do estado atual você tá evitando fazer?', 'Neemias chegou em Jerusalém e percorreu os muros à noite, sozinho, pra ver o real. Não ouviu boato. Foi. Viu. Tu? Decide sem diagnóstico. Reage sem avaliar. Quando foi a última vez que tu parou, fez inventário sincero — casamento, saúde, finanças, espiritual? Sem diagnóstico, plano é chute. Hoje: sonda. Uma área. 30 minutos. Anota números, dados, fatos. Só assim plano vira real.', 'Plano sem diagnóstico é exorcismo de cego.', '@neemias.barros'),
('06-26', 6, 26, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Dá-nos um rei.', '1 Samuel 8:5', 'Que atalho humano tu tá pedindo a Deus — e Ele tá prestes a te dar como juízo?', 'Israel pediu rei. Samuel avisou: não vai dar certo. Deus disse: dá o rei pra eles. Consegue o pedido. Colhe consequência. Tu também: pede atalho ''me dá essa porta, esse sócio, essa esposa''. Deus avisa: errado. Tu insiste. Ele libera. Tu celebra. Três anos depois sofre. Cuidado com orações que Deus ''responde'' não porque quer — porque tu forçou. Submete: ''Senhor, não se a Tua vontade, não se a Tua hora''.', 'Atalho insistido é prisão concedida.', '@samuelqueiroga'),
('06-27', 6, 27, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Em corrida.', '1 Coríntios 9:24', 'Tu corre como quem quer ganhar — ou como quem só quer participar?', 'Paulo fala: corre de modo a ganhar. Não é participar. É vencer. Hoje cultura cristã virou ''o que importa é participar''. Errado. Jesus era extremo. Paulo era extremo. Davi era extremo. Tu? Morno. Corre pra ganhar ou pra marcar presença? Essa é a pergunta. Extremo não é orgulho — é obediência. Abraça. Santo não é medíocre com Deus.', 'Cristão morno perde a coroa que podia ter.', '@benjamim.paiva'),
('06-28', 6, 28, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Vede, como semelhança de fogo.', 'Ezequiel 1:27', 'Que visão de Deus você teve no passado que esfriou — e parou de buscar de novo?', 'Ezequiel viu. Visão de fogo. Experiência. Tu teve também. Lembra? Dia da conversão. Retiro marcante. Noite específica. Depois foi esfriando. Rotina tomou. Visão é intermitente — precisa renovação. Pede nova visão. ''Senhor, já faz tempo que não Te vejo assim''. Pede. Deus não cansa de mostrar pra quem busca. Ele cansa de responder pra quem para de pedir.', 'Visão antiga sem renovação vira fóssil.', '@ezequielferraz'),
('06-29', 6, 29, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Exortai-vos uns aos outros.', 'Hebreus 3:13', 'Quando foi a última vez que tu exortou irmão de verdade — ou escondeu por medo?', 'Hebreus manda: exortai TODOS OS DIAS. Todos. Os. Dias. Tu? Último exortar foi quando? Não aquele whatsapp ''Deus te abençoe'' — exortar real: ''mano, o que você tá fazendo não tá certo, para''. Exortação custa. Gera atrito. Incomoda. Mas salva. Cristão que não exorta é cúmplice da morte espiritual alheia. Hoje: manda mensagem específica. Com amor, firme.', 'Cristão que não exorta é cúmplice do próximo de cair.', '@jonataspellegrino'),
('06-30', 6, 30, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Peleja por nós.', 'Êxodo 14:14', 'Tu briga primeiro e ora depois — ou confia Deus brigar enquanto tu toma posição?', 'Moisés: Deus peleja por vós, ficai tranquilos. Tu briga humano. Gasta energia. Responde mensagem. Replica publicação. Processa pessoa. Perde sono. Enquanto isso, Deus podia ter resolvido se tu tivesse confiado. Recolhe. Entrega. Silencia. Ora. Deus peleja melhor. Tua briga nunca cura — só adia. Retirada estratégica com oração é mais poderosa que briga direta.', 'Quem briga sozinho perde tempo. Deus briga melhor.', '@caleb.montenegro'),
('07-01', 7, 1, 'josue-caetano', 'Josué Caetano', '71.204', 'Dar-vos-ei descanso.', 'Josué 1:13', 'Tu entra na Terra Prometida descansando — ou chega já estressado como no deserto?', 'Deus prometeu: farei vocês descansarem. Nem toda vitória vem com frenesi. Tu conquista objetivo novo e já parte pro próximo sem parar. Sempre deserto. Deus prometeu descanso. Casa própria, casamento estável, vocação clara — é pra desfrutar, não pra sofrer. Permite descansar. Permite sentar sem culpa. Promessa cumprida pede desfrute — não prova de mais valor.', 'Promessa cumprida e não desfrutada ofende o Dador.', '@josue.caetano'),
('07-02', 7, 2, 'davi-valverde', 'Davi Valverde', '71.337', 'O Senhor é o meu rochedo.', '2 Samuel 22:2', 'Em que rocha tu tá apoiado agora — e se ela tremer, cai junto?', 'Davi confessa: o Senhor é o meu rochedo. Não a reputação. Não o dinheiro. Não o casamento. Não o filho. Não a igreja. O Senhor. Tu identifica tua rocha real? Faz o teste mental: se X sumir amanhã, desabo? Então X é tua rocha. E Deus é teto. Inverte. Ele é a rocha. Tudo mais é bênção acima dela. Essa troca de lugares muda paz interior.', 'Se algo além de Deus tem poder de te destruir, é teu ídolo.', '@davi.valverde'),
('07-03', 7, 3, 'elias-dovale', 'Elias do Vale', '71.418', 'Deixou uma dobra e vestiu o manto.', '2 Reis 2:13', 'Quem que te inspirou teu chamado tu tá honrando — e que unção tu pediu em dobro?', 'Eliseu pegou o manto de Elias. Pediu unção em dobro. Tu tem pai espiritual. Mentor. Referência. Honra. Pede dobrado. Não pra inflar ego — pra levar adiante. A maioria fica igual ao mentor. Poucos dobram. Dobra exige obediência intencional. Aprender, praticar, superar. Quem tu quer superar no Reino? E o que tu tá fazendo específico pra isso?', 'Igual é fácil. Dobrar exige obediência custosa.', '@elias.dovale'),
('07-04', 7, 4, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Não pouparam a nação.', 'Juízes 7:22', 'Onde tu tá contemporizando que deveria estar cortando?', 'Os 300 não pouparam. Cortaram. Tu? Contemporiza. ''Devagar a pessoa melhora''. ''Aos poucos vou largar''. ''Com tempo ajusto''. Às vezes, sim. Outras, é só desculpa lenta pra dor gradual. Algumas coisas têm que ser cortadas: vício específico, relacionamento tóxico, compromisso errado, hábito destrutivo. Não ''vou diminuindo''. É cortar. De uma vez. Deus ajuda quem corta. Quem contemporiza envelhece com o problema.', 'Corte definitivo é mais curto que 25 anos contemporizando.', '@gideao.sampaio'),
('07-05', 7, 5, 'neemias-barros', 'Neemias Barros', '71.612', 'Eles zombaram de nós.', 'Neemias 2:19', 'Quem tá rindo do teu projeto — e isso tá parando tu ou movendo tu?', 'Sambalate, Tobias e Gesém riram de Neemias. Deboche. Tu? Tem gente rindo de teu projeto. Investimento que achou arriscado. Negócio que julgou pequeno. Casamento que chamaram de ingenuidade. Ministério que acharam loucura. Deboche é teste. Quem recua com deboche, não era chamado mesmo. Quem continua, prova que era. Neemias continuou E respondeu à zombaria com verdade. Nem ignora nem carrega — responde com trabalho.', 'Zombaria é peneira. Chamado real fica; vaidade sai.', '@neemias.barros'),
('07-06', 7, 6, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Tu és o homem.', '2 Samuel 12:7', 'Quem Deus tá colocando na tua vida pra dizer ''tu és o homem'' — e tu tá afastando?', 'Natã confrontou Davi direto: tu és o homem da parábola. Davi recebeu. Não matou o profeta. Tu tem Natã? Mentor, pastor, esposa, amigo íntimo, filho adulto. Que Deus usa pra te apontar pecado. Se sim, receba. Se não tem, pede. Sem Natã, rei cai. Davi tinha Natã e sobreviveu. Saul não tinha e ruiu. Escolhe. Ou Natã te alerta, ou tragédia te ensina — do jeito duro.', 'Homem sem Natã morre por orgulho.', '@samuelqueiroga'),
('07-07', 7, 7, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Fervor no espírito.', 'Romanos 12:11', 'Teu fogo espiritual esfriou desde quando?', 'Paulo: fervoroso no espírito. Fogo. Hoje cristão tem morno como orgulho: ''sou equilibrado''. Engano. Morno é aviso. Apocalipse 3: cuspo o morno. Tu sente fogo quando ora? Quando lê Palavra? Quando adora? Ou virou hábito chato? Fogo não é temperamento emotivo — é queima interna. Pede. ''Pai, reaviva o fogo. Me tira do morno''. Legendário queima. Quem não queima esquenta inimigo.', 'Morno é pior que frio. Frio pelo menos é diagnóstico.', '@benjamim.paiva'),
('07-08', 7, 8, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Veio sobre mim a mão do Senhor.', 'Ezequiel 37:1', 'Qual direção Deus tá te levando que parece inútil — e tu tá hesitando em ir?', 'Deus levou Ezequiel a um vale de ossos secos. Por quê? Não tinha lógica. Foi. Pregou. Viveu. Ordem divina às vezes parece absurda. Mudar cidade. Começar projeto impossível. Abrir igreja em bairro impopular. Encarar assunto difícil. Se tu espera lógica, nunca vai obedecer. Deus não consulta teu bom senso. Vai. A lógica aparece na obediência — não antes.', 'Lógica antes de obediência paralisa. Obediência revela lógica depois.', '@ezequielferraz'),
('07-09', 7, 9, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Quantas vezes te daria.', 'Mateus 23:37', 'A quem tu rejeitou amor — e depois chamou de mágoa?', 'Jesus chorou Jerusalém: quantas vezes quis reunir e vocês não quiseram. Tu? Alguém tentou te amar e você rejeitou. Pai, mãe, esposa, irmão, amigo. Chamou de interesseiro. Duvidou da intenção. Empurrou pra longe. Depois chorou solidão. Muitas vezes amor foi oferecido — tu não quis. Admite. Abre. Algumas pontes ainda estão de pé. Atravessa antes de ruir de vez.', 'Quem rejeita amor oferecido fica com solidão merecida.', '@jonataspellegrino'),
('07-10', 7, 10, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Onde quer que pisar a planta dos teus pés.', 'Josué 1:3', 'Onde tu ainda não pisou porque esperou convite humano que Deus nunca ia enviar?', 'Deus falou: toda terra que pisar, eu dou. Ação primeiro. Tu espera convite humano. Aprovação de pastor pra ministério. Sim da esposa pra passo de fé. Ok do sócio pra decisão certa. Às vezes bom consultar. Outras, é fuga. Espera sinal Divino, não aval humano. Quando o chão é teu, pisa. Convite de gente às vezes nunca vem. Aprovação do Céu já veio.', 'Esperar aval humano depois que Deus já mandou é desobediência educada.', '@caleb.montenegro'),
('07-11', 7, 11, 'josue-caetano', 'Josué Caetano', '71.204', 'Vou velho, entrado em dias.', 'Josué 23:2', 'O que tu precisa dizer à tua família antes de envelhecer mais — que tá adiando?', 'Josué, velho, reuniu liderança e falou verdade. Testamento verbal. Tu vai morrer. 20, 40, 60 anos. Tem palavra que tem que ser dita — pro filho, pra esposa, pro pai, pro irmão. Perdão a dar. Benção a declarar. Segredo a contar. Valor a ensinar. Não leva pro túmulo o que tinha que ter falado. Hoje, escreve. Uma carta. Amanhã, entrega.', 'Palavra não dita vira ausência que não se preenche.', '@josue.caetano'),
('07-12', 7, 12, 'davi-valverde', 'Davi Valverde', '71.337', 'Acorda, glória minha.', 'Salmo 57:8', 'Que parte de ti tu deixou dormir pra sobreviver — e Deus tá chamando pra despertar?', 'Davi acordou sua glória. Harpa. Canto. Criatividade. Tu também tem glória dormindo. Criatividade sepultada. Sonho silenciado. Dom não exercido. Por ''maturidade'', tu matou. Não era maturidade, era medo. Deus chama de volta. ''Acorda glória minha''. Aquela parte de ti que tu abandonou pra caber no mundo prático — acorda. Legendário não deixa glória dormir.', 'Glória dormente morre se não acordar.', '@davi.valverde'),
('07-13', 7, 13, 'elias-dovale', 'Elias do Vale', '71.418', 'Responde-me, Senhor.', '1 Reis 18:37', 'Tu grita pra Deus — ou tu sussurra por medo de constranger?', 'Elias gritou diante do povo. Público. Sem constrangimento. Tu ora baixinho. Susurra. Congresso ergue mão, tu finge. Culto canta forte, tu cochicha. Medo do que pensam. Legendário não mede expressão por plateia. Grita quando for grito. Chora quando for choro. Se alegra quando for alegria. Deus prefere intensidade real a performance contida.', 'Medo de parecer é o que trava expressão real.', '@elias.dovale'),
('07-14', 7, 14, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Sede ainda do nosso lado.', '2 Crônicas 19:11', 'Quem na tua tropa tá duvidando do teu lado — e tu nem viu?', 'Josafá falou aos juízes: sede corajosos. Coesão. Tu lidera. Tem gente na tua equipe duvidando. Silenciosa, mas duvidando. Ela não fala, age. Performance caindo. Engajamento frouxo. Tu atribui a preguiça. Pode ser dúvida. Conversa 1-1. Pergunta: você tá comigo? Tá convicto do que fazemos? Se não, calibra ou libera. Dúvida silenciosa corrói o exército por dentro.', 'Exército com dúvida interna perde antes da batalha.', '@gideao.sampaio'),
('07-15', 7, 15, 'neemias-barros', 'Neemias Barros', '71.612', 'Tomara que todos fossem profetas.', 'Números 11:29', 'Quem tu tá achando pequeno — que Deus pode estar usando?', 'Moisés desejou: todos profetas! Não só eu. Tu é ciumento de chamado. Quando um irmão cresce, incomoda. Quando um jovem desponta, minimiza. Tem gente sendo levantada na tua célula, no teu círculo, que tu enxerga pequeno por orgulho. Olha de novo. Deus levanta quem quer. Não concorra. Reconheça. Bendiga. Legendário chama outros legendários, não compete.', 'Inveja de chamado alheio atrasa teu próprio.', '@neemias.barros'),
('07-16', 7, 16, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Jovem acha.', 'Eclesiastes 11:9', 'Qual decisão do passado tu ainda não entregou a Deus — continua remoendo?', 'Pregador: jovem, alegra-te, mas lembra que Deus julgará. Tu foi jovem. Fez coisa. Hoje tem 40, 50. Remói decisão antiga. Culpa. Arrependimento sem entregar. Fica preso. Deus perdoa — literalmente. Precisa entregar. Escreve no papel a coisa específica. Ora sobre. Rasga o papel. Fé em ato simbólico. Vira nova página. Ou remói até morrer.', 'Culpa entregue é liberdade. Não entregue, corrente.', '@samuelqueiroga'),
('07-17', 7, 17, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Acaso é a minha palavra como fogo.', 'Jeremias 23:29', 'Palavra de Deus queima em ti — ou você lê frio como jornal?', 'Jeremias: minha palavra é fogo, martelo que esmigalha. Tu lê Bíblia sem arder. Lê como livro chato. Pula versículos. Repete de memória sem sentir. Por quê? Oração antes de ler? Fé de que vai encontrar Deus ali? Palavra não arde quando tu entra com postura de consumidor. Arde quando tu entra com fome. Hoje, lê menos — mas com oração antes e meditação depois. Arde.', 'Bíblia lida sem fé é história antiga. Com fé, é fogo.', '@benjamim.paiva'),
('07-18', 7, 18, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Tu és perfeito.', 'Ezequiel 28:15', 'Em que ponto tu começou a se achar — e começou a cair?', 'Deus falou da queda de Satanás: perfeito até encontrar iniquidade. Queda começa com auto-estima desbalanceada. Tu, depois de vitória, inflou? Pensou ''sou mesmo''? Esse é o ponto exato que começa a cair. Pedro negou Jesus depois de gabar que não negaria. Humildade não é negação de força — é lembrança de fonte. Tua força não é tua. É Dele. Escorrega em esquecer isso e o tombo começa.', 'Inflar depois de vitória é assinatura da próxima queda.', '@ezequielferraz');
INSERT INTO public.provocacoes (dia_ano, mes, dia, autor_slug, autor_dia, autor_numero, citacao, autor_citacao, pergunta, texto, aspas_autor, instagram) VALUES
('07-19', 7, 19, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Levantai-vos, partamos.', 'Marcos 14:42', 'Qual próxima obediência tá clara — e tu tá procrastinando?', 'Jesus levanta a tropa no Getsêmani: levantai, partamos. Não discute. Parte. Tu tem ação clara hoje. Aquela ligação difícil. Aquela mensagem. Aquele passo que Deus apontou. Procrastina. Tira da mente com distração. Obediência adiada enrijece coração. Na próxima, fica mais difícil. Levanta. Parte. Agora. Obediência é músculo — treina ou atrofia.', 'Cada obediência adiada treina tua desobediência.', '@jonataspellegrino'),
('07-20', 7, 20, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Aprendizagem.', '2 Timóteo 3:14', 'O que tu aprendeu espiritualmente nesse ano — que ainda não começou a ensinar?', 'Paulo a Timóteo: permanece no que aprendeste. Aprender pra reter, não pra guardar. Tu aprendeu alguma coisa esse ano. Sobre oração, vício, casamento, dinheiro, paternidade. Retém. E passa. A quem? Alguém mais novo. Discipulado. Legendário ensina o que aprendeu — formal ou informal. Se não passa, aprendeu pra si. Egoísmo espiritual.', 'Aprendizado guardado endurece. Passado, floresce.', '@caleb.montenegro'),
('07-21', 7, 21, 'josue-caetano', 'Josué Caetano', '71.204', 'Sê forte.', 'Josué 1:9', 'Onde tu tá fraco por não ter pedido força — e achou que podia sozinho?', 'Deus repete 4 vezes: sê forte. Quer dizer: tu não é, vai precisar. Força não é autoajuda. É orada. Pedida. Descida. Tu tenta ser forte por vontade própria. Cansa. Falha. Culpa-se. Muda a fonte. Começa o dia: ''Pai, me dê força pra hoje''. Simples. Sem essa, tu enche o tanque com gasolina de posto qualquer e acelera pouco.', 'Força própria tem teto. Força pedida é sem-limite.', '@josue.caetano'),
('07-22', 7, 22, 'davi-valverde', 'Davi Valverde', '71.337', 'Aquietar-me-ei.', 'Salmo 116:7', 'Por onde tua alma tá inquieta — que tu tá enchendo com ruído em vez de descansar em Deus?', 'Davi falou com sua alma: aquieta. Alma inquieta busca entretenimento. Scroll, Netflix, drinks, shopping, gossip. Parece alívio, é anestésico. Alma descansa em Deus, não em distração. Hoje: 20 minutos sem ruído. Só você, Deus, silêncio. Desconfortável no começo. Depois paz real — não a de anestesia. Legendário sabe descansar a alma antes de dormir o corpo.', 'Alma sem Deus usa ruído como sedativo.', '@davi.valverde'),
('07-23', 7, 23, 'elias-dovale', 'Elias do Vale', '71.418', 'E assim é todo aquele.', 'Atos 2:21', 'Tu deixa o nome do Senhor fácil de invocar — ou virou difícil até em casa?', 'Pedro: todo que invocar o nome do Senhor será salvo. Fácil de dizer. Mas em casa tu invoca? Na mesa, ora voz alta? No carro, louva? Quando brigou com esposa, recua e invoca? Em público é mais fácil que em casa. Casa é intimidade, não tem performance. Invoca Dele em casa. Teu filho ouvindo. Cria atmosfera que depois nunca mais ele esquece.', 'O nome de Deus invocado em casa forma gerações.', '@elias.dovale'),
('07-24', 7, 24, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Levanta-te tu!', 'Juízes 8:20', 'Qual coisa tu tá deixando pros outros fazerem que é responsabilidade tua?', 'Gideão falou pro filho: levanta tu, mata. Delegar é bom. Delegar o que é tua responsabilidade específica, pecado. Tu delega correção do filho pra esposa. Conversa difícil com sócio pro RH. Liderança da oração em casa pra pastor. Tu é o responsável. Assume. Às vezes é duro — e é esse o ponto. Responsabilidade própria forja caráter. Delegar pra evitar dor é encolher a alma.', 'Delegar o que é teu é fugir do forjamento.', '@gideao.sampaio'),
('07-25', 7, 25, 'neemias-barros', 'Neemias Barros', '71.612', 'Não vim da terra.', 'Gênesis 24:5', 'Qual volta ao passado Deus tá te proibindo — mesmo que pareça razoável?', 'Abraão proibiu o servo de levar Isaque de volta à terra antiga. Tu? Volta pra ex, pra antigo emprego, pra igreja antiga, pro hábito velho. ''Foi bom antes''. Pode ter sido — Deus tirou. Voltar é descumprir mudança divina. Nostalgia é venenosa quando vira direção. Ora: ''Senhor, posso voltar?''. Se é não — fecha porta. Mesmo que parecesse razoável.', 'Nostalgia como bússola conduz ao passado que Deus já cortou.', '@neemias.barros'),
('07-26', 7, 26, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Corrija o seu filho.', 'Provérbios 29:17', 'Tua correção do teu filho é firmeza ou descontrole?', 'Salomão: corrige teu filho. Correção, não surto. Muitos pais confundem. Surto é emocional, destrói; correção é pedagógica, constrói. Teu filho testa. Se tu explode, ensina instabilidade. Se tu corrige com firmeza e afeto, ensina caráter. Hoje: antes de corrigir, respira. Ora 5 segundos. Aí fala. Correção com Deus no meio muda tudo. Correção sem, é trauma.', 'Correção sem oração é descarrego emocional travestido.', '@samuelqueiroga'),
('07-27', 7, 27, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Pela manhã clamar.', 'Salmo 5:3', 'Primeira coisa que tu faz ao acordar — é celular ou Deus?', 'Davi: pela manhã clamarei. Primeiro. Tu? Acorda, pega celular. Instagram antes de Jesus. Whatsapp antes de Pai. Notícia antes da Palavra. Tua cabeça se programa com input do mundo antes de input de Deus. Durante o dia, tu se pergunta por que anda ansioso. Troca. Amanhã: celular depois. Oração primeiro. 5 minutos. Teu dia muda. Começo direciona tudo.', 'Primeiro input do dia define frequência do resto.', '@benjamim.paiva'),
('07-28', 7, 28, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Cometeram abominação.', 'Ezequiel 16:50', 'Qual abominação o mundo tá vendendo como normal — e tu tá comprando?', 'Ezequiel fala de Sodoma com linguagem dura. Abominação. Hoje abominação virou orgulho. Virou ativismo. Virou estética. Tu consome sem criticar. Série, música, festa, influenciador. Examina: o que Deus chama abominação o mundo chama arte? Se Sim, tu não assiste? Legendário não é puritano. Mas não é idiota. Filtra. Palavra de Deus é gabarito. Nada acima dela.', 'Abominação normalizada vira identidade social.', '@ezequielferraz'),
('07-29', 7, 29, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Coragem.', 'Marcos 10:49', 'Qual coragem alheia você precisa reconhecer publicamente — e não tá?', 'Jesus para Bartimeu: coragem. Reconheceu. Tu? Vê coragem no outro — esposa que saiu de depressão, filho que voltou de longe, amigo que largou vício — e cala. Nem elogia, nem celebra. Legendário reconhece coragem alheia. Não por bajulação, mas por verdade. Fortalece quem tá se levantando. Hoje: nome + mensagem. Reconhece. Coragem reconhecida se multiplica. Ignorada, murcha.', 'Coragem ignorada do próximo vira ressentimento dele e orgulho teu.', '@jonataspellegrino'),
('07-30', 7, 30, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Pisarás sobre os seus altos.', 'Deuteronômio 33:29', 'Qual alto tu tá pisando agora — e é por teu esforço ou por Deus te colocar lá?', 'Moisés bendisse: Israel pisará altos. Não é jactância — é profecia cumprida. Tu também pisa altos hoje. Emprego bom, casa boa, família boa. Pergunta séria: tu alcançou ou Deus te pôs? Humildade é resposta honesta. Gratidão é postura correta. Soberba é pisar alto e esquecer quem te subiu. Pisa firme — com joelho no chão interno.', 'Pisar alto com coração ajoelhado é o equilíbrio do eleito.', '@caleb.montenegro'),
('07-31', 7, 31, 'josue-caetano', 'Josué Caetano', '71.204', 'Fidelíssimo.', '1 Samuel 26:23', 'Onde tu prometeu e não cumpriu — há tanto tempo que esqueceu?', 'Davi falou de Deus: fidelíssimo. Deus cumpre. Tu? Tem promessa a filho, a esposa, a funcionário, a Deus. Meses, anos. Esqueceu. A outra pessoa não. Ela guarda como dívida. Resgata. Uma por uma. Hoje: abre agenda. Anota promessas por cumprir. Cumpre uma hoje. Outra amanhã. Palavra legendária é contrato não-assinado. Quebra palavra quebra integridade.', 'Palavra não cumprida é mentira com atraso.', '@josue.caetano'),
('08-01', 8, 1, 'davi-valverde', 'Davi Valverde', '71.337', 'A mim me sondou Deus.', 'Salmo 139:1', 'O que tu esconde de ti mesmo — que Deus já sabe e tá te convidando a ver?', 'Davi reconheceu: Deus me sondou. Soube tudo. Tu tem autoengano ativo. Coisa que tu acha leve e Deus acha séria. Coisa que tu minimiza e Ele sublinha. Convida Ele sondar. Pede luz. ''Pai, o que tô escondendo de mim?''. Espera. Pode ser um hábito. Uma atitude. Um motivo por trás de motivo. Sondagem autorizada leva à liberdade. Sem sondar, prisão permanece.', 'Tu pode esconder de ti. Não dele. E o que tu esconde, governa.', '@davi.valverde'),
('08-02', 8, 2, 'elias-dovale', 'Elias do Vale', '71.418', 'Tomaram pedras pra apedrejá-lo.', '1 Reis 21:13', 'Qual injustiça contra inocente você não denunciou por covardia institucional?', 'Jezabel mandou matar Nabote por falsa testemunha. Tu vê injustiça e cala. Fofoca do grupo contra alguém. Demissão arbitrária. Difamação. Tu não entra. ''Não é comigo''. É sim. Silêncio diante de injustiça é cumplicidade. Legendário fala quando o fraco tá sendo esmagado. Com tato, com firmeza. Se ninguém faz nada, tu faz. Pequeno. Mas faz. Na história, o silêncio pesou mais que o grito.', 'Silêncio diante de injustiça protege o injusto.', '@elias.dovale'),
('08-03', 8, 3, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'E o ferreiro.', '1 Samuel 13:19', 'Qual ferramenta Deus te deu que tu não aprendeu a usar — porque depende dos outros?', 'Na época de Saul, Israel não tinha ferreiro — dependia dos filisteus pra afiar. Tu depende dos outros pra tudo. Depende de contador, advogado, terapeuta pra pensar. Nem tudo é ruim. Mas toma consciência: tu aprende também? Ou só contrata? Algumas ferramentas são pra tu dominar. Oração. Estudo da Palavra. Comunicação. Finanças básicas. Não dá pra terceirizar espiritualidade nem autoconhecimento.', 'Dependência total é fragilidade disfarçada de especialização.', '@gideao.sampaio'),
('08-04', 8, 4, 'neemias-barros', 'Neemias Barros', '71.612', 'Perto do muro.', 'Neemias 3:23', 'Cada um de nome pra construir o muro. Tu tá construindo teu trecho específico?', 'Neemias capítulo 3 lista quem consertou cada parte. Nome por nome. Trecho por trecho. Não era ''todos construindo tudo''. Era ''cada um o seu''. Tu sabe teu trecho? Ou tá metido em obra de todo mundo e não faz a tua? Chamado específico exige foco específico. Qual muro é teu? Constroi aquele. Deixa que irmão constrói o dele. Não tenta substituir ele — mas não ausenta do teu.', 'Quem tenta fazer trecho alheio, abandona o próprio.', '@neemias.barros'),
('08-05', 8, 5, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Examinando diariamente.', 'Atos 17:11', 'Tu examina o que ouve — ou engole?', 'Bereanos examinavam Paulo com a Palavra. Tu? Engole. Pregador famoso fala, tu aceita. Podcaster cristão opina, tu reposta. Livro diz, tu adota. Não examina. Exames simples: isso bate com Bíblia? Tem fruto? O autor vive o que prega? Bereanos eram ''mais nobres'' por isso. Legendário é bereano. Examina tudo. Aceita após peneira.', 'Cristão que não examina é escravo do carisma alheio.', '@samuelqueiroga'),
('08-06', 8, 6, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Exerce-te tu mesmo.', '1 Timóteo 4:7', 'Tu treina piedade — ou vive de migalha do domingo?', 'Paulo a Timóteo: exerce-te na piedade. Verbo. Esforço. Disciplina. Tu? Vive de culto dominical. Segunda a sábado, seca. Piedade sem treino é ilusão. Treino: jejum semanal, leitura diária, oração em horário fixo, memorização de Palavra, serviço regular. Não é legalismo — é formação. Atleta sem treino não compete. Legendário sem treino não vence nada espiritualmente.', 'Cristão sem rotina espiritual é atleta de passeio.', '@benjamim.paiva'),
('08-07', 8, 7, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Corações divididos.', 'Oséias 10:2', 'Qual divisão interna que tu acha que ''dá pra conciliar'' — e Deus chama de ruína?', 'Oséias: coração dividido culpa os. Tu tenta conciliar Deus com mundo. Cristo com conveniência. Fé com carreira tóxica. Não cabe. Uma das duas vai fracassar. Cristão que tenta servir dois perde os dois — os tempo. Decide: plant bandeira inteira. Ou Cristo ou o outro. Fingir equilíbrio é auto-engano de longo prazo. Vai ruir um dia.', 'Coração dividido é ruína com prazo escondido.', '@ezequielferraz'),
('08-08', 8, 8, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Não vos apartes.', 'Judas 1:19', 'Qual irmão tu tá empurrando pra longe que Deus te mandou ficar perto?', 'Judas falou de sensuais que se separam. Tu também se separa. Por orgulho. Por mágoa. Por cansaço. Por achar o outro irmão inferior. Cristão se separando de cristão — vergonhoso. Quem tu deixou de falar? Quem evita? Pensa. Talvez seja caso de reconciliação pendente. Mesmo que tu não volte a conviver diariamente, reconcilia. Não carrega essa sujeira pro teu altar.', 'Separação sem reconciliação é oferta rejeitada.', '@jonataspellegrino'),
('08-09', 8, 9, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Vós não quisestes.', 'Mateus 23:37', 'Quantos convites de Deus tu recusou por ter achado difícil — e hoje chama isso de ''Ele não quis''?', 'Jesus chorou Jerusalém — quis reunir, eles não quiseram. Vários momentos Deus quis, tu não quis. Convite pra liderar, tu recuou. Chamado pra oração, tu deu desculpa. Impulso pra perdoar, tu adiou. Hoje tu conclui ''Deus fechou porta'' — mas foi tu que trancou. Revisita teus ''nãos''. Alguns ainda podem ser abertos. Outros, só o arrependimento restaura.', 'Deus abre porta. Tua desobediência fecha. Não inverta.', '@caleb.montenegro'),
('08-10', 8, 10, 'josue-caetano', 'Josué Caetano', '71.204', 'Fazei o que fizer Gideão.', 'Juízes 7:17', 'Qual líder na tua vida hoje merece tu copiar fielmente — e tu tá se recusando por orgulho?', 'Gideão disse: olha pra mim e faz igual. Tropa copiou. Venceu. Tu acha humilhação copiar. Quer inventar. Quer fazer do teu jeito. Às vezes bom. Mas há líderes que Deus já testou — copia. Pastor, mentor, pai, chefe fiel. Copiar não é perder personalidade — é respeitar caminho provado. Orgulho que recusa cópia termina repetindo os erros que outros já pagaram.', 'Humildade de copiar bom líder evita anos de erro próprio.', '@josue.caetano'),
('08-11', 8, 11, 'davi-valverde', 'Davi Valverde', '71.337', 'Onde os teus olhos.', 'Gênesis 44:21', 'O que tem capturado teu olhar — e o que esse olhar tá revelando sobre teu coração?', 'José mandou olhar o irmão menor. Olhar é mapa do coração. Tu olha o quê? Feed de quê, por quanto tempo? Pessoa quem? Objeto de desejo qual? Onde tua atenção se deposita involuntariamente, tua alma tá. Ajusta. Olhos com filtro = coração com filtro. Legendário não vê de tudo — escolhe o que entra. Ou teu olhar te serve, ou te escraviza.', 'O olhar revela o coração antes do coração revelar por palavras.', '@davi.valverde'),
('08-12', 8, 12, 'elias-dovale', 'Elias do Vale', '71.418', 'Eia, levanta e come.', '1 Reis 19:5', 'Quando tu tá pra desistir, tu pede ou ignora?', 'Elias quis morrer. Anjo trouxe comida. Não sermão — comida. Tu chega no limite, ignora. Não pede ajuda. Acha que é fraqueza. Errado. Crise pede comunidade. Pede médico. Pede terapia. Pede pastor. Pede amigo. Pede Deus de nome. Ignora e fica solo se afundando. Quem ignora pede caro depois — custa família. Humildade de pedir salva vida.', 'Ignorar o limite é levar a alma pro abismo solitário.', '@elias.dovale'),
('08-13', 8, 13, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'O que ouvi.', 'Juízes 7:14', 'Qual palavra de outro Deus tá usando pra confirmar o que já tinha falado contigo?', 'Gideão ouviu midianita contar sonho. Confirmou o que Deus já disse. Deus confirma. Tu despreza confirmação externa. ''Só minha oração basta''. Orgulho. Deus confirma por Palavra, oração, sonho E circunstância E conselho sábio. Os 4. Se tá só em 1, fica mais alerta. Se tá 4, avança. Despreza sinal externo é recusar ajuda divina.', 'Confirmação em múltiplas frentes é prudência, não incredulidade.', '@gideao.sampaio'),
('08-14', 8, 14, 'neemias-barros', 'Neemias Barros', '71.612', 'Peguei na espada.', 'Neemias 4:16', 'Hoje, tu precisa proteger algo. Tua mão tá na espada ou no almoço?', 'Neemias diz: metade trabalhava, metade protegia com espada. Tu? Constrói, mas não protege. Ou protege, mas não constrói. Casamento precisa ser construído E protegido. Empresa também. Filho também. Ministério também. Proteger do quê? Influência ruim, distração, concorrente, adversário espiritual. Quem só constrói sem guardar, vê ruir. Quem só guarda sem construir, não cresce.', 'Construir sem proteger é construir pra perder.', '@neemias.barros'),
('08-15', 8, 15, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Longe de vós.', 'Salmo 119:115', 'Quem na tua vida puxa tua fé pra baixo — que tu ainda não teve coragem de afastar?', 'Salmista: apartai-vos, malignos. Duro? Nem tanto. Tem gente na tua vida que mina tua fé. Piada sobre oração, deboche sobre igreja, sedução pra voltar pro antigo. ''Meus amigos de infância''. Ou seja quem for. Afasta. Não é julgamento — é sobrevivência. Quem puxa tua fé pra baixo, puxa tua família pra baixo. Distância é proteção. Reavaliação é maturidade. Legendário escolhe quem entra no círculo.', 'Círculo forma convicção. Escolhe quem pisa perto.', '@samuelqueiroga'),
('08-16', 8, 16, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Eu sou o bom pastor.', 'João 10:11', 'Tu obedece um pastor humano — ou ao Bom Pastor?', 'Jesus é o bom pastor. Pastor humano é falho. Tu? Se o pastor humano se perdeu, tu se perde junto. Ruim. Fidelidade a pastor humano é devida até ele contrariar o Bom Pastor. Aí, muda. Legendário é fiel a Cristo primeiro. Não confunde obediência a liderança humana com idolatria. Pastores caem — acontece. Jesus nunca. Apega-se Nele.', 'Fiel a pastor humano acima de Cristo, é ovelha perdida com aval.', '@benjamim.paiva'),
('08-17', 8, 17, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Aqui o fazem.', 'Ezequiel 8:6', 'Que abominação tá acontecendo na tua casa — na tua própria casa — que tu naturalizou?', 'Deus mostrou a Ezequiel abominação DENTRO do templo. Surpresa. Casa de Deus, sujeira. Tu? Tua casa tem abominação. Naturalizou. Palavrão ouvindo com filho. Pornografia no celular durante família assiste TV. Gossip na mesa. Culto a dinheiro disfarçado de trabalho duro. Reconhece. Deus não entra quando abominação mora. Limpa. Começa pela específica que veio na cabeça agora — essa.', 'Naturalização do pecado é espessa camada sobre o óbvio.', '@ezequielferraz'),
('08-18', 8, 18, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Vai em paz.', '1 Samuel 1:17', 'Quem tá precisando de uma benção tua — não genérica, específica?', 'Eli abençoou Ana com paz específica. Tu bendiz? Ou só manda ''Deus te abençoe'' que virou auto-preenchido? Benção real: nome, situação concreta, pedido específico. Ana partiu diferente depois de benção ancorada. Hoje: três pessoas. Benção concreta. Mensagem, ligação, presença física. Benção genérica não aterra — só ecoa. Legendário bendiz com precisão.', 'Benção sem precisão é polidez disfarçada.', '@jonataspellegrino'),
('08-19', 8, 19, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Repreendei.', 'Tito 2:15', 'Tu sabe repreender sem destruir — ou fica calado porque tem medo de ser o durão?', 'Paulo diz a Tito: repreende. Verbo direto. Com autoridade. Tu cala. Não quer ser desagradável. Virou virtude social. Cristianismo adequado não inclui repreensão. Errado. Bíblia inteira tem repreensão. Com amor, com firmeza. Com tato, com verdade. Tu repreende quando é necessário? Filho, esposa, sócio, amigo. Silêncio social é cumplicidade travestida de educação. Legendário repreende.', 'Quem não sabe repreender, não sabe amar direito.', '@caleb.montenegro'),
('08-20', 8, 20, 'josue-caetano', 'Josué Caetano', '71.204', 'Há terra que resta.', 'Josué 13:1', 'Qual terra do chamado ainda resta tomar — que tu envelheceu e não foi?', 'Deus disse a Josué velho: ainda tem muita terra. Tu? Já envelheceu sem tomar tudo. Ainda dá tempo. Projeto engavetado, perdão não pedido, igreja não plantada, livro não escrito, filho não reconciliado. ''Passou meu tempo''. Mentira. Caleb pediu monte aos 85. Moisés liderou aos 80. Abraão teve filho aos 100. Aos anos que te restam, a terra tá lá. Toma. Não deixa pros netos.', 'Terra não tomada cobra dívida de gerações.', '@josue.caetano'),
('08-21', 8, 21, 'davi-valverde', 'Davi Valverde', '71.337', 'Aquele dia.', 'Salmo 118:24', 'O que faz esse dia diferente — que tu tá transformando em mais um?', 'Davi: este é o dia que o Senhor fez. Davi celebrava. Tu? Hoje é quarta. Hoje é ordinário. Hoje é só dia. Errado. Cada dia é ato criativo. Hoje não vai voltar. Presente literal. Uma pessoa que você verá hoje morrerá um dia — talvez essa seja última vez. Uma palavra que cairá. Um momento único. Trata o dia como gift — não como repetição. Legendário aproveita.', 'Dia tratado como ordinário vira arrependimento no fim.', '@davi.valverde'),
('08-22', 8, 22, 'elias-dovale', 'Elias do Vale', '71.418', 'E ele já não é.', '2 Reis 2:12', 'Qual mentor teu morreu e tu nunca mais elevou ao nível que ele deixou?', 'Elias subiu. Eliseu rasgou vestes e chorou: meu pai, meu pai. Perdeu referência. Pegou o manto. Tu perdeu referência (pai falecido, pastor que se foi, mentor que mudou). Ficou vazio. Não perdeu só pessoa — perdeu guia. A tarefa é pegar o manto. Continuar. Honrando. Agindo. Multiplicando. Lágrimas são legítimas. Paralisia não. Faz as pazes com a partida e levanta a bandeira.', 'Manto deixado no chão é traição do legado.', '@elias.dovale'),
('08-23', 8, 23, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Quando ouvir nas folhas.', '2 Samuel 5:24', 'Que sinal Deus tá dando agora pra tu se mover — e tu tá esperando sinal maior?', 'Deus disse a Davi: ouvindo som das folhas, te moves. Sutil. Tu espera sinal gigante. Trovão, voz audível, sonho três vezes. Deus geralmente fala sutil. Irritação de consciência. Frase de desconhecido. Versículo que pulou. Move no sutil. Se tu esperar sinal ''autorizado'' tamanho jumbo, perde a janela. Móvel agora. Fé responde ao sussurro.', 'Sinal sutil é fé testada. Grande é mimo.', '@gideao.sampaio'),
('08-24', 8, 24, 'neemias-barros', 'Neemias Barros', '71.612', 'Confidenciávamos.', 'Neemias 6:17', 'Quem na tua vida tá confabulando CONTRA ti — e tu tá agindo como se fosse aliança?', 'Neemias descobriu que nobres de Judá se correspondiam com Tobias, inimigo. Tinha traidor interno. Tu tem? Gente dentro do teu círculo que tá passando informação pro lado errado. Discerne. Não é paranoia — é sabedoria. Neemias confrontou com fatos. Tu? Hoje, observa mais. Fala menos. Quem merece tua informação? Quem tá te devorando por dentro? Legendário confia — mas seleciona.', 'Inimigo interno é o que machuca mais. E o mais difícil de enxergar.', '@neemias.barros'),
('08-25', 8, 25, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Tomar o jugo.', 'Mateus 11:29', 'Que jugo Deus tá te oferecendo — que tu tá rejeitando por achar que o teu é melhor?', 'Jesus ofereceu: tomem meu jugo, é suave. Tu insiste no teu. Tua rotina, tua estratégia, teu jeito. Orgulho. Jugo de Jesus: obediência moldada por Ele. Disciplina que Ele define, não tu. Tua disciplina humana faz ''tua versão'' — cansa. O Dele, transforma. Experimenta. Uma semana submetido ao que Ele pede, no ritmo Dele. Diferença drástica.', 'Jugo próprio exaure. Jugo Dele forma.', '@samuelqueiroga'),
('08-26', 8, 26, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Sofreis para o bem.', '1 Pedro 3:17', 'Tua última crise foi consequência de obediência — ou de estupidez?', 'Pedro: sofrer fazendo bem, melhor que por fazer mal. Tu sofre. Qual categoria? Se fez bem e apanhou, é honra. Se fez burrice e apanhou, é consequência. Se fez bem mas sofre pouco, ora mais profundamente — Cristo sofreu fazendo bem. Se fez burrice — confessa. Cada crise tem origem; não culpa Satanás quando sua carne comandou.', 'Nem toda crise é satânica. Tem muita coisa que é idiotice com data.', '@benjamim.paiva'),
('08-27', 8, 27, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Eu farei ouvir.', 'Ezequiel 2:7', 'Qual palavra Deus tá te mandando falar pra alguém — que tu tem diluído por medo da reação?', 'Deus disse a Ezequiel: fala, ouçam ou não. Tu dilui. Corta um pedaço. Suaviza o adjetivo. Retira o nome. Acha que amor é palavra mole. Errado. Amor é palavra verdadeira. Diluição é covardia com marketing cristão. Fala o que Deus mandou — inteiro. Se a pessoa ouvir, aleluia. Se não, sangue não é teu. Ezequiel transmitiu sem censura.', 'Palavra diluída é Palavra traída.', '@ezequielferraz'),
('08-28', 8, 28, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Toda a casa.', 'Atos 10:2', 'Teu chefe de casa é evidente — ou tu é só o que dorme ali?', 'Cornélio: temia a Deus com TODA sua casa. Liderança espiritual masculina em casa. Tu? Deixou tudo pra esposa. Culto em família? Ela. Oração? Ela. Confronto com filho? Ela. Ensino bíblico? Ela. Tu provê, tu assiste. Cornélio liderava casa na fé. Legendário lidera casa na fé — não delega. Começa simples: oração antes do jantar. Liderado por ti. Hoje.', 'Pai que não lidera em fé deixa casa acéfala espiritualmente.', '@jonataspellegrino'),
('08-29', 8, 29, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Ainda mais.', '2 Samuel 6:22', 'Qual ridículo Deus tá te pedindo — que tu tá evitando por orgulho?', 'Davi dançou seminu diante da arca. Mical desprezou. Davi respondeu: mais aviltado ainda me farei. Tu tem pudor da fé. Não ora público. Não confessa Cristo no trabalho. Não canta no culto com intensidade. Medo de pareça. Davi não tinha. Aviltar por Cristo honra mais que estar elegante sozinho. Legendário paga preço social da fé.', 'Quem economiza ridículo por Cristo economiza benção.', '@caleb.montenegro'),
('08-30', 8, 30, 'josue-caetano', 'Josué Caetano', '71.204', 'Descansastes.', 'Josué 22:4', 'Já descansou. Tempo de voltar pra casa — ou ainda quer mais missão?', 'Josué liberou Rúben/Gade depois da missão. Terra já tomada. Vocês ganharam — voltem pra casa. Tu? Acaba missão, quer outra. Nunca volta pra casa. Família te vê só de longe. Sempre em ministério, sempre em viagem, sempre em mais. Às vezes Deus diz: descansou, volta. Família é missão primária. Voltar não é fracasso — é obediência inversa.', 'Missão perpétua longe de casa é fuga travestida de chamado.', '@josue.caetano'),
('08-31', 8, 31, 'davi-valverde', 'Davi Valverde', '71.337', 'Abri a minha boca.', 'Salmo 81:10', 'Tu tá com boca fechada com Deus — por preguiça ou por raiva disfarçada?', 'Deus a Israel: abre a boca, Eu encho. Aberta é pra receber. Tu fecha. Não ora. Não pede. ''Não quero incomodar Ele''. Mentira. É preguiça ou ressentimento. Ora menos porque pediu e ''não veio''. Deus não dá tudo como queremos. Ele é Pai, não entregador. Continua abrindo boca. Pedindo. Esperando. Boca fechada dá fome espiritual.', 'Quem fecha boca com Deus passa fome espiritual e culpa Deus.', '@davi.valverde'),
('09-01', 9, 1, 'elias-dovale', 'Elias do Vale', '71.418', 'Farei vós presentear.', 'Isaías 58:14', 'Quando foi a última vez que tu jejuou?', 'Isaías 58 descreve jejum que Deus aprova — não só privação, justiça social também. Tu jejua? Não só Quaresma tradicional. Jejum real. Uma refeição, um dia, uma semana. Acompanhado de oração, de ouvir Deus, de perdoar, de ajudar pobre. Cristão moderno não jejua. Perdeu disciplina. Perdeu presença. Começa pequeno. Café da manhã pulado com oração no lugar. Jejum muda cabeça mais que qualquer sermão.', 'Oração sem jejum tem limite. Jejum acompanhado quebra limite.', '@elias.dovale'),
('09-02', 9, 2, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Cava-lo-ás.', 'Deuteronômio 23:13', 'Qual nojeira tu tá tratando como invisível — e Deus tá te mandando enterrar?', 'Lei velha mandava enterrar as fezes. Questão de santidade prática. Tu? Deixa coisa nojenta à vista. Hábito fedendo. Ambiente desorganizado. Relacionamento sujo. Anda por cima como se não sentisse cheiro. Deus liga pra o cotidiano físico — porque forma o espiritual. Limpa. Arruma. Descarta. Pequeno ato físico libera atmosfera espiritual.', 'Baderna física influencia atmosfera espiritual.', '@gideao.sampaio'),
('09-03', 9, 3, 'neemias-barros', 'Neemias Barros', '71.612', 'Guardai o dia de sábado.', 'Deuteronômio 5:12', 'Tu tem um sábado — ou vive sete dias iguais?', 'Deus instituiu sábado. Não foi sugestão. Mandamento. Um dia fora da produção. Pra adoração, pra família, pra descanso, pra respirar. Tu pula. Trabalha o dia todo. ''Produtividade''. Mas teu corpo e alma estão esgotados — e tu acha que é teu dever lutar. Errado. Sábado cristão é proteção divina. Não entra em contato com e-mail. Não abre agenda. Vive. Pessoas esquecem.', 'Sete dias iguais é escravidão com salário.', '@neemias.barros'),
('09-04', 9, 4, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Tu, Senhor.', 'Atos 1:24', 'Qual decisão tu tá prestes a tomar — sem consultar Deus com o devido peso?', 'Discípulos sortearam sobre Matias depois de oração pública e séria. Tu? Decide grande sem oração longa. Anuncia, depois ora. Escolhe sozinho, depois avisa família. Inverte. Importante é o reverso: primeiro ora. Depois decide. Depois anuncia. Ordem tira ansiedade. Dá peso. Deus merece consulta — e gosta de ser consultado antes.', 'Decisão sem oração longa é tiro com olhos fechados.', '@samuelqueiroga'),
('09-05', 9, 5, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'O mundo passa.', '1 João 2:17', 'Em que tu tá investindo há anos — que passa em 5?', 'João: o mundo passa. Carreira passa. Dinheiro passa. Beleza passa. Curso passa. Cargo passa. Tu investe a vida inteira no que passa. Pouco no que fica. Alma tua fica. Alma teu filho fica. Palavra de Deus fica. Discipulado fica. Gesto de amor fica. Reequilibra agenda. Semana típica: quantas horas no passageiro, quantas no eterno? Vergonhoso, né? Ajusta.', 'Investir no passageiro é perder 100% na eternidade.', '@benjamim.paiva'),
('09-06', 9, 6, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Glória se retirou.', 'Ezequiel 11:23', 'Em que fase tua vida espiritual a glória se retirou — e tu continuou vivendo como se ainda estivesse?', 'Ezequiel viu a glória de Deus se retirar do templo. Templo continuava fisicamente. Mas vazio. Tu tem áreas assim. Igreja que frequenta por hábito — glória saiu? Casamento que continua por logística — glória saiu? Rotina espiritual tua — glória saiu? Reconhece. Terrível. Humilha. Pede volta. Deus pode voltar se tu reconhecer a vacância. Disfarce não reverte.', 'Glória retirada sem reconhecimento vira rotina morta.', '@ezequielferraz');
INSERT INTO public.provocacoes (dia_ano, mes, dia, autor_slug, autor_dia, autor_numero, citacao, autor_citacao, pergunta, texto, aspas_autor, instagram) VALUES
('09-07', 9, 7, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Exortando e consolando.', '1 Tessalonicenses 2:11', 'Tu é pai de verdade — exorta E console — ou só faz uma coisa?', 'Paulo: como pai com filhos — exortando E consolando. Dois verbos. Tu faz um. Tu é ''pai duro'' só — só corrige. Ou ''pai mole'' só — só abraça. Deus pai faz os dois. Disciplina sem afeto é terror. Afeto sem disciplina é moleza. Equilíbrio custa — mas é o caminho. Hoje: se tu é duro, abraça teu filho. Se tu é mole, corrige algo específico. Pai completo forma filho sólido.', 'Pai incompleto forma filho quebrado.', '@jonataspellegrino'),
('09-08', 9, 8, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Inteiramente.', 'Números 14:24', 'Que área de vida Deus pede integralidade — e tu dá só uma parte?', 'De novo Caleb — inteiro. Insisto. É raro. Deus não vai repartir contigo só o que tu entregou inteiro. Entrega parcial = benção parcial. Casamento inteiro = frutos inteiros. Negócio inteiro = colheita inteira. Ministério inteiro = unção inteira. Descobre tua área amputada. Entrega. Se dói, dói. Maior dor é descobrir em velhice o quanto perdeu por 30% de economia.', 'Integralidade é o investimento que entrega dividendos eternos.', '@caleb.montenegro'),
('09-09', 9, 9, 'josue-caetano', 'Josué Caetano', '71.204', 'Os deuses que serviram os vossos pais.', 'Josué 24:14', 'Qual idolatria da tua família de origem você ainda pratica sem perceber?', 'Josué: jogue fora os deuses dos pais. Tu herdou idolatria sem rotular. Culto ao sucesso. Culto à aparência. Culto ao medo. Culto à conformidade. Teu pai fazia. Tu faz. Transmite pro filho. Ciclo. Nomeia. Joga fora. Geração tua pode ser a que quebrou. Discipula tua família — ex-paganismo cristianizado deita raiz profunda.', 'Idolatria de pais vira normal — até alguém chamar de pecado.', '@josue.caetano'),
('09-10', 9, 10, 'davi-valverde', 'Davi Valverde', '71.337', 'Clamarei ao Senhor.', 'Salmo 120:1', 'Em quem tu clama primeiro — Deus ou pessoa?', 'Davi: clamarei ao Senhor. Primeiro. Tu? Clama na esposa. No grupo. No terapeuta. No conselho de amigo. Depois, quando esgotou humano, lembra Deus. Ordem invertida. Deus primeiro. Humano depois. Não inverte. Tu perde paz. Deus ouve antes do que humano escuta. Humano vai ajudar depois — mas Deus orquestra.', 'Clamor primeiro a humano é desconfiança do Pai.', '@davi.valverde'),
('09-11', 9, 11, 'elias-dovale', 'Elias do Vale', '71.418', 'O que escreves?', 'Jeremias 36:17', 'Tu deveria estar escrevendo — e não tá?', 'Rei perguntou Baruque: como escreves? Perguntou sério. Tu? Tem o que escrever e tá calado. Livro engavetado. Testemunho não publicado. Experiência não compartilhada. Palavra que Deus deu específica. Escrever é multiplicar. Tempo tu tem. Desculpa: não sou escritor. Nem Jeremias era. Era profeta com Baruque escrevendo. Tu tem celular. Escreve 200 palavras hoje. Post ou documento. Multiplica.', 'Palavra não escrita morre com o dono. Escrita vira legado.', '@elias.dovale'),
('09-12', 9, 12, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Porão sobre a porta.', 'Ezequiel 9:4', 'Qual marca identifica tua casa pra o anjo — ou não tem nada?', 'Deus mandou marcar a porta dos que oravam contra a apostasia de Israel. Anjo passou poupando quem tinha marca. Tua casa tem marca? Marca de oração regular. De discipulado. De generosidade. De santidade visível. Marca sutil ao mundo, óbvia a Deus. Tu quer que o anjo passe poupando? Marca hoje. Não com símbolo — com hábito real.', 'Casa sem marca não é distinta da ruína coletiva.', '@gideao.sampaio'),
('09-13', 9, 13, 'neemias-barros', 'Neemias Barros', '71.612', 'Deixemos essa ocupação.', 'Neemias 6:3', 'Quem tá te oferecendo ''reunião importante'' — pra te tirar da obra?', 'Sambalate chamou Neemias 4 vezes pra descer e ''conversar''. Neemias recusou: a obra é grande, não posso. Tu? Cai em toda distração chamada ''importante''. Reunião sem pauta. Conversa sem fim. Grupo de whatsapp. Serve café, pelos dois. Em nome de networking. Descemos da obra. Foca. Nem todo convite é chamado — a maioria é distração vestida de oportunidade.', 'Distração vestida de oportunidade é armadilha mais eficaz.', '@neemias.barros'),
('09-14', 9, 14, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Casa de meu pai.', 'Lucas 2:49', 'Onde é a ''casa do Pai'' pra ti hoje — e quando foi a última vez que tu esteve lá voluntariamente?', 'Jesus aos 12: não sabíeis que tenho que estar na casa do meu Pai? Tu? Vai à casa do Pai (igreja, oração, Palavra) por hábito, por obrigação, por culpa. Não por ter que estar. Jesus queria estar. Tua vontade, de verdade, é estar? Se não, examina. Quando fé vira obrigação, é sinal de distância interior. Reconcilia — não com performance, com intimidade.', 'Quem vai à casa do Pai por obrigação não fica íntimo.', '@samuelqueiroga'),
('09-15', 9, 15, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Eis o homem.', 'João 19:5', 'Quando Pilatos mostrou Jesus ferido — tu teria reconhecido Rei ou visto derrotado?', 'Pilatos: eis o homem. Jesus coroado espinhos, cuspido, apanhado. Discípulos fugiram. Reconhecer Rei ali era fé. Tu? Reconhece Rei em sofrimento? Ou só em vitória? Em irmão caído, tu enxerga Cristo sendo moldado? Em tua própria crise, Rei invisível tá agindo? Perceber Deus nos momentos feios é escola rara. Legendário treina.', 'Reconhecer Cristo no sofrimento é olho treinado. Outros veem só derrota.', '@benjamim.paiva'),
('09-16', 9, 16, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Nenhum outro cuidará.', 'Jeremias 23:4', 'Qual rebanho Deus te deu — e tu tá terceirizando pra qualquer um cuidar?', 'Deus: darei pastores que cuidarão. Pastoreio é chamado sério. Tu tem rebanho (filho, discípulo, equipe, comunidade). Tu cuida, de verdade? Conhece nome por nome? Ora pelo específico? Chama quando some? Ou terceiriza pra escola, pra igreja, pra sistema? Rebanho tua responsabilidade. Legendário pastoreia com intenção — não por hábito.', 'Pastoreio terceirizado é rebanho abandonado com marketing.', '@ezequielferraz'),
('09-17', 9, 17, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Vosso coração se detenha.', 'Atos 2:46', 'Quantos irmãos te receberam em casa nesse mês?', 'Primeira igreja: partiam pão de casa em casa. Comunhão simples. Tu? Só vê irmão no culto. Igreja virou evento. Perdeu casa. Amizade cristã se forma na mesa — não na fileira. Convida três irmãos pra comer casa. Sem pauta. Sem pregação forçada. Só estar. Igreja viva é a que come junta. Legendário abre casa.', 'Igreja que só se encontra em prédio não é igreja — é auditório.', '@jonataspellegrino'),
('09-18', 9, 18, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Cânticos na noite.', 'Jó 35:10', 'Qual canção tu canta quando tudo desaba?', 'Eliú em Jó: Deus dá cânticos na noite. Tu? Quando desaba, fica em silêncio tóxico. Depressão, ruminação. Legendário canta. Não finge alegria — canta declaração. ''Grande é o Senhor''. ''Tu és fiel''. ''Tu és bom''. Canto na noite é fé em ação. Cantar altera química interna. Tenta. Na próxima crise: canta antes de resolver. Canta no meio. Saída é canto acompanhando luta — não substituindo.', 'Canto na noite é fé traduzida em voz.', '@caleb.montenegro'),
('09-19', 9, 19, 'josue-caetano', 'Josué Caetano', '71.204', 'Vai e traze-os.', '1 Samuel 9:13', 'Quem precisa ser buscado por ti — literalmente?', 'Povo buscou Saul escondido. Tu? Tem gente precisando ser buscada. Filho que se afastou. Amigo que sumiu. Irmão da igreja que faltou. ''Ele sabe o caminho''. Pode saber — mas às vezes quem recua, precisa que vá e traga. Orgulho diz ''deixa ele vir''. Amor diz ''vai busca-lo''. Diferença de postura muda relação. Hoje: nome. Liga, pergunta, convida. Ou visita.', 'Orgulho separa. Iniciativa de buscar resgata.', '@josue.caetano'),
('09-20', 9, 20, 'davi-valverde', 'Davi Valverde', '71.337', 'Restituirás em sete dobras.', 'Provérbios 6:31', 'O que tu roubou — mesmo que simbólico — e ainda não restituiu?', 'Salomão: ladrão pago restitui sete vezes. Tu roubou. Tempo da empresa usando pra redes pessoais. Fama de outro tomando crédito. Paz de esposa com grito vazio. Atenção de filho trocada por celular. Pequenos roubos. Restitui. Horas extras sem cobrar. Elogio público pro colega. Tempo puro com esposa. Presença total com filho. Sete vezes. Restituição limpa consciência e abre cá futuro.', 'Ladrão que não restitui fica preso em consciência.', '@davi.valverde'),
('09-21', 9, 21, 'elias-dovale', 'Elias do Vale', '71.418', 'Não serás envergonhado.', 'Isaías 54:4', 'Que vergonha passada Deus já apagou — e tu continua carregando como tatuagem?', 'Isaías promete: não serás envergonhada. Tempo passado. Tu? Ainda carrega. Vergonha de faliu. Vergonha de foi traído. Vergonha de caiu no vício. Deus apagou — pelo sangue. Tu mantém por orgulho invertido (sim, autopunição é orgulho). Larga. Legendário não exibe cicatriz pra chamar atenção. Usa pra testemunhar cura. Diferença é postura.', 'Vergonha carregada é orgulho pelo contrário.', '@elias.dovale'),
('09-22', 9, 22, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Ajuntou Gideão.', 'Juízes 7:1', 'Quantas pessoas tu consegue reunir pra um propósito — não pra festa?', 'Gideão ajuntou 32 mil. Líder junta. Pra propósito. Tu junta pra festa, pra jantar, pra lazer. Ótimo. E pra propósito? Oração coletiva, jejum, voluntariado, evangelismo? Reúne? Ou só participa do que outros organizam? Líder ajunta. Começa. Convida 5 pra oração hoje. Se 2 vierem, suficiente. Legendário inicia coletividade de propósito.', 'Quem não convoca pra propósito não é líder. É participante social.', '@gideao.sampaio'),
('09-23', 9, 23, 'neemias-barros', 'Neemias Barros', '71.612', 'Levantei-me pela manhã.', 'Neemias 2:13', 'Qual hábito matinal tá te destruindo — que tu chama de ritual?', 'Neemias levantou cedo pra examinar muros. Manhã estratégica. Tu? Levanta mal. Celular, notícia, coffee, pressa. Ritual matutino forma dia. Ajusta. Hoje: 15 minutos pela manhã. Sem celular. Água, Palavra, oração curta. Experimenta uma semana. Diferença é drástica. Manhãs moldam tudo. Manhã roubada por tela: dia todo sequestrado.', 'Manhã roubada = dia todo em déficit.', '@neemias.barros'),
('09-24', 9, 24, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Não tem parte nem sorte.', 'Atos 8:21', 'Qual motivo oculto do teu trabalho espiritual — que Pedro chamaria de comprar dom?', 'Simão Mago quis comprar o Espírito. Pedro fulminou. Tu? Tua motivação de servir é limpa? Ou busca aprovação? Posição? Visibilidade? Comprar influência com serviço? Pergunta dura — não é auto-condenação. É auto-exame. Sem exame, motivação suja contamina serviço. Ora: ''Pai, purifica motivo. Que eu sirva por Ti só''. Só Ele pode limpar a fonte.', 'Serviço limpo nasce de motivo limpo.', '@samuelqueiroga'),
('09-25', 9, 25, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Tornaste, pois.', 'Deuteronômio 23:5', 'Qual maldição pronunciada contra ti Deus virou benção — que tu ainda chora como derrota?', 'Balaão tentou amaldiçoar Israel. Deus virou benção. Tu? Evento que parecia maldição — demissão, divórcio, falência, traição — Deus pode estar virando benção. Tu não enxerga ainda. Chora como derrota. Abre olhos. O quê Deus tá pondo de bom no que parecia fim? Tempo livre? Clareza? Proximidade com ele? Legendário enxerga transmutação onde os outros enxergam ruína.', 'Maldição entregue vira benção no tempo de Deus.', '@benjamim.paiva'),
('09-26', 9, 26, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Sobre pés.', 'Ezequiel 37:10', 'Tu tá em pé ou ainda deitado com a desculpa de ''Deus tá trabalhando''?', 'Ezequiel profetizou e os ossos se levantaram — em pé. Tu? Deita no sofá. Reclama. Espera. ''Deus tá trabalhando'', diz tu. Pode estar. Mas Deus age com cooperação. Profetiza se colocando em pé. Levanta fisicamente. Sai. Age. Fé passiva é indolência cristianizada. Ossos se levantaram porque a palavra foi falada — e eles obedeceram.', 'Fé passiva permanece deitada. Fé ativa levanta em pé.', '@ezequielferraz'),
('09-27', 9, 27, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Ligou-se.', '1 Samuel 18:1', 'Tua alma tá ligada a quem fortalece tua fé — ou a quem drena?', 'Jônatas ligou alma a Davi. Escolha consciente de aliança. Tu? Ligou sua alma a quem? Parceiro de negócio? Ex que não largou emocionalmente? Grupo que te leva pra baixo? Amigo fofoqueiro? Alma liga. Tira energia. Liga só a quem fortalece. Desliga o resto. Ligação alma precisa consentimento mas também precisa curadoria.', 'Alma ligada a alma fraca vira fraqueza em dobro.', '@jonataspellegrino'),
('09-28', 9, 28, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Esquadrinha a terra.', 'Josué 18:4', 'Antes de decidir, tu esquadrinhou — ou só reagiu?', 'Josué mandou três homens por tribo esquadrinhar a terra antes de dividir. Esquadrinhar = investigar. Tu decide sem esquadrinhar. Compra impulsivo. Casa com pouca pesquisa. Sócio por carisma. Mentor por moda. Legendário esquadrinha. Pergunta, consulta, observa, ora. Decisão rápida emocional colhe arrependimento longo. Decisão esquadrinhada colhe descanso.', 'Decisão sem investigação é tempo emprestado pra arrependimento.', '@caleb.montenegro'),
('09-29', 9, 29, 'josue-caetano', 'Josué Caetano', '71.204', 'De continho.', 'Deuteronômio 6:7', 'Com que frequência tu ensina teu filho sobre Deus — não em ocasião especial, no dia a dia?', 'Deus mandou: falarás destas palavras quando levantar, quando deitar, quando andar. Continuo. Tu ensina teu filho em formalidade. Oração na mesa, tchau no carro pra escola. Esporádico. Errado. É no meio de uma caminhada que pergunta sobre estrela. No trânsito que explica perdão. Deitando que ora Pai Nosso. Contínuo. Discipulado por osmose — não por palestra.', 'Discipulado é sombra longa. Palestra é momento breve.', '@josue.caetano'),
('09-30', 9, 30, 'davi-valverde', 'Davi Valverde', '71.337', 'Confiei na tua benignidade.', 'Salmo 13:5', 'Tu confia na benignidade de Deus — ou no teu próprio esforço pra merecer?', 'Davi confessou: confio na Tua benignidade. Não no próprio mérito. Tu confia no quê? Tua obediência? Teu serviço? Teu dízimo? Seu trabalho espiritual? Ou na bondade Dele? Ordem é: Ele é bom primeiro — daí tu responde com obediência. Se tu inverte, vira legalismo. Não produz paz. Relaxa. Ele é bom. Vai continuar sendo. Independente do teu esforço hoje.', 'Mérito próprio é fundação de areia. Benignidade divina é rocha.', '@davi.valverde'),
('10-01', 10, 1, 'elias-dovale', 'Elias do Vale', '71.418', 'Pelejai pelo povo.', 'Neemias 4:14', 'Por quem tu peleja hoje — ou só defende a ti mesmo?', 'Neemias exortou: pelejai pelos vossos irmãos. Tu peleja só pelo teu CPF. Teu negócio. Tua família. E irmão que tá apanhando fora? Ignora. Legendário peleja pelo próximo. Intercede. Defende. Protege. Não é messianismo — é pertencimento. Hoje escolhe um irmão em crise e briga espiritualmente com ele. Oração, gesto, presença.', 'Cristão que só briga por si, não briga pelo Reino.', '@elias.dovale'),
('10-02', 10, 2, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Deus vos entregou.', 'Juízes 7:15', 'Qual batalha tua tá meio dia longe — mas no espiritual já foi ganha?', 'Gideão soube pelo sonho do midianita: Deus já entregou. Batalhas espirituais se ganham antes do campo. Tu ora, Deus entrega no invisível. Tu luta, resolve no visível. Ordem: oração primeiro, ação segunda. Hoje a batalha específica tua — já foi ganha no joelho ou tá sendo perdida no suor?', 'Batalha perdida no joelho é perdida no campo também.', '@gideao.sampaio'),
('10-03', 10, 3, 'neemias-barros', 'Neemias Barros', '71.612', 'Atentava pela obra.', 'Neemias 5:16', 'Quantas horas de fato tu investe na obra central — versus em fogo periférico?', 'Neemias foco. Atentava pela obra central. Tu? Atento em tudo menos no principal. Gasta dia em reunião periférica, email vazio, chat irrelevante. Chamado principal fica no fim do dia. Cansado. Reorganiza. Manhã: obra central. Tarde: periferia. Legendário defende horário nobre do chamado maior.', 'Obra central no horário medíocre entrega resultado medíocre.', '@neemias.barros'),
('10-04', 10, 4, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Filho, honra a teu pai.', 'Êxodo 20:12', 'Qual honra tu deve ao pai vivo que tá faltando?', 'Mandamento com promessa. Pai vivo ainda tá aí? Quando tu ligou? Visitou? Honrou publicamente? Não espera reconciliação perfeita — honra mesmo imperfeito. Pai humano é imagem de Pai Celeste — reconciliação com o visível abre porta pra invisível. Hoje: ligação ou mensagem real.', 'Honra pai vivo. Depois de morto vira saudade culpada.', '@samuelqueiroga'),
('10-05', 10, 5, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Tudo posso.', 'Filipenses 4:13', 'Tu usa ''tudo posso'' pra se vangloriar — ou pra arriscar obediência impossível?', 'Paulo: tudo posso no que me fortalece. Contexto era pobreza extrema. Tu? Usa como mantra de carreira. Errado. Tudo posso pra OBEDECER o impossível — perdoar, confessar, mudar, arriscar pelo Reino. Não pra lucrar mais. Recoloca o verso no contexto. Usa pra obedecer pesado, não pra vender melhor.', 'Descontextualizar versículo é manipular Deus.', '@benjamim.paiva'),
('10-06', 10, 6, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Despertem os valentes.', 'Joel 3:9', 'Que valente em ti tá dormindo — enquanto tu vive como covarde social?', 'Joel convoca valentes. Tu tem valente dentro. Deus criou. Dorme porque tu virou socialmente cauteloso. Fala pouco. Cede demais. Pula briga certa. Valente desperta pela Palavra, pela oração, pela convicção. Hoje acorda. Uma atitude corajosa específica. Só uma. Valente acordado é o primeiro passo.', 'Valente dormindo é covarde com histórico.', '@ezequielferraz'),
('10-07', 10, 7, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Amai uns aos outros.', '1 Pedro 1:22', 'Teu amor fraternal é ativo — ou só tolerância educada?', 'Pedro: amai ardentemente. Arder. Tu só tolera irmão. Convive frio. Sem intensidade. Amor cristão é ativo — serve, sacrifica, suporta, celebra. Frieza fraternal é pecado silencioso. Aquece a relação com um irmão específico essa semana. Gesto, palavra, presença intencional.', 'Tolerar irmão não é amar. É conviver sem amor.', '@jonataspellegrino'),
('10-08', 10, 8, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Até hoje.', 'Josué 14:11', 'Que capacidade tua de 20 anos atrás ainda tá ativa — mas parou de ser usada?', 'Caleb com 85 disse: estou tão forte. Tu aos 40, 50, 60 — ''já não sou mais''. Mentira. Capacidades não se perdem por idade sozinha; se perdem por desuso. Voltar a pregar, a escrever, a correr, a aprender idioma, a discipular. O que parou por desculpa etária? Retoma.', 'Desuso mata capacidade mais rápido que envelhecimento.', '@caleb.montenegro'),
('10-09', 10, 9, 'josue-caetano', 'Josué Caetano', '71.204', 'Cada um em seu lugar.', 'Juízes 7:21', 'Qual é teu lugar no exército de Deus — que tu ainda anda procurando fora?', 'Os 300 ficaram CADA UM EM SEU LUGAR. Disciplina de posição. Tu? Envia aplicação pra toda vaga. Participa de todo projeto. Se oferece pra tudo. Dispersão. Lugar específico teu existe. Oração e experiência revelam. Reduz. Aprofunda.', 'Tomar todo posto é não tomar posto nenhum.', '@josue.caetano'),
('10-10', 10, 10, 'davi-valverde', 'Davi Valverde', '71.337', 'Bom é render graças.', 'Salmo 92:1', 'Tu agradece só quando vem bênção grande — ou no meio do trabalho comum?', 'Salmo 92 começa com gratidão rotineira. Tu agradece em raras ocasiões grandiosas. Erro. Gratidão pelo dia comum, café comum, trabalho comum, esposa comum forma alma resistente. Grande pode não vir. Pequeno, sim. Gratidão sobre pequeno é fundação. Hoje, agradece 5 coisas específicas antes de dormir.', 'Gratidão pelo pequeno é defesa contra amargura futura.', '@davi.valverde'),
('10-11', 10, 11, 'elias-dovale', 'Elias do Vale', '71.418', 'Quebrantados.', 'Isaías 57:15', 'Tu tá tentando aparecer inteiro — quando Deus habita com quebrantados?', 'Deus habita com alto E com quebrantado. Escolha: posar inteiro ou admitir quebra. Posar te mantém sozinho. Admitir aproxima Deus. Vergonha social tá mais te matando que a quebra real. Confessa quebra real a Deus. A 1-3 pessoas íntimas. Legendário não tem pose. Tem cicatriz.', 'Pose de inteiro mata intimidade divina.', '@elias.dovale'),
('10-12', 10, 12, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Subiu fumo.', 'Juízes 20:40', 'Que sinal claro Deus tá te dando — que tu tá ignorando pra seguir plano teu?', 'Em Juízes 20, o sinal do fumo subindo confirmou. Deus dá sinal claro — tu ignora. Porta fechando 3 vezes é sinal. Pessoa que concorda sem enxergar é sinal. Paz que vaza é sinal. Obedece o óbvio. Deus não vai repetir infinito. Legendário reconhece sinal pela terceira vez, não espera a décima.', 'Ignorar sinais claros é dar convite à consequência.', '@gideao.sampaio'),
('10-13', 10, 13, 'neemias-barros', 'Neemias Barros', '71.612', 'Alegria do Senhor.', 'Neemias 8:10', 'Qual alegria do Senhor tá alimentando tua força — ou tu usa outro combustível?', 'Neemias: alegria do Senhor é força. Tu usa medo como combustível. Ou raiva. Ou vergonha. Funciona curto prazo, destrói no longo. Alegria é fonte sustentável. Cultiva: louvor, família, risada, fé exercitada. Força de motor errado quebra a máquina.', 'Combustível errado carburou te leva à oficina.', '@neemias.barros'),
('10-14', 10, 14, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Orarei ao Senhor.', '1 Samuel 12:23', 'Quando tu parou de orar pelo outro — por mágoa, cansaço, desistência?', 'Samuel disse: longe esteja de mim deixar de orar por vós. Mesmo quando o povo errou. Tu? Parou de orar pelos que te machucaram. Defendável? Só humanamente. Biblicamente, não. Intercessão pelo inimigo é ordem. Hoje: ora pelo que mais te machucou. Não pelos bons desejos — pela salvação dele.', 'Parar de orar pelo próximo é dispensar função sacerdotal.', '@samuelqueiroga'),
('10-15', 10, 15, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Corra para o alvo.', 'Filipenses 3:14', 'Tu ainda tem um ALVO — ou só tem lista de to-do?', 'Paulo corria pro alvo. Alvo único. Tu? Lista dispersa, 20 prioridades, nenhuma central. Sem alvo central, corrida é circular. Escolhe alvo primário pra fase de vida atual. Formar filho, terminar livro, plantar igreja, quitar dívida. Um. Resto é caminho.', 'Sem alvo, correr mais cansa sem chegar.', '@benjamim.paiva'),
('10-16', 10, 16, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Levaram a tua iniquidade.', 'Ezequiel 4:5', 'Qual pecado coletivo Deus tá pedindo tu carregar em intercessão?', 'Ezequiel deitou dias levando a iniquidade de Israel. Intercessão carrega peso. Tu ora superficial. Carregar pecado do grupo, da cidade, do país é intercessão séria. Legendário carrega em oração o que ninguém quer carregar — pornografia nacional, falência familiar, confusão geracional. Entra no clima.', 'Intercessão rasa ecoa. Carregada, abre céu.', '@ezequielferraz'),
('10-17', 10, 17, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Abraçou-se ao pescoço.', 'Lucas 15:20', 'Quem tu precisa receber como Pai recebe Prodígio — sem sermão prévio?', 'Pai não repreendeu na volta. Abraçou primeiro. Tu? Quando filho volta, ex-esposa volta, irmão volta, amigo volta — tu cobra conta antes. Recebe com abraço primeiro. Conversa depois. Muitas vezes conversa nem é necessária — abraço fala mais. Deus te recebeu assim. Repassa.', 'Abraço precede sermão. Inverter é crueldade religiosa.', '@jonataspellegrino'),
('10-18', 10, 18, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Vinte e cinco anos.', 'Deuteronômio 1:46', 'Quantos anos tu demorou num lugar que era pra ser passagem?', 'Israel demorou muito em Cades. Tu tá há anos em lugar que devia ser passagem. Emprego temporário virou 15 anos. Namoro sem rumo virou 7 anos. Igreja que deveria ser escola virou vida inteira. Saí. Nem tudo merece permanência. Alguns lugares são só estação.', 'Estação que virou destino é cadeia bonita.', '@caleb.montenegro'),
('10-19', 10, 19, 'josue-caetano', 'Josué Caetano', '71.204', 'Passaram a ordem.', 'Josué 1:11', 'Quais ordens tu tá dando à tua tropa — ou ainda espera que ela adivinhe?', 'Josué passou ordem clara aos oficiais. Liderança comunica. Tu espera família adivinhar visão. Espera equipe ler pensamento. Comunica claro. Escreve visão. Repete. Oficiais precisam saber destino. Tropa só segue quem diz pra onde vai.', 'Líder que não comunica visão lidera pra onde ninguém quer ir.', '@josue.caetano'),
('10-20', 10, 20, 'davi-valverde', 'Davi Valverde', '71.337', 'Quem há no céu senão tu?', 'Salmo 73:25', 'Deus é teu fim último — ou Ele é instrumental pra outras coisas?', 'Asafe: quem no céu senão Tu? Deus é o fim. Tu usa Deus: pra paz, pra saúde, pra prosperidade, pra família. Ele dá — mas Ele mesmo é o prêmio. Cuidado com fé utilitária. Mesmo sem benção, Ele basta? Essa pergunta reorienta toda relação.', 'Deus como meio é redução. Como fim, é salvação.', '@davi.valverde'),
('10-21', 10, 21, 'elias-dovale', 'Elias do Vale', '71.418', 'Ah, Senhor Deus.', '1 Reis 17:20', 'Tu tá com coragem de reclamar com Deus — ou acha errado sentir?', 'Elias reclamou: ''por que mataste o filho dessa mulher?'' Não foi punido. Intimidade permite franqueza. Tu reprime emoção com Deus. Finge conformidade. Deus prefere honestidade bruta. Reclamação orada é oração. Salmos tem 1/3 de lamento. Tu omite. Fala sincero.', 'Omitir raiva com Deus é fingir fé.', '@elias.dovale'),
('10-22', 10, 22, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Três companhias.', 'Juízes 7:16', 'Qual abordagem multi-frente tu tá precisando — em vez de ataque único?', 'Gideão dividiu 300 em 3 companhias. Tática inteligente. Tu ataca problema de uma frente só — e fracassa. Problema complexo exige abordagem múltipla. Vício: oração + terapia + accountability. Negócio: produto + marketing + operação. Tecno-spiritual — não é terceirização, é estratégia.', 'Ataque único a problema complexo falha por natureza.', '@gideao.sampaio'),
('10-23', 10, 23, 'neemias-barros', 'Neemias Barros', '71.612', 'Volte, nós contamos.', 'Neemias 7:5', 'O que precisa ser contado na tua vida — número, fato, inventário — que tu tá evitando?', 'Neemias contou o povo. Números, listas, fatos. Tu foge. Conta dívidas, tá com medo. Conta visitas a filho, tá envergonhado. Conta orações, tá com vergonha. Conta horas de tela, tá com susto. Conta. Realidade esclarece. Plano só vem depois de diagnóstico numérico.', 'Quem não conta, não gerencia. Quem não gerencia, perde.', '@neemias.barros'),
('10-24', 10, 24, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Envelheci.', '1 Samuel 12:2', 'Qual transição de liderança tu precisa fazer — passando bastão antes de cair?', 'Samuel anunciou envelhecimento, passou bastão. Transição planejada. Tu? Segura posição até desabar. Nunca prepara sucessor. Ego ama indispensabilidade. Deus ama sucessão. Quem é teu Saul (ou Davi) em formação? Investe. Cai bem quem preparou substituto.', 'Não preparar sucessor é auto-idolatria lenta.', '@samuelqueiroga'),
('10-25', 10, 25, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Olhai para as aves.', 'Mateus 6:26', 'Qual preocupação com amanhã tá te roubando hoje?', 'Jesus: olhem pras aves. Não semeiam, não colhem, Deus sustenta. Tu preocupa com amanhã e perde hoje. Ansiedade religiosa — fé teórica. Se Deus cuida de pardal, cuida de ti. Vive o dia. Planeja sem se desesperar. Diferença sutil mas vital.', 'Preocupação sobre amanhã rouba o hoje duas vezes.', '@benjamim.paiva'),
('10-26', 10, 26, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Teu olho.', 'Ezequiel 24:16', 'Qual ''desejo dos teus olhos'' Deus tá tocando — e tu tá desabando?', 'Ezequiel perdeu a esposa — ''desejo dos olhos''. Deus usou. Tu? Perde algo central e culpa Deus. Às vezes Deus retira. Dói, mas é metodologia. Aceita com reverência. Não paraliza. Continua profetizando. Luto é pontual; missão é permanente.', 'Luto não suspende o chamado. Vai junto.', '@ezequielferraz');
INSERT INTO public.provocacoes (dia_ano, mes, dia, autor_slug, autor_dia, autor_numero, citacao, autor_citacao, pergunta, texto, aspas_autor, instagram) VALUES
('10-27', 10, 27, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Pela manhã.', 'Salmo 30:5', 'Qual choro teu da noite Deus já prometeu virar alegria — e tu não acredita?', 'Salmo: lamento de noite, alegria de manhã. Profecia em andamento. Tu chora e acha eterno. Deus prometeu virar. Crê. Não só intelectualmente. Espera. Luto tem prazo — não infinito. Manhã vem. Confia.', 'Desespero é incredulidade na manhã prometida.', '@jonataspellegrino'),
('10-28', 10, 28, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Se o Senhor for contigo.', 'Números 14:8', 'Tu tá tomando decisão supondo Deus com — ou fingindo que Ele tá automático?', 'Caleb: se o Senhor for contigo, a terra é boa. Condicional. Tu presume Deus automático em tudo. Quando decide, Ele tá? Quando casou, Ele tava? Quando mudou, pediu? Desobediência assumindo presença é caminho pra deserto. Pergunta primeiro.', 'Presumir presença é a nova idolatria sutil.', '@caleb.montenegro'),
('10-29', 10, 29, 'josue-caetano', 'Josué Caetano', '71.204', 'Dividi a terra em herança.', 'Josué 13:7', 'Como tu tá dividindo herança entre teus — ou deixa pra briga?', 'Josué dividiu antes de morrer. Testamento ativo. Tu? Deixa herança sem conversa, sem clareza, sem justiça visível. Filhos brigam depois. Escreve. Divide vivo. Conversa aberto. Transparência evita conflito. Especial — herança simbólica também (privilégios, atenção).', 'Herança sem clareza gera briga entre herdeiros.', '@josue.caetano'),
('10-30', 10, 30, 'davi-valverde', 'Davi Valverde', '71.337', 'Esquadrinha-me.', 'Salmo 139:23', 'Quando foi a última vez que tu pediu exame completo — e ouviu o relatório?', 'Davi pediu sondagem. Tu pede confirmação. Diferença enorme. Sondagem expõe. Confirmação ratifica. Pede sondagem. Ouve. Não se defende. Anota. Muda. Ciclo regular de sondagem (trimestral) evita decadência lenta.', 'Vida sem sondagem periódica enferruja sem perceber.', '@davi.valverde'),
('10-31', 10, 31, 'elias-dovale', 'Elias do Vale', '71.418', 'Vão o povo para suas casas.', 'Juízes 7:8', 'Quem tu deveria mandar descansar — e tá mantendo no front pra aliviar teu próprio peso?', 'Gideão dispensou 9700. Manteve 300. Tu? Mantém todos no front. Cansa esposa. Sobrecarrega filho. Explora funcionário. Porque delegar volta pra ti sozinho. Descansa gente. Assume peso. Legendário libera quem precisa descanso — mesmo que custe.', 'Manter todos acordados pra teu conforto é liderança doente.', '@elias.dovale'),
('11-01', 11, 1, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Tocai a trombeta.', 'Juízes 7:20', 'Qual sinal tu tá esperando dar — que se tu desse todos seguiriam?', '300 tocaram trombeta juntos. Sinal desperta. Tu tem sinal pra dar e segura. Início de movimento que só tu pode dar. Empresa começa contigo tocando. Ministério começa contigo. Casamento restaurado começa contigo. Não espera alguém tocar primeiro.', 'Todos esperam alguém começar. Tu tá esperando igual.', '@gideao.sampaio'),
('11-02', 11, 2, 'neemias-barros', 'Neemias Barros', '71.612', 'Plantaram vinhas.', 'Nehemiah 9:25', 'Qual fruto tu tá plantando hoje — que tu não verá em 20 anos?', 'Israel plantou vinhas em Canaã. Frutos de vinha demoram. Tu quer rápido. Planta vinha: discipulado de filho, formação de jovem, construção lenta de negócio sólido. Geração tua talvez não veja colheita completa. Planta.', 'Quem só planta safra rápida morre sem sombra.', '@neemias.barros'),
('11-03', 11, 3, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Não vos apartes.', 'Atos 1:4', 'Qual ''espera santa'' tu tá pulando por ansiedade de agir?', 'Jesus: não partam, esperem o Espírito. Espera ordenada. Tu pula. Age antes da unção. Inicia ministério antes do preparo. Empreende antes do chamado claro. Casa sem escolher direito. Às vezes esperar é obediência maior. Legendário espera quando tem que esperar.', 'Ação antes da espera santa é iniciativa carnal.', '@samuelqueiroga'),
('11-04', 11, 4, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Despojado.', 'Hebreus 12:1', 'Qual peso específico tá te roubando velocidade — que tu ainda defende como útil?', 'Hebreus: despojai todo peso E o pecado que vos rodeia. Dois níveis: pecado e peso (coisa boa em excesso). Peso vai ao diabo mesmo sendo legítimo. Muitos amigos. Muitos compromissos. Muitas oportunidades. Despoja. Corrida é longa — só mínimo necessário passa rápido.', 'Nem todo peso é pecado. Mas todo excesso é lento.', '@benjamim.paiva'),
('11-05', 11, 5, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Escrevi.', 'Ezequiel 43:11', 'O que Deus mandou tu escrever — e tá guardado na cabeça?', 'Deus mandou Ezequiel escrever a visão. Tu? Ouve palavra e guarda só na cabeça. Esquece. Escreve. Cria caderno de visão, livro de palavra, pasta de profecia pessoal. Escrito volta como testemunho. Esquecido vira dúvida depois.', 'Profecia não escrita vira dúvida reciclada.', '@ezequielferraz'),
('11-06', 11, 6, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Falou Jesus aos seus.', 'João 13:1', 'Qual palavra de despedida Deus tá te pedindo falar agora — pra alguém que ainda não morreu?', 'Jesus falou palavras finais antes de cruz. Tu? Guarda palavras pra depois. Pra quem? Funeral é tarde. Diz agora. Pai, esposa, filho, amigo. Diz o que tu diria no túmulo. Agora, vivo. Legendário fala antes de precisar.', 'Palavra guardada pra funeral é palavra perdida.', '@jonataspellegrino'),
('11-07', 11, 7, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Por teus descendentes.', 'Gênesis 22:18', 'Que promessa Deus deu pro teu descendente — que tu tá desperdiçando com vida pequena?', 'Abraão: por teus descendentes. Tu vive pequeno, descendente colhe pequeno. Tu cresce em fé, descendente herda terreno. Viver legendário não é só pra ti — é herança genética e espiritual. Filhos e netos herdam caminho trilhado. Cuida.', 'Quem vive pequeno condena descendente a começar do zero.', '@caleb.montenegro'),
('11-08', 11, 8, 'josue-caetano', 'Josué Caetano', '71.204', 'Fui valente.', 'Josué 14:7', 'Qual relatório tu pode dar hoje sem vergonha?', 'Caleb respondeu com relatório sincero. Tu? Relatório teu é cheio de desculpa. ''Tentei'', ''quase'', ''ia fazer''. Deus não colhe tentativas. Colhe entregues. Ajusta. Começa a gerar semanas reportáveis. Sem verniz.', 'Relatório de tentativa é fracasso com orgulho.', '@josue.caetano'),
('11-09', 11, 9, 'davi-valverde', 'Davi Valverde', '71.337', 'Sou pequeno e desprezível.', 'Salmo 119:141', 'Tu aceita ser pequeno na vista do mundo — se isso for fiel diante de Deus?', 'Davi disse: pequeno e desprezado — mas não esqueço preceitos. Quem escolhe fidelidade tem preço social. Tu aceita? Ou troca fidelidade por reconhecimento? Legendário paga preço pequeno na terra por tesouro eterno. Relembra — muitos grandes foram pequenos.', 'Grande na terra pequeno no céu. Inversão do reino.', '@davi.valverde'),
('11-10', 11, 10, 'elias-dovale', 'Elias do Vale', '71.418', 'Vai, volta.', '1 Reis 19:15', 'Qual passo simples Deus tá dizendo — que tu tá complicando?', 'Deus disse a Elias: vai, volta pelo deserto. Direção simples. Tu complica tudo. Quer estratégia elaborada. Obedece o simples. Vai. Volta. Faz. O próximo se revelará.', 'Simplicidade obediente tem mais poder que plano complexo.', '@elias.dovale'),
('11-11', 11, 11, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Segui-me.', 'Juízes 8:5', 'Tu tá convidando pessoas pra TE seguir — ou só se oferecendo pra seguir?', 'Gideão: segui-me. Autoridade em chamado. Tu tem autoridade pra chamar. Na tua área, no teu dom. Mas evita. Segue. Se oferece. Humildade é bom, mas também chama. Hoje, convide alguém específico pra seguir contigo em propósito definido.', 'Chamar precisa coragem. Ser chamado é fácil.', '@gideao.sampaio'),
('11-12', 11, 12, 'neemias-barros', 'Neemias Barros', '71.612', 'Dedicaram o muro.', 'Neemias 12:27', 'Que coisa concluída tu ainda não dedicou a Deus publicamente?', 'Muro acabou, Neemias dedicou. Celebração pública, consagrando a Deus. Tu? Conclui empresa, casa, curso e não dedica. Dedicar é reconhecer: Ele fez através de mim. Cerimônia simples — família, amigos, oração, agradecimento. Legendário consagra.', 'Coisa não dedicada vira orgulho particular.', '@neemias.barros'),
('11-13', 11, 13, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Vem e senta aqui.', 'Rute 4:1', 'Que negócio tu tá deixando aberto — sem testemunha nem palavra pública?', 'Boaz chamou anciãos como testemunha de transação. Tu faz negócio informal. Sem papel, sem testemunha. Depois briga. Formalize. Sociedade, divisão de herança, acordo, promessa. Escreve, assina, testemunhas. Isso é inteireza cristã, não frieza.', 'Informalidade barata cobra caro depois.', '@samuelqueiroga'),
('11-14', 11, 14, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Fervei de esperança.', 'Romanos 15:13', 'Tua esperança tá em Deus — ou em plano teu que depende dele dar certo?', 'Paulo: Deus da esperança. Não das circunstâncias. Tu coloca esperança no plano. Se plano desanda, desanda contigo. Coloca em Deus. Mesmo que plano quebre, esperança permanece. Diferença sutil, impacto enorme.', 'Esperança condicional é ansiedade disfarçada.', '@benjamim.paiva'),
('11-15', 11, 15, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Grito.', 'Ezequiel 9:8', 'Tem grito dentro de ti por injustiça — que tu tá calando por não atrapalhar?', 'Ezequiel gritou contra destruição. Profeta grita. Tu cala. Vê injustiça, segue vida. Tráfico humano, aborto, corrupção, opressão. Cala. Medo de atrapalhar. Grita. Vota, denuncia, levanta voz. Legendário grita quando quase ninguém quer ouvir.', 'Grito santo incomoda. Por isso quase ninguém grita.', '@ezequielferraz'),
('11-16', 11, 16, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Se dois dormirem juntos.', 'Eclesiastes 4:11', 'Tu tem alguém pra aquecer — ou dorme sozinho emocionalmente mesmo casado?', 'Pregador: dois se aquecem. Solidão emocional mesmo casado é real. Ora junto com esposa? Compartilha luta específica? Ouve sonho dela? Se não, dorme solitário ao lado de alguém. Aquece. Sentem pele não basta — aquece alma.', 'Casamento sem aquecer alma é divórcio adiado.', '@jonataspellegrino'),
('11-17', 11, 17, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Todo o caminho.', 'Deuteronômio 8:2', 'Tu lembra tudo que Deus te guiou — ou só reclama das dificuldades da caminhada?', 'Moisés: lembrai-vos de TODO caminho. Todo. Bom e ruim. Tu só lembra do ruim. Deserto seco é fácil citar. Maná diário é esquecido. Gratidão se treina lembrando tudo. Legendário faz memorial completo.', 'Memória seletiva gera ateísmo funcional.', '@caleb.montenegro'),
('11-18', 11, 18, 'josue-caetano', 'Josué Caetano', '71.204', 'Sois livres.', 'Josué 2:14', 'De que servidão tu saiu — mas ainda age como escravo?', 'Raabe saiu da servidão. Tu saiu do mundo — mas ainda age como dele. Mentalidade de escravo: medo, escassez, esconder-se, servilismo. Mentalidade de livre: confiança, abundância, transparência, dignidade. Renove mentalidade. Liberto é mudança de postura.', 'Liberto que age escravo voltou ao Egito mentalmente.', '@josue.caetano'),
('11-19', 11, 19, 'davi-valverde', 'Davi Valverde', '71.337', 'Saí e marchou.', '2 Samuel 11:1', 'Qual responsabilidade central tu abandonou — ficando em casa ocupado com menor coisa?', 'Quando reis saíam à guerra, Davi ficou em casa. Resultado: Bate-Seba. Abandono do chamado central abre brecha pra pecado específico. Tu fica em casa quando devia sair? Ou sai quando devia ficar? Chamado central importa. Abandono custa.', 'Abandono de chamado central é porta pra queda específica.', '@davi.valverde'),
('11-20', 11, 20, 'elias-dovale', 'Elias do Vale', '71.418', 'Arrependi-vos.', 'Atos 3:19', 'Qual arrependimento específico tá adiado — que Deus tá esperando?', 'Pedro: arrependei. Tu pede perdão genérico. Deus pede específico. Nomeia pecado. Confessa por nome. Confissão genérica é fuga. Reconheceu, vira. Não repete. Legendário arrepende específico. Não desce cortinas.', 'Arrependimento genérico é evasão com aparência de humildade.', '@elias.dovale'),
('11-21', 11, 21, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Abri e conversaram.', 'Lucas 24:32', 'Qual conversa com alguém te deu fogo — e tu ainda não buscou mais dessas?', 'Discípulos de Emaús: conversa com Jesus queimava peito. Tu tem conversas assim — raras. Depois esquece. Busca. Mais dessas conversas. Irmãos de profundidade, não só de bate-papo. Agenda tempo. Marca encontro. Queima o coração de novo.', 'Conversa rasa esfria alma. Profunda, queima.', '@gideao.sampaio'),
('11-22', 11, 22, 'neemias-barros', 'Neemias Barros', '71.612', 'Se fortalecerão.', 'Neemias 6:9', 'Em que momento tu precisa se fortalecer com oração — em vez de ceder cansaço?', 'Neemias orava: fortalece minhas mãos. Tu cansa, cede. Ele cansava, orava. Diferença. Toda vez que te dá vontade de largar, para 2 minutos, ora, volta. Fortalecimento em tempo real. Legendário não espera virar férias pra pedir força.', 'Força pedida no meio da luta é força usada.', '@neemias.barros'),
('11-23', 11, 23, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Meditarei.', 'Salmo 119:15', 'Quanto tempo tu medita na Palavra — ou só lê e passa?', 'Davi meditava. Não só lia. Pondera. Rumina. Tu lê rápido, devocional de 5 min, fechou. Sem meditação não forma. Uma ideia bíblica por dia, ruminada durante o dia. Mais poderoso que 10 capítulos lidos rápido. Legendário rumina.', 'Leitura sem meditação é consumo. Meditação forma.', '@samuelqueiroga'),
('11-24', 11, 24, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Pelejar boa peleja.', '1 Timóteo 6:12', 'Qual peleja boa tu tá pulando por achar que ''ninguém notaria se tu ficasse de fora''?', 'Paulo a Timóteo: peleja boa peleja. Algumas pelejas são tuas. Pula porque poderia. Batalha por filho, por esposa, por país, por igreja, por amigo. Deus pode usar outro? Sim. Mas chamou tu. Pula e perdes coroa. Aceita.', 'Pular peleja própria é entregar coroa.', '@benjamim.paiva'),
('11-25', 11, 25, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Caminho.', 'Ezequiel 20:30', 'Que caminho dos pais tu repetiu — sem nem perceber?', 'Ezequiel: andaste pelo caminho dos pais? Herança comportamental. Tu repete pai que não sabia. Ausência emocional. Raiva explosiva. Crítica constante. Silêncio congelante. Nem percebe. Identifica. Rompe ciclo. Legendário quebra herança ruim.', 'Herança ruim repetida é escolha — não destino.', '@ezequielferraz'),
('11-26', 11, 26, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Irmãos.', 'Salmo 133:1', 'Quando foi o último jantar só com irmãos em Cristo — sem família biológica?', 'Salmo 133: bom morar junto. Comunhão fraternal. Tu tem? Ou só vive com família de sangue. Família de Cristo se forma na mesa, no choro, na alegria. Crie laço. Agenda. Não é substituição — é complementação. Jesus teve.', 'Igreja sem intimidade fraternal é fileira de Netflix.', '@jonataspellegrino'),
('11-27', 11, 27, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Como nos dias da minha juventude.', 'Jó 29:4', 'O que de tua juventude espiritual tu perdeu — e pode recuperar?', 'Jó lembrou dos dias de glória. Tu? Perdeu zelo, fome, radicalidade. Aceita? Recupera. Unção não é idade — é intimidade. Reanima. Retiro pessoal, jejum longo, leitura pesada. Recupera o que esfriou.', 'Juventude espiritual pode retornar com rigor adulto.', '@caleb.montenegro'),
('11-28', 11, 28, 'josue-caetano', 'Josué Caetano', '71.204', 'A renhida guerra.', 'Josué 11:18', 'Qual renhida guerra tu tá esperando acabar em 2 semanas — que vai levar 2 anos?', 'Josué guerreou muito tempo. Não foi blitz. Tu quer resolver coisas profundas em prazo curto. Vício: 2 anos de processo. Casamento: anos de recomposição. Mudança de área: décadas. Aceita prazo longo. Escapa de expectativa irreal.', 'Expectativa curta em guerra longa gera desistência.', '@josue.caetano'),
('11-29', 11, 29, 'davi-valverde', 'Davi Valverde', '71.337', 'Ensina-me.', 'Salmo 25:4', 'Tu aceita ser ensinado — ou já tá cheio de respostas?', 'Davi: ensina-me. Postura de aprendiz. Tu? Virou expert em tudo. Conversa ensinando. Resiste a conselho. Ainda tem muito pra aprender. Legendário é eterno aprendiz. Oração: Pai, me ensina — de alguém que tu não espera.', 'Quem tá cheio de respostas perdeu a capacidade de aprender.', '@davi.valverde'),
('11-30', 11, 30, 'elias-dovale', 'Elias do Vale', '71.418', 'Passa.', '1 Reis 19:11', 'Qual passagem de Deus na tua vida tá vindo — e tu precisa só deixar passar sem querer prender?', 'Deus passou por Elias. Não ficou. Passou. Tu quer prender glória. Manter experiência. Repetir. Deus passa — tu muda. Não quer ficar no mesmo lugar. Sabedoria é saber quando reter e quando deixar passar.', 'Glória retida vira rotina. Glória passada transforma.', '@elias.dovale'),
('12-01', 12, 1, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Fumaça subiu.', 'Juízes 20:38', 'Qual sinal combinado Deus tá te dando em parceria com alguém — que tu não conecta?', 'Sinal por fumaça era combinado antes. Deus te deu sinais combinados com pessoas: oração com esposa, conselho de mentor, aviso de amigo. Tu ignora parte. Conecta. Conselho reforça sinal. Conselho contradiz, para. Legendário opera em rede confirmadora.', 'Sinal isolado é chute. Sinal em rede, confirmação.', '@gideao.sampaio'),
('12-02', 12, 2, 'neemias-barros', 'Neemias Barros', '71.612', 'Expulsei todos.', 'Neemias 13:28', 'Quem tu precisa remover do teu círculo — mesmo que seja custoso socialmente?', 'Neemias expulsou até genro do sumo sacerdote que tinha misturado com pagão. Custou caro — fez. Tu segura relações doentes por custo social. Sócio problemático, amigo tóxico, parente corrosivo. Distancia. Corte firme quando necessário. Legendário paga preço.', 'Relação doente acolhida corrói todo o círculo.', '@neemias.barros'),
('12-03', 12, 3, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Edificação do próximo.', 'Romanos 14:19', 'Teu próximo sai de teu convívio edificado — ou desgastado?', 'Paulo: busquem edificar. Pessoas depois de ti ficam melhores ou piores? Auto-avaliação honesta. Palavras tuas somam ou subtraem? Legendário edifica conscientemente. Cada conversa — alguém sai construído. Ou não sai.', 'Quem sai desgastado volta menos da próxima.', '@samuelqueiroga'),
('12-04', 12, 4, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Gemer.', 'Romanos 8:22', 'Quando tu ouviu a criação gemendo — e uniu tua voz?', 'Paulo: criação geme. Universo espera. Tu? Passa sem perceber. Junta voz. Ora pela terra. Pelos mortos. Pelos oprimidos. Pela igreja global. Intercessão ecológica e humanitária. Não é moda — é função sacerdotal.', 'Cristão só com oração privada é sacerdote manco.', '@benjamim.paiva'),
('12-05', 12, 5, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Anjo que fala comigo.', 'Zacarias 1:9', 'Tu tem vozes de Deus interpretadas — ou só ouve sem entender?', 'Anjo explicava a Zacarias. Tu ouve sem entender, não pede interpretação. Escreve, ora, consulta sábio. Revelação não interpretada é enigma sem proveito. Legendário persegue entendimento.', 'Revelação sem interpretação é sonho esquecido.', '@ezequielferraz'),
('12-06', 12, 6, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Serve.', 'João 13:14', 'Qual serviço sujo tu se recusa fazer pra parecer digno?', 'Jesus lavou pés. Servo de todos. Tu? Pede serviço sempre. Delega sujeira. Legendário serve coisa pequena. Quando ninguém vê. Carregar mala do amigo, limpar prato do vizinho, segurar porta, pagar conta. Serviço real é invisível.', 'Servo que aparece não é servo. É performer.', '@jonataspellegrino'),
('12-07', 12, 7, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Prevalecer contra.', 'Números 14:9', 'Qual gigante diante de ti tá fazendo tu achar que Deus é pequeno?', 'Caleb/Josué: os gigantes são nosso pão. Tu? Ao ver gigante, acha Deus pequeno. Inverte. Ao ver Deus, gigante vira pão. Orientação determina percepção. Olha primeiro pra Deus. Gigante encolhe.', 'Gigante grande é Deus esquecido.', '@caleb.montenegro'),
('12-08', 12, 8, 'josue-caetano', 'Josué Caetano', '71.204', 'A obra se acha.', 'Josué 22:4', 'Qual missão tu terminou e não parou pra descansar — vai sem pausa pra outra?', 'Rúben e Gade terminaram: agora descansem. Ordem. Tu termina e corre. Sem pausa. Burnout a caminho. Pausa é ordem. Legendário descansa após missão antes da próxima.', 'Não descansar após missão sabota a próxima.', '@josue.caetano'),
('12-09', 12, 9, 'davi-valverde', 'Davi Valverde', '71.337', 'Bondade.', 'Salmo 23:6', 'Tu confia que bondade te seguirá — ou age como se fosse sorte?', 'Davi: bondade e misericórdia me seguirão. Seguirão. Promessa. Tu age como se tudo fosse sorte. Se der certo, sorte. Se der errado, azar. Não. Bondade divina ativa. Reconhece. Atribui. Bondade ignorada cessa de ser percebida — mas não de acontecer.', 'Ignorar bondade divina fecha olhos pra onda de milagres diários.', '@davi.valverde'),
('12-10', 12, 10, 'elias-dovale', 'Elias do Vale', '71.418', 'Revestido de poder.', 'Lucas 24:49', 'Tu tá saindo revestido — ou desarmado na tua missão do dia?', 'Jesus: esperem o poder. Tu sai sem. Preciso de mais oração, jejum, revestimento. Missão sem poder é acidente. Revestido, transforma. Antes de sair, ora 5 minutos específicos de revestimento. Diferença é notável.', 'Saída sem revestimento é coragem sem arma.', '@elias.dovale'),
('12-11', 12, 11, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Tomou-os.', 'Juízes 8:16', 'Qual liderança tu precisa assumir firme — que tu tá delegando por medo de impopularidade?', 'Gideão castigou anciãos de Sucote. Impopular, necessário. Tu? Delega decisão dura por medo. Filho precisa correção firme — esposa faz. Equipe precisa demissão — alguém faz. Assuma. Legendário paga preço impopular.', 'Delegar impopularidade é fugir de responsabilidade.', '@gideao.sampaio'),
('12-12', 12, 12, 'neemias-barros', 'Neemias Barros', '71.612', 'Não deixei assim.', 'Neemias 13:25', 'Qual iniquidade tu tá olhando e passando — como se não fosse teu papel intervir?', 'Neemias repreendeu, xingou, até bateu. Drástico. Tu assiste abuso, injustiça e passa. ''Não é minha briga''. Às vezes é. Silêncio é cumplicidade. Legendário intervém quando deve.', 'Testemunha silenciosa vira ré espiritual.', '@neemias.barros'),
('12-13', 12, 13, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Fui testemunha.', '1 Samuel 12:5', 'Quem pode testemunhar da tua integridade — ou só tem quem viu tua imagem?', 'Samuel chamou testemunhas da sua integridade. Tu? Tem quem viu tua integridade de perto? Casamento íntimo, família extensa, equipe por anos. Sem testemunha, imagem é fachada. Desenvolve intimidade que sustente integridade pública.', 'Imagem sem testemunha íntima é casca.', '@samuelqueiroga'),
('12-14', 12, 14, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Assaz.', '2 Coríntios 12:9', 'Qual fraqueza tu esconde — que Deus quer usar como palco de graça?', 'Paulo: me glorio nas fraquezas. Tu esconde. Orgulho de imagem inteira. Mostra fraqueza — poder de Deus aparece. Testemunha de vício que saiu é mais poderoso que autobiografia de santo. Legendário mostra cicatriz pra pregar cura.', 'Esconder fraqueza é monopolizar glória.', '@benjamim.paiva'),
('12-15', 12, 15, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Aos mortos.', 'Ezequiel 37:9', 'Qual pessoa morta espiritualmente na tua vida tu ainda intercede — ou já desistiu?', 'Ezequiel profetizou aos mortos. Deus chama os mortos. Tu parou de orar por filho ateu, ex cética, amigo longe. ''Perda de tempo''. Errado. Continua. Deus trabalha em morto. Legendário intercede até o último suspiro.', 'Desistir de morto é descrer do Ressuscitador.', '@ezequielferraz');
INSERT INTO public.provocacoes (dia_ano, mes, dia, autor_slug, autor_dia, autor_numero, citacao, autor_citacao, pergunta, texto, aspas_autor, instagram) VALUES
('12-16', 12, 16, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Ao corpo se ajunta.', 'Romanos 12:5', 'Tu faz parte de corpo funcional — ou só atende culto?', 'Paulo: membros uns dos outros. Corpo. Tu atende evento mas não pertence. Não tá inserido. Não tem célula, não tem grupo, não tem função, não tem responsabilidade. Consumidor religioso. Legendário serve corpo específico.', 'Cristão desfiliado é órgão fora do corpo — morre.', '@jonataspellegrino'),
('12-17', 12, 17, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'Estabelecimento.', 'Provérbios 24:3', 'Qual sabedoria tá construindo tua casa — tua ou a do Senhor?', 'Salomão: sabedoria edifica casa. Qual sabedoria? Cultura, pai, coach secular, Deus? Muitas vezes misturado. Legendário audita fonte. Constrói com sabedoria divina primária. Outras, filtradas por ela.', 'Casa com sabedoria errada rui no terremoto.', '@caleb.montenegro'),
('12-18', 12, 18, 'josue-caetano', 'Josué Caetano', '71.204', 'Esta terra.', 'Deuteronômio 4:22', 'Qual terra tu não entrará — mas tua equipe entrará?', 'Moisés morreu antes de Canaã. Josué entrou. Tu prepara pra outro colher. Mentoria, ensino, obra de longa duração. Aceita não ver colheita. Plantou. Outro colhe. Legendário semeia sem reclamar.', 'Quem só planta pra colher pessoalmente morre amargo.', '@josue.caetano'),
('12-19', 12, 19, 'davi-valverde', 'Davi Valverde', '71.337', 'De Samuel até aqui.', '1 Crônicas 17:1', 'Que lista de ''Deus guiou assim'' tu pode fazer dos últimos anos?', 'Davi contemplou como Deus guiara. Faz lista. 5, 10, 20 anos. O que Deus guiou, conduziu, fez? Lista concreta. Memória detalhada alimenta fé. Legendário recita intervenções. Pessoalmente e em voz alta.', 'Recitar a ação de Deus é ato de fé ativa.', '@davi.valverde'),
('12-20', 12, 20, 'elias-dovale', 'Elias do Vale', '71.418', 'Diante de Eliseu.', '2 Reis 2:14', 'Depois que saiu mentor — tu tá usando o manto que ele te deixou?', 'Eliseu continuou com manto. Separou rio. Tu? Teve mentor, ele se foi. Fazendo o que ele ensinou? Ou abandonou. Herança espiritual exige continuação. Usa. Dobra. Multiplica.', 'Manto guardado no armário é insulto ao mentor.', '@elias.dovale'),
('12-21', 12, 21, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Não tinha mais medo.', 'Juízes 8:10', 'Em que tu hoje já não tem medo — que 5 anos atrás era impossível?', 'Gideão cresceu em coragem. Tu também. Lembra. Pedir dízimo, falar em público, confrontar pai, largar vício. Áreas onde medo já desapareceu. Pra que Deus te mostra? Pra crer que no atual também vai passar. Legendário comemora medos vencidos.', 'Medos vencidos são testemunho do próximo conquistado.', '@gideao.sampaio'),
('12-22', 12, 22, 'neemias-barros', 'Neemias Barros', '71.612', 'Me lembre deste.', 'Neemias 13:31', 'Qual serviço invisível tu pede pra Deus lembrar — sem precisar humano reconhecer?', 'Neemias: me lembra deste serviço. Tu? Quer reconhecimento humano. Faz pra ser visto. Legendário serve pra Deus lembrar. Anonimato santo. Ele recompensa. Humano esquece.', 'Reconhecimento humano é salário pago. Divino, herança.', '@neemias.barros'),
('12-23', 12, 23, 'samuel-queiroga', 'Samuel Queiroga', '70.089', 'Onde estás?', 'Gênesis 3:9', 'Quando Deus pergunta onde tu tá — tu responde ou se esconde?', 'Deus a Adão: onde estás? Adão se escondeu. Tu também. Evita oração quando tá no errado. Deus vai perguntar. Responde. Confessa localização. Esconde? Piora. Legendário responde.', 'Esconder-se de Deus adia, não resolve.', '@samuelqueiroga'),
('12-24', 12, 24, 'benjamim-paiva', 'Benjamim Paiva', '72.183', 'Ao teu Deus.', 'Oséias 12:6', 'Tu volta pra Deus todo dia — ou só no domingo?', 'Oséias: volte ao teu Deus. Volta diária. Tu volta semanal. Volta diária gera intimidade cumulativa. Volta semanal é ritual. Matinal regular, tarde pontual, noturno rápido — ou só um momento focado. Ritmo firme.', 'Volta diária é intimidade. Volta semanal é religião.', '@benjamim.paiva'),
('12-25', 12, 25, 'ezequiel-ferraz', 'Ezequiel Ferraz', '71.749', 'Dia do Senhor.', 'Ezequiel 30:3', 'Tua vida tá fazendo sentido pra dia do julgamento — ou tu prefere não pensar nele?', 'Ezequiel falava do Dia. Julgamento. Tu evita pensar. Mas vai vir. Tua vida hoje resistirá? Obras, motivos, palavras. Pensar na morte não é mórbido — é sabedoria. Muda prioridade. Legendário vive com olho no Dia.', 'Esquecer o Dia é viver como louco.', '@ezequielferraz'),
('12-26', 12, 26, 'jonatas-pellegrino', 'Jônatas Pellegrino', '71.866', 'Até o fim.', 'João 13:1', 'Quem tu tem amado ''até o fim'' — mesmo quando foi rejeitado?', 'Jesus amou até o fim — mesmo traição. Tu ama até ser conveniente. Ofendeu, cortou. Traiu, banco. Amor até o fim é sobrenatural. Impossível humano. Possível em Cristo. Quem na tua vida precisa desse amor radical? Começa.', 'Amor interrompido pela ofensa não era amor cristão.', '@jonataspellegrino'),
('12-27', 12, 27, 'caleb-montenegro', 'Caleb Montenegro', '71.100', 'E o Senhor me guardou.', 'Josué 14:10', 'Em qual momento Deus te guardou — que tu ainda não soube agradecer publicamente?', 'Caleb disse: Deus me guardou 45 anos. Tu? Tem décadas de guarda divina. Nunca contou. Nunca agradeceu pública. Lembra um episódio específico. Conta. Hoje, pra alguém. Testemunho de guarda ativa fé coletiva.', 'Guarda silenciada perde efeito multiplicador.', '@caleb.montenegro'),
('12-28', 12, 28, 'josue-caetano', 'Josué Caetano', '71.204', 'Provou o Senhor.', 'Deuteronômio 8:2', 'Qual fase da tua vida foi prova — que tu confundiu com castigo?', 'Deserto foi prova. Pra conhecer o que havia dentro. Tu passou prova e achou castigo. Amargou em vez de aprender. Fases difíceis: lição ou castigo. Investiga. Prova tira ouro do minério. Castigo é reação moralmente desobediente. Distingue.', 'Confundir prova com castigo amargura o que deveria enriquecer.', '@josue.caetano'),
('12-29', 12, 29, 'davi-valverde', 'Davi Valverde', '71.337', 'Na minha velhice.', 'Salmo 71:9', 'Tu tá preparando legado de fé — ou teu idoso será amargurado?', 'Davi orou: não me rejeites na velhice. Velhice amarga ou doce. Depende do jovem que tu é hoje. Fé cultivada por décadas gera velhice luminosa. Alma superficial gera amargor. Decide hoje — semeia pra colher velhice com sabedoria.', 'Jovem sem fundação é velho amargo garantido.', '@davi.valverde'),
('12-30', 12, 30, 'elias-dovale', 'Elias do Vale', '71.418', 'Coisa grande.', '1 Reis 19:5', 'Qual ''coisa grande'' Deus tá pedindo — que tu tá minimizando?', 'Anjo a Elias: coisa grande antes de ti. Tu minimiza chamado. ''Coisinha, hobby''. Deus rotulou grande. Aceita. Legendário reconhece chamado grande e assume gravidade.', 'Minimizar chamado é despeitar quem chamou.', '@elias.dovale'),
('12-31', 12, 31, 'gideao-sampaio', 'Gideão Sampaio', '71.525', 'Paz.', 'Juízes 6:24', 'No fim de ano — tu tem paz real, ou só tá exausto?', 'Gideão construiu altar: Senhor é paz. Fim de ano tu avalia. Paz real vem de caminhar com Deus — não de listas cumpridas. Tu tem paz? Sem, avalia: o que desalinhou? Uma coisa específica pra reconstruir em janeiro. Ano novo de altar de paz.', 'Paz real é termômetro do caminho. Sem, desviou.', '@gideao.sampaio');
