--
-- Bug V2.3 corrigido:
--   51 linhas do CSV tinham formato antigo (10 cols em vez de 12).
--   csv.DictReader lia elas deslocadas: autor_dia caía em autor_slug.
--   Resultado: INSERT com 'Caleb Montenegro' no campo autor_slug →
--   FK violation contra autores(slug='caleb-montenegro').
--
-- Fix: Python script detectou + reconstruiu as 51 linhas usando map
-- nome→(slug, numero). Agora CSV tem 366 linhas todas com slug válido.
--
-- Como rodar:
--   1. Cmd+A dentro do editor SQL (selecionar o que tiver lá)
--   2. Delete
--   3. Cola este arquivo inteiro
--   4. Clica Run (NÃO selecionar texto com mouse antes)
-- =====================================================================

BEGIN;

-- ============ DROP existente ============
DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
DROP FUNCTION IF EXISTS public.handle_new_user() CASCADE;
DROP TABLE IF EXISTS public.ranking_cache CASCADE;
DROP TABLE IF EXISTS public.whatsapp_logs CASCADE;
DROP TABLE IF EXISTS public.user_events CASCADE;
DROP TABLE IF EXISTS public.user_actions CASCADE;
DROP TABLE IF EXISTS public.user_unlocks CASCADE;
DROP TABLE IF EXISTS public.user_reads CASCADE;
DROP TABLE IF EXISTS public.provocacoes CASCADE;
DROP TABLE IF EXISTS public.users CASCADE;
DROP TABLE IF EXISTS public.autores CASCADE;
DROP FUNCTION IF EXISTS update_updated_at_column() CASCADE;

-- ============ SCHEMA ============
-- =============================================================
-- LEGENDIARIO — Schema Supabase
-- Rodar no SQL Editor do Supabase (projeto novo)
-- =============================================================

-- Autores do conteúdo (10 personas Legendiárias com número de registro)
CREATE TABLE IF NOT EXISTS public.autores (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  slug TEXT UNIQUE NOT NULL,               -- caleb-montenegro
  nome TEXT NOT NULL,                      -- Caleb Montenegro
  numero_registro TEXT UNIQUE NOT NULL,    -- formato XX.XXX (ex: 71.100)
  instagram TEXT,                          -- @caleb.montenegro
  arquetipo TEXT,                          -- Veterano, Líder, Profeta...
  cor_hex TEXT,                            -- #FF4D14 — cor de identidade visual
  bio_curta TEXT,                          -- 1-2 frases
  persona TEXT,                            -- descrição de voz/tom
  ativo BOOLEAN DEFAULT true,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);
CREATE INDEX idx_autores_slug ON public.autores(slug);
CREATE INDEX idx_autores_numero ON public.autores(numero_registro);

-- Usuários do app (espelha auth.users com dados extras)
CREATE TABLE IF NOT EXISTS public.users (
  id UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  email TEXT UNIQUE NOT NULL,
  nome TEXT,
  telefone TEXT,                           -- E.164: +5511999999999
  whatsapp_enabled BOOLEAN DEFAULT true,
  whatsapp_hour INT DEFAULT 7,             -- Hora local de envio (0-23)
  profissao TEXT,                          -- médico, nutricionista, etc.
  estado TEXT,                             -- UF: SP, RJ, MG...
  cidade TEXT,
  genero TEXT,
  data_nascimento DATE,
  subscription_start DATE,                 -- Quando iniciou os 365 dias
  hotmart_id TEXT,                         -- ID da transação Hotmart
  hotmart_plan TEXT,                       -- anual | vitalicio
  perfil_completo BOOLEAN DEFAULT false,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Conteúdo: 365 provocações
-- Referencia autor pelo slug (FK) — dados do autor ficam normalizados em autores
CREATE TABLE IF NOT EXISTS public.provocacoes (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  dia_ano TEXT UNIQUE NOT NULL,            -- formato MM-DD (ex: "01-15")
  mes INT NOT NULL,                        -- 1-12
  dia INT NOT NULL,                        -- 1-31
  autor_slug TEXT REFERENCES public.autores(slug) ON DELETE SET NULL,
  autor_dia TEXT NOT NULL,                 -- denormalizado: nome do autor (perf)
  autor_numero TEXT,                       -- denormalizado: numero_registro (perf)
  citacao TEXT,                            -- trecho bíblico
  autor_citacao TEXT,                      -- referência bíblica (ex: "Josué 14:12")
  pergunta TEXT NOT NULL,                  -- pergunta provocadora
  texto TEXT NOT NULL,                     -- conteúdo principal
  aspas_autor TEXT,                        -- citação final do autor fictício
  instagram TEXT,                          -- @ do autor (denormalizado)
  updated_at TIMESTAMPTZ DEFAULT now()
);
CREATE INDEX idx_provocacoes_mes_dia ON public.provocacoes(mes, dia);
CREATE INDEX idx_provocacoes_autor ON public.provocacoes(autor_slug);

-- Leituras do usuário (quais dias ele leu)
CREATE TABLE IF NOT EXISTS public.user_reads (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  day_id TEXT NOT NULL,                    -- formato MM-DD
  read_at TIMESTAMPTZ DEFAULT now(),
  UNIQUE(user_id, day_id)
);
CREATE INDEX idx_user_reads_user ON public.user_reads(user_id);

-- Desbloqueios com crédito (dias perdidos recuperados)
CREATE TABLE IF NOT EXISTS public.user_unlocks (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  day_id TEXT NOT NULL,
  unlocked_at TIMESTAMPTZ DEFAULT now(),
  UNIQUE(user_id, day_id)
);

-- Ações/compromissos do usuário
CREATE TABLE IF NOT EXISTS public.user_actions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  day_id TEXT NOT NULL,
  title TEXT NOT NULL,
  descricao TEXT,
  status TEXT DEFAULT 'pending',           -- pending | done
  reminder_date DATE,                       -- lembrete opcional
  created_at TIMESTAMPTZ DEFAULT now(),
  completed_at TIMESTAMPTZ
);
CREATE INDEX idx_user_actions_user ON public.user_actions(user_id);

-- Eventos (tracking completo do usuário)
CREATE TABLE IF NOT EXISTS public.user_events (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID REFERENCES public.users(id) ON DELETE CASCADE,
  type TEXT NOT NULL,                      -- login, read, share, unlock, action_done, ...
  data_json JSONB,
  created_at TIMESTAMPTZ DEFAULT now()
);
CREATE INDEX idx_user_events_user_type ON public.user_events(user_id, type);
CREATE INDEX idx_user_events_created ON public.user_events(created_at);

-- Logs WhatsApp (enviados, erros)
CREATE TABLE IF NOT EXISTS public.whatsapp_logs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID REFERENCES public.users(id) ON DELETE SET NULL,
  telefone TEXT,
  template TEXT,
  status TEXT,                             -- sent | delivered | read | failed
  error_code TEXT,
  error_message TEXT,
  meta_message_id TEXT,
  payload_json JSONB,
  created_at TIMESTAMPTZ DEFAULT now()
);
CREATE INDEX idx_whatsapp_user ON public.whatsapp_logs(user_id);

-- Ranking cache (recalculado periodicamente)
CREATE TABLE IF NOT EXISTS public.ranking_cache (
  user_id UUID PRIMARY KEY REFERENCES public.users(id) ON DELETE CASCADE,
  posicao_global INT,
  total_global INT,
  percentil NUMERIC,
  streak INT,
  reads_total INT,
  shares INT,
  actions_done INT,
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Trigger: auto-update updated_at em users
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
   NEW.updated_at = now();
   RETURN NEW;
END;
$$ language 'plpgsql';

CREATE TRIGGER update_users_updated_at BEFORE UPDATE ON public.users
   FOR EACH ROW EXECUTE PROCEDURE update_updated_at_column();

CREATE TRIGGER update_autores_updated_at BEFORE UPDATE ON public.autores
   FOR EACH ROW EXECUTE PROCEDURE update_updated_at_column();


-- ============ RLS ============
-- =============================================================
-- LEGENDIARIO — Row Level Security (RLS)
-- Aplicar DEPOIS de 01_schema.sql
-- =============================================================

-- ============ CONTEÚDO PÚBLICO ============
-- Provocações: leitura livre pra qualquer user autenticado ou anônimo
ALTER TABLE public.provocacoes ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Provocacoes públicas (leitura)" ON public.provocacoes
  FOR SELECT USING (true);

-- Autores: leitura livre (necessário pro app exibir bio/cor/instagram)
ALTER TABLE public.autores ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Autores públicos (leitura)" ON public.autores
  FOR SELECT USING (true);

-- Ranking: leitura pública
ALTER TABLE public.ranking_cache ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Ranking leitura pública" ON public.ranking_cache
  FOR SELECT USING (true);

-- ============ USERS ============
ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;

-- SELECT: user vê só o próprio
CREATE POLICY "Users leem próprio perfil" ON public.users
  FOR SELECT USING (auth.uid() = id);

-- INSERT: user pode criar o próprio registro (ao confirmar magic link)
CREATE POLICY "Users inserem próprio perfil" ON public.users
  FOR INSERT WITH CHECK (auth.uid() = id);

-- UPDATE: user atualiza só o próprio
CREATE POLICY "Users atualizam próprio perfil" ON public.users
  FOR UPDATE USING (auth.uid() = id) WITH CHECK (auth.uid() = id);

-- ============ USER READS ============
ALTER TABLE public.user_reads ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Reads SELECT próprio" ON public.user_reads
  FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Reads INSERT próprio" ON public.user_reads
  FOR INSERT WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Reads DELETE próprio" ON public.user_reads
  FOR DELETE USING (auth.uid() = user_id);

-- ============ USER UNLOCKS ============
ALTER TABLE public.user_unlocks ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Unlocks SELECT próprio" ON public.user_unlocks
  FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Unlocks INSERT próprio" ON public.user_unlocks
  FOR INSERT WITH CHECK (auth.uid() = user_id);

-- ============ USER ACTIONS ============
ALTER TABLE public.user_actions ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Actions SELECT próprio" ON public.user_actions
  FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Actions INSERT próprio" ON public.user_actions
  FOR INSERT WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Actions UPDATE próprio" ON public.user_actions
  FOR UPDATE USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Actions DELETE próprio" ON public.user_actions
  FOR DELETE USING (auth.uid() = user_id);

-- ============ USER EVENTS (tracking) ============
ALTER TABLE public.user_events ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Events SELECT próprio" ON public.user_events
  FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Events INSERT próprio" ON public.user_events
  FOR INSERT WITH CHECK (auth.uid() = user_id);

-- ============ WHATSAPP LOGS ============
-- Sem policy pública — acesso só via SERVICE_ROLE_KEY no backend
ALTER TABLE public.whatsapp_logs ENABLE ROW LEVEL SECURITY;

-- ============ TRIGGER: auto-criar row em public.users quando Auth cria usuário ============
-- Isso dispara ao Brunno clicar no magic link e confirmar email
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER AS $$
BEGIN
  VALUES (NEW.id, NEW.email, NEW.created_at)
  ON CONFLICT (id) DO NOTHING;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE PROCEDURE public.handle_new_user();


