-- ============ VALIDAÇÃO FINAL ============
DO $$
DECLARE n_autores INT; n_provs INT;
BEGIN
  SELECT COUNT(*) INTO n_autores FROM public.autores;
  SELECT COUNT(*) INTO n_provs FROM public.provocacoes;
  IF n_autores <> 10 THEN
    RAISE EXCEPTION 'ERRO: autores tem %, esperado 10', n_autores;
  END IF;
  IF n_provs <> 366 THEN
    RAISE EXCEPTION 'ERRO: provocacoes tem %, esperado 366', n_provs;
  END IF;
  RAISE NOTICE 'SUCESSO: % autores, % provocacoes', n_autores, n_provs;
END $$;

